const PLOT_OWNER_FIXED_PRICE = 299; // kept for price-display references elsewhere

/**
 * showBookingPage — populates booking summary UI and wires the Pay button.
 * Payment is initiated by paymentService.js startPayment() — no redirect.
 */
function showBookingPage(bookingDetails) {
    const safe = (id, val) => { const el = document.getElementById(id); if (el) el.textContent = val ?? ''; };

    const amount      = Number(bookingDetails.amount) || 0;
    const platformFee = amount * 0.10;

    safe('booking-ground-name', bookingDetails.groundName || 'Unknown Ground');
    safe('booking-date',        bookingDetails.date);
    safe('booking-time',        bookingDetails.slotTime);
    safe('booking-amount',      formatCurrency(amount));
    safe('payment-amount',      formatCurrency(amount));
    safe('platform-fee',        formatCurrency(platformFee));
    safe('final-amount',        formatCurrency(amount));

    // Wire pay button — setupPayButton is defined in paymentService.js
    if (typeof setupPayButton === 'function') {
        setupPayButton(bookingDetails);
    }

    showPage('booking-page');
}

async function debugOwnerType(groundId) {
    const groundDoc = await db.collection(COLLECTIONS.GROUNDS).doc(groundId).get();
    if (!groundDoc.exists) {
        console.log('Ground not found');
        return;
    }
    
    const ground = groundDoc.data();
    console.log('Ground:', ground.groundName);
    console.log('Ground price:', ground.pricePerHour);
    console.log('Owner ID:', ground.ownerId);
    
    const ownerDoc = await db.collection(COLLECTIONS.OWNERS).doc(ground.ownerId).get();
    if (ownerDoc.exists) {
        const owner = ownerDoc.data();
        console.log('Owner type:', owner.ownerType);
        console.log('Is Plot Owner:', owner.ownerType === 'plot_owner');
    } else {
        console.log('Owner not found');
    }
}

