/**
 * Update the selectSlot function to use the new booking page
 */
async function selectSlot(slot) {
    console.log('=== selectSlot called ===');
    console.log('Selected slot:', slot);
    console.log('Current user:', currentUser);
    console.log('Current ground:', currentGround);
    console.log('Selected date:', selectedDate);
    
    // ==================== VALIDATION CHECKS ====================
    
    // Check if user is logged in
    if (!currentUser) {
        showToast('Please login to book a ground', 'warning');
        showPage('login-page');
        return;
    }
    
    // Check if ground information exists
    if (!currentGround) {
        console.error('Current ground is null, trying to recover from session');
        
        const savedGround = sessionStorage.getItem('currentGround');
        if (savedGround) {
            try {
                currentGround = JSON.parse(savedGround);
                console.log('Recovered ground from session:', currentGround);
            } catch(e) {
                console.error('Failed to parse saved ground:', e);
            }
        }
        
        const groundId = sessionStorage.getItem('currentGroundId');
        if (groundId && !currentGround) {
            try {
                const groundDoc = await db.collection(COLLECTIONS.GROUNDS).doc(groundId).get();
                if (groundDoc.exists) {
                    currentGround = { id: groundDoc.id, ...groundDoc.data() };
                    sessionStorage.setItem('currentGround', JSON.stringify(currentGround));
                    console.log('Fetched ground from Firestore:', currentGround);
                }
            } catch(e) {
                console.error('Failed to fetch ground:', e);
            }
        }
        
        if (!currentGround) {
            showToast('Ground information not found. Please select a ground again.', 'error');
            goHome();
            return;
        }
    }
    
    // Check if date is selected
    if (!selectedDate) {
        console.error('Selected date is null, trying to recover from session');
        const savedDate = sessionStorage.getItem('selectedDate');
        if (savedDate) {
            selectedDate = savedDate;
            console.log('Recovered date from session:', selectedDate);
        } else {
            showToast('Please select a date first', 'warning');
            return;
        }
    }
    
    // ==================== TIME VALIDATION ====================
    
    const today = new Date().toISOString().split('T')[0];
    if (selectedDate === today) {
        const now = new Date();
        const currentTime = now.getHours() * 60 + now.getMinutes();
        const [startHour, startMinute] = slot.split('-')[0].split(':').map(Number);
        const slotStartTime = startHour * 60 + (startMinute || 0);
        
        if (slotStartTime <= currentTime) {
            showToast('This time slot has already passed. Please select a future slot.', 'error');
            if (currentGround && currentGround.id) {
                await loadSlots(currentGround.id, selectedDate);
            }
            return;
        }
    }
    
    // ==================== CHECK SLOT AVAILABILITY ====================
    
    const [startTime, endTime] = slot.split('-');
    const isAvailable = await checkSlotAvailability(
        currentGround.id,
        selectedDate,
        startTime,
        endTime
    );
    
    if (!isAvailable) {
        showToast('This time slot is no longer available. Please select another slot.', 'error');
        if (currentGround && currentGround.id) {
            await loadSlots(currentGround.id, selectedDate);
        }
        return;
    }
    
    // ==================== STORE SELECTED SLOT ====================
    
    selectedSlot = slot;
    
    sessionStorage.setItem('selectedSlot', selectedSlot);
    sessionStorage.setItem('selectedDate', selectedDate);
    sessionStorage.setItem('currentGround', JSON.stringify(currentGround));
    sessionStorage.setItem('currentGroundId', currentGround.id);
    
    console.log('✅ Slot stored in session:', selectedSlot);
    console.log('✅ Date stored in session:', selectedDate);
    console.log('✅ Ground stored in session:', currentGround.groundName);
    
    // ==================== GET VENUE INFORMATION ====================
    
    let venueName = '';
    let venueAddress = '';
    let groundAddress = currentGround.groundAddress || '';
    
    if (currentVenue) {
        venueName = currentVenue.venueName || '';
        venueAddress = currentVenue.address || '';
    } else {
        try {
            const venueSnapshot = await db.collection(COLLECTIONS.VENUES)
                .where('ownerId', '==', currentGround.ownerId)
                .limit(1)
                .get();
            
            if (!venueSnapshot.empty) {
                const venue = venueSnapshot.docs[0].data();
                currentVenue = { id: venueSnapshot.docs[0].id, ...venue };
                venueName = currentVenue.venueName || '';
                venueAddress = currentVenue.address || '';
                sessionStorage.setItem('currentVenue', JSON.stringify(currentVenue));
                console.log('Found venue:', venueName);
            }
        } catch(e) {
            console.error('Error fetching venue:', e);
        }
    }
    
    // ==================== CHECK OWNER TYPE (CRITICAL FIX) ====================
    
    let isPlotOwner = false;
    let ownerType = 'venue_owner';
    let actualPrice = currentGround.pricePerHour || 0;
    
    try {
        const ownerDoc = await db.collection(COLLECTIONS.OWNERS).doc(currentGround.ownerId).get();
        if (ownerDoc.exists) {
            ownerType = ownerDoc.data().ownerType || 'venue_owner';
            isPlotOwner = ownerType === 'plot_owner';
            console.log('Owner type:', ownerType, 'Is plot owner:', isPlotOwner);
            console.log('Ground price from database:', actualPrice);
        }
    } catch(e) {
        console.error('Error fetching owner type:', e);
    }
    
    // Store plot owner status
    sessionStorage.setItem('isPlotOwnerGround', isPlotOwner ? 'true' : 'false');
    
    // ==================== GET USER MOBILE NUMBER ====================
    
    let userMobile = currentUser.phone || currentUser.userPhone || '';
    
    if (!userMobile || userMobile.length !== 10) {
        userMobile = await promptForMobileNumber();
        if (!userMobile) {
            showToast('Mobile number is required for booking verification', 'error');
            return;
        }
    }
    
    // ==================== CALCULATE AMOUNT BASED ON OWNER TYPE ====================
    
    let amount;
    let originalAmount;
    
    // CRITICAL FIX: Check owner type to determine pricing
    if (isPlotOwner) {
        // PLOT OWNER: Fixed price of ₹299
        amount = PLOT_OWNER_FIXED_PRICE;
        originalAmount = PLOT_OWNER_FIXED_PRICE;
        console.log('✅ PLOT OWNER GROUND - Fixed price: ₹', amount);
    } else {
        // VENUE/TURF OWNER: Use actual ground price
        amount = currentGround.pricePerHour;
        originalAmount = currentGround.pricePerHour;
        console.log('✅ VENUE/TURF OWNER GROUND - Regular price: ₹', amount);
    }
    
    // Validate amount
    if (amount <= 0 || isNaN(amount)) {
        showToast('Invalid price. Please contact the owner.', 'error');
        return;
    }
    
    // ==================== APPLY FIRST BOOKING OFFER (20% OFF) ====================
    
    const hasFirstBookingOffer = !localStorage.getItem('firstBookingOffer_' + currentUser.uid);
    let finalAmount = amount;
    let appliedOffer = null;
    
    // Apply discount for first-time users (for all owner types)
    if (hasFirstBookingOffer) {
        finalAmount = amount * 0.8; // 20% off
        appliedOffer = 'FIRST20';
        console.log('First booking offer applied! Original: ₹', amount, 'Discounted: ₹', finalAmount);
    }
    
    // Round to nearest integer
    finalAmount = Math.round(finalAmount);
    
    console.log('=== FINAL PRICE CALCULATION ===');
    console.log('Owner type:', isPlotOwner ? 'Plot Owner' : 'Venue/Turf Owner');
    console.log('Base price:', amount);
    console.log('After discount:', finalAmount);
    console.log('Discount applied:', appliedOffer || 'No discount');
    
    // ==================== CREATE BOOKING DETAILS OBJECT ====================
    
    const bookingId = generateId('BKG');
    const orderId = bookingId;
    
    const bookingDetails = {
        bookingId: bookingId,
        orderId: orderId,
        type: 'booking',
        
        userId: currentUser.uid,
        userName: currentUser.name || currentUser.ownerName || currentUser.displayName || 'User',
        userEmail: currentUser.email || '',
        userPhone: userMobile,
        
        ownerId: currentGround.ownerId,
        ownerType: ownerType,
        
        groundId: currentGround.id,
        groundName: currentGround.groundName || 'Unknown Ground',
        groundAddress: groundAddress,
        
        venueName: venueName || (isPlotOwner ? 'Open Ground' : 'Sports Facility'),
        venueAddress: venueAddress,
        
        slotTime: selectedSlot,
        date: selectedDate,
        
        // PRICING - This is what will be sent to Cashfree
        amount: finalAmount,
        originalAmount: originalAmount,
        discountAmount: originalAmount - finalAmount,
        ownerAmount: finalAmount * 0.9,
        platformAmount: finalAmount * 0.1,
        commission: finalAmount * 0.1,
        
        sportType: currentGround.sportType || 'Multi-sport',
        
        appliedOffer: appliedOffer,
        
        isPlotOwner: isPlotOwner,
        
        paymentStatus: 'pending',
        bookingStatus: 'pending_payment',
        
        initiatedAt: new Date().toISOString(),
        createdAt: new Date().toISOString()
    };
    
    console.log('=== FINAL BOOKING DETAILS ===');
    console.log('Amount to charge customer: ₹', bookingDetails.amount);
    console.log('Owner type in booking:', bookingDetails.isPlotOwner ? 'Plot Owner' : 'Venue Owner');

    // FIX: Sanitise bookingDetails with a JSON round-trip before storing or
    // passing downstream. This strips any accidental Timestamp objects,
    // FieldValue instances, class instances or functions that would cause
    // "FirebaseError: Expected type 'Vd', but it was: a custom Pd object"
    // when the data eventually reaches a Firestore write inside startPayment().
    // NOTE: initiatedAt / createdAt are already ISO strings here, so they
    // survive JSON serialisation correctly.
    const safeBookingDetails = JSON.parse(JSON.stringify(bookingDetails));
    console.log('FINAL PAYMENT DATA:', safeBookingDetails); // debug log

    // Store pending booking
    sessionStorage.setItem('pendingBooking', JSON.stringify(safeBookingDetails));
    sessionStorage.setItem('pendingCashfreeBooking', JSON.stringify(safeBookingDetails));

    // Create pending booking record in Firestore.
    // Timestamps and FieldValues are kept here because this is a direct
    // Firestore write — they are NOT passed to startPayment().
    try {
        const lockExpiresAtMs = Date.now() + 30 * 60 * 1000; // store as plain ms number

        const pendingBookingData = {
    orderId: orderId,
    userId: String(safeBookingDetails.userId),
    groundId: String(safeBookingDetails.groundId),
    groundName: String(safeBookingDetails.groundName || ""),
    venueName: String(safeBookingDetails.venueName || ""),
    venueAddress: String(safeBookingDetails.venueAddress || ""),
    groundAddress: String(safeBookingDetails.groundAddress || ""),
    date: String(safeBookingDetails.date),
    slotTime: String(safeBookingDetails.slotTime),
    amount: Number(safeBookingDetails.amount),

    status: "pending_payment",
    paymentStatus: "pending",

    lockExpiresAtMs: lockExpiresAtMs,
    createdAt: firebase.firestore.FieldValue.serverTimestamp()
};

        await db.collection('pending_bookings').doc(bookingId).set(pendingBookingData);
        console.log('✅ Pending booking saved to Firestore');
    } catch (error) {
        console.error('Error saving pending booking:', error);
    }

    // Create slot lock.
    // Same rule: Timestamps only appear at top-level of direct Firestore writes.
    try {
        const lockExpiresAtMs = Date.now() + 30 * 60 * 1000; // plain number

        const slotQuery = await db.collection(COLLECTIONS.SLOTS)
            .where('groundId', '==', currentGround.id)
            .where('date', '==', selectedDate)
            .where('startTime', '==', startTime)
            .where('endTime', '==', endTime)
            .get();

        if (!slotQuery.empty) {
            await slotQuery.docs[0].ref.update({
                status          : 'locked',
                lockExpiresAtMs,                                             // plain number — safe
                lockBookingId   : bookingId,
                lockUserPhone   : userMobile,
                updatedAt       : firebase.firestore.FieldValue.serverTimestamp(), // top-level only
            });
        } else {
            await db.collection(COLLECTIONS.SLOTS).add({
                groundId        : currentGround.id,
                date            : selectedDate,
                startTime       : startTime,
                endTime         : endTime,
                status          : 'locked',
                lockExpiresAtMs,                                             // plain number — safe
                lockBookingId   : bookingId,
                lockUserPhone   : userMobile,
                createdAt       : firebase.firestore.FieldValue.serverTimestamp(), // top-level only
                updatedAt       : firebase.firestore.FieldValue.serverTimestamp(), // top-level only
            });
        }

        sessionStorage.setItem('slotLock', JSON.stringify({
            bookingId,
            groundId  : currentGround.id,
            date      : selectedDate,
            slotTime  : selectedSlot,
            userPhone : userMobile,
            expiresAt : new Date(lockExpiresAtMs).toISOString(), // ISO string — safe
        }));

    } catch (error) {
        console.error('Error creating slot lock:', error);
    }

    // Navigate to booking page — pass the sanitised plain-JS object
    showBookingPage(safeBookingDetails);
}

