// ==================== SAFE DOM ELEMENT ACCESS ====================

function safeGetElement(id) {
    const element = document.getElementById(id);
    if (!element) {
        console.warn(`Element with id "${id}" not found in DOM`);
    }
    return element;
}

function safeSetValue(id, value) {
    const element = safeGetElement(id);
    if (element) {
        element.value = value;
        return true;
    }
    return false;
}

function safeGetValue(id) {
    const element = safeGetElement(id);
    return element ? element.value : '';
}

// ==================== OPTIMIZED AUTH STATE CHANGE HANDLER ====================

let authStateProcessed = false;
let splashTimeout = null;

// Set a maximum time for splash screen (1.5 seconds)
splashTimeout = setTimeout(() => {
    const splash = document.getElementById('splash-screen');
    if (splash && !splash.classList.contains('hide')) {
        splash.classList.add('hide');
        console.log('Splash screen hidden by timeout');
    }
}, 1500);

auth.onAuthStateChanged(async (user) => {
    // Clear the timeout since auth state changed
    if (splashTimeout) {
        clearTimeout(splashTimeout);
    }
    
    // Prevent multiple executions
    if (authStateProcessed && user) return;
    
    if (user) {
        try {
            console.log('User logged in:', user.email);
            authStateProcessed = true;
            
            // Show loading but hide splash screen immediately
            showLoading('Loading your profile...');
            
            // Hide splash screen quickly with animation
            const splashScreen = document.getElementById('splash-screen');
            if (splashScreen) {
                splashScreen.classList.add('hide');
            }
            
            // Check if user is CEO
            if (user.email === CEO_EMAIL) {
                console.log('CEO user detected:', user.email);
                
                const ceoRef = db.collection(COLLECTIONS.ADMINS).doc(user.uid);
                const ceoDoc = await ceoRef.get();
                
                if (!ceoDoc.exists) {
                    const ceoData = {
                        uid: user.uid,
                        email: user.email,
                        name: 'CEO',
                        profileImage: user.photoURL || 'https://via.placeholder.com/150',
                        phone: user.phoneNumber || '',
                        adminId: generateId('ADM'),
                        adminRole: ADMIN_ROLES.SUPER_ADMIN,
                        isCEO: true,
                        permissions: {
                            manageOwners: true,
                            manageVenues: true,
                            manageBookings: true,
                            manageTournaments: true,
                            viewPayouts: true,
                            manageSlots: true,
                            manageAdmins: true
                        },
                        status: ADMIN_STATUS.ACTIVE,
                        role: 'ceo',
                        createdAt: firebase.firestore.FieldValue.serverTimestamp(),
                        updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
                        lastLogin: firebase.firestore.FieldValue.serverTimestamp(),
                        totalLogins: 1
                    };
                    await ceoRef.set(ceoData);
                    currentUser = {
                        uid: user.uid,
                        ...ceoData,
                        role: 'ceo'
                    };
                } else {
                    await ceoRef.update({
                        lastLogin: firebase.firestore.FieldValue.serverTimestamp(),
                        totalLogins: firebase.firestore.FieldValue.increment(1)
                    });
                    
                    currentUser = {
                        uid: user.uid,
                        ...ceoDoc.data(),
                        role: 'ceo'
                    };
                }
            }
            // Check if user exists in admins collection
            else {
                // Try to get from local storage first for faster loading
                const cachedUser = localStorage.getItem(`user_${user.uid}`);
                if (cachedUser && !currentUser) {
                    try {
                        const parsedUser = JSON.parse(cachedUser);
                        // Check if cache is not older than 5 minutes
                        if (parsedUser.cachedAt && Date.now() - parsedUser.cachedAt < 300000) {
                            currentUser = parsedUser;
                            console.log('Using cached user data');
                        }
                    } catch(e) {}
                }
                
                const adminDoc = await db.collection(COLLECTIONS.ADMINS).doc(user.uid).get();
                
                if (adminDoc.exists) {
                    const adminData = adminDoc.data();
                    
                    await db.collection(COLLECTIONS.ADMINS).doc(user.uid).update({
                        lastLogin: firebase.firestore.FieldValue.serverTimestamp(),
                        totalLogins: firebase.firestore.FieldValue.increment(1)
                    });
                    
                    currentUser = {
                        uid: user.uid,
                        ...adminData,
                        role: 'admin'
                    };
                    
                    // Cache user data
                    localStorage.setItem(`user_${user.uid}`, JSON.stringify({
                        ...currentUser,
                        cachedAt: Date.now()
                    }));
                }
                else if (ADMIN_EMAILS.includes(user.email)) {
                    const adminData = {
                        uid: user.uid,
                        email: user.email,
                        name: user.displayName || 'Admin',
                        profileImage: user.photoURL || 'https://via.placeholder.com/150',
                        phone: user.phoneNumber || '',
                        adminId: generateId('ADM'),
                        adminRole: ADMIN_ROLES.SUPER_ADMIN,
                        permissions: {
                            manageOwners: true,
                            manageVenues: true,
                            manageBookings: true,
                            manageTournaments: true,
                            viewPayouts: true,
                            manageSlots: true,
                            manageAdmins: true
                        },
                        status: ADMIN_STATUS.ACTIVE,
                        role: 'admin',
                        createdBy: 'system',
                        createdAt: firebase.firestore.FieldValue.serverTimestamp(),
                        updatedAt: firebase.firestore.FieldValue.serverTimestamp(),
                        lastLogin: firebase.firestore.FieldValue.serverTimestamp(),
                        totalLogins: 1
                    };
                    
                    await db.collection(COLLECTIONS.ADMINS).doc(user.uid).set(adminData);
                    
                    currentUser = {
                        uid: user.uid,
                        ...adminData,
                        role: 'admin'
                    };
                    
                    // Cache user data
                    localStorage.setItem(`user_${user.uid}`, JSON.stringify({
                        ...currentUser,
                        cachedAt: Date.now()
                    }));
                }
                else {
                    const ownerDoc = await db.collection(COLLECTIONS.OWNERS).doc(user.uid).get();
                    
                    if (ownerDoc.exists) {
    const ownerData = ownerDoc.data();
    currentUser = {
        uid: user.uid,
        ...ownerData,
        role: 'owner',
        registrationPaid: ownerData.registrationPaid || false,
        registrationVerified: ownerData.registrationVerified || false
    };
                        
                        // Cache user data
                        localStorage.setItem(`user_${user.uid}`, JSON.stringify({
                            ...currentUser,
                            cachedAt: Date.now()
                        }));
                    } 
                    else {
                        const userDoc = await db.collection(COLLECTIONS.USERS).doc(user.uid).get();
                        
                        if (userDoc.exists) {
                            currentUser = {
                                uid: user.uid,
                                ...userDoc.data(),
                                role: 'user'
                            };
                            
                            // Cache user data
                            localStorage.setItem(`user_${user.uid}`, JSON.stringify({
                                ...currentUser,
                                cachedAt: Date.now()
                            }));
                        } else {
                            // Create new user - only essential data first
                            const urlParams = new URLSearchParams(window.location.search);
                            const refCode = urlParams.get('ref');
                            let referredBy = null;
                            
                            if (refCode) {
                                const referralSnapshot = await db.collection(COLLECTIONS.REFERRALS)
                                    .where('code', '==', refCode)
                                    .get();
                                
                                if (!referralSnapshot.empty) {
                                    referredBy = referralSnapshot.docs[0].data().ownerId;
                                }
                            }
                            
                            currentUser = {
                                uid: user.uid,
                                email: user.email,
                                name: user.displayName || 'User',
                                profileImage: user.photoURL || 'https://via.placeholder.com/150',
                                phone: user.phoneNumber || '',
                                role: 'user',
                                referralCode: generateReferralCode(),
                                referredBy,
                                createdAt: firebase.firestore.FieldValue.serverTimestamp(),
                                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                            };
                            
                            await db.collection(COLLECTIONS.USERS).doc(user.uid).set(currentUser);
                            
                            if (referredBy) {
                                await db.collection(COLLECTIONS.REFERRALS).add({
                                    code: currentUser.referralCode,
                                    userId: user.uid,
                                    referredBy,
                                    createdAt: firebase.firestore.FieldValue.serverTimestamp()
                                });
                            }
                            
                            // Cache user data
                            localStorage.setItem(`user_${user.uid}`, JSON.stringify({
                                ...currentUser,
                                cachedAt: Date.now()
                            }));
                        }
                    }
                }
            }
            
            console.log('FINAL currentUser role:', currentUser.role);
            
            hideLoading();
            
            // Show main page immediately
            showPage('main-page');
            
            // Load main page content in background (don't wait for it)
            setTimeout(() => {
                loadMainPage();
                updateProfileHeader();
                checkFirstBookingOffer();
                getUserLocation();
                updateMatchStatuses();
            }, 50);
            
            // Update dashboard links visibility
            const ownerLink = safeGetElement('owner-dashboard-link');
            const adminLink = safeGetElement('admin-dashboard-link');
            const ceoLink = safeGetElement('ceo-dashboard-link');
            const qrScanner = safeGetElement('header-qr-scanner');
            
            if (ownerLink) ownerLink.style.display = currentUser.role === 'owner' ? 'flex' : 'none';
            if (adminLink) adminLink.style.display = (currentUser.role === 'admin' || currentUser.role === 'ceo') ? 'flex' : 'none';
            if (ceoLink) ceoLink.style.display = currentUser.role === 'ceo' ? 'flex' : 'none';
            if (qrScanner) qrScanner.style.display = currentUser.role === 'owner' ? 'flex' : 'none';
            
            // Show referral code if user
            const profileReferralCode = safeGetElement('profile-referral-code');
            if (profileReferralCode && currentUser.role === 'user' && currentUser.referralCode) {
                profileReferralCode.style.display = 'flex';
                const referralCodeValue = safeGetElement('referral-code-value');
                if (referralCodeValue) referralCodeValue.textContent = currentUser.referralCode;
            }
            
            console.log('App loaded successfully');
            
        } catch (error) {
            console.error('Auth state change error:', error);
            hideLoading();
            showToast('Error loading user data: ' + error.message, 'error');
            
            // Still show main page even if there's error
            showPage('main-page');
        }
    } else {
        // User is logged out
        authStateProcessed = false;
        currentUser = null;
        removeAllListeners();
        
        // Clear cached user data
        if (localStorage.getItem('user_')) {
            Object.keys(localStorage).forEach(key => {
                if (key.startsWith('user_')) {
                    localStorage.removeItem(key);
                }
            });
        }
        
        // Hide splash screen quickly
        const splashScreen = safeGetElement('splash-screen');
        if (splashScreen) {
            splashScreen.classList.add('hide');
        }
        
        showPage('login-page');
    }
});

