// ==================== STRONG SLOT LOCKING SYSTEM ====================

const SLOT_LOCK_STATUS = {
    AVAILABLE: 'available',
    LOCKED: 'locked',
    BOOKED: 'booked',
    PENDING: 'pending'
};

const SLOT_LOCK_DURATION_MS = 10 * 60 * 1000; // 10 minutes lock duration

/**
 * Acquire a lock on a slot before payment
 */
async function acquireSlotLock(groundId, date, slotTime, bookingId) {
    console.log('Acquiring slot lock...');
    
    const [startTime, endTime] = slotTime.split('-');
    const lockId = generateId('LOCK');
    const expiresAt = new Date(Date.now() + SLOT_LOCK_DURATION_MS);
    
    try {
        // Use Firestore transaction to ensure atomic operation
        return await db.runTransaction(async (transaction) => {
            // Check existing slot
            const slotQuery = await db.collection(COLLECTIONS.SLOTS)
                .where('groundId', '==', groundId)
                .where('date', '==', date)
                .where('startTime', '==', startTime)
                .where('endTime', '==', endTime)
                .get();
            
            let slotRef;
            let existingSlot;
            
            if (slotQuery.empty) {
                // Create new slot record
                slotRef = db.collection(COLLECTIONS.SLOTS).doc();
                existingSlot = null;
            } else {
                slotRef = slotQuery.docs[0].ref;
                existingSlot = slotQuery.docs[0].data();
            }
            
            // Check if slot is available (not booked or locked by someone else)
            if (existingSlot) {
                const isBooked = existingSlot.status === SLOT_LOCK_STATUS.BOOKED;
                const isLockedByOther = existingSlot.status === SLOT_LOCK_STATUS.LOCKED && 
                                        existingSlot.lockedBy !== currentUser.uid &&
                                        existingSlot.lockExpiresAt && 
                                        existingSlot.lockExpiresAt.toDate() > new Date();
                
                if (isBooked) {
                    throw new Error('This slot is already booked');
                }
                
                if (isLockedByOther) {
                    throw new Error('This slot is being booked by another user. Please try again in a few minutes.');
                }
            }
            
            // Create lock record
            const lockData = {
                lockId: lockId,
                groundId: groundId,
                date: date,
                startTime: startTime,
                endTime: endTime,
                slotTime: slotTime,
                bookingId: bookingId,
                userId: currentUser.uid,
                userName: currentUser.name || currentUser.ownerName || 'User',
                status: SLOT_LOCK_STATUS.LOCKED,
                lockedAt: firebase.firestore.FieldValue.serverTimestamp(),
                expiresAt: firebase.firestore.Timestamp.fromDate(expiresAt)
            };
            
            // Store lock in separate collection
            const lockRef = db.collection('slot_locks').doc(lockId);
            transaction.set(lockRef, lockData);
            
            // Update or create slot with lock info
            if (slotRef) {
                if (existingSlot) {
                    transaction.update(slotRef, {
                        status: SLOT_LOCK_STATUS.LOCKED,
                        lockedBy: currentUser.uid,
                        lockExpiresAt: firebase.firestore.Timestamp.fromDate(expiresAt),
                        lockId: lockId,
                        updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                    });
                } else {
                    transaction.set(slotRef, {
                        groundId: groundId,
                        date: date,
                        startTime: startTime,
                        endTime: endTime,
                        status: SLOT_LOCK_STATUS.LOCKED,
                        lockedBy: currentUser.uid,
                        lockExpiresAt: firebase.firestore.Timestamp.fromDate(expiresAt),
                        lockId: lockId,
                        createdAt: firebase.firestore.FieldValue.serverTimestamp(),
                        updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                    });
                }
            }
            
            // Store lock info in session
            sessionStorage.setItem('slotLock', JSON.stringify({
                lockId: lockId,
                groundId: groundId,
                date: date,
                slotTime: slotTime,
                expiresAt: expiresAt.toISOString(),
                bookingId: bookingId
            }));
            
            console.log(`Slot lock acquired: ${lockId}`);
            return { success: true, lockId: lockId };
        });
        
    } catch (error) {
        console.error('Error acquiring slot lock:', error);
        return { success: false, error: error.message };
    }
}

/**
 * Release a slot lock (on payment failure or cancellation)
 */
async function releaseSlotLock(lockId, groundId, date, slotTime) {
    console.log('Releasing slot lock...');
    
    try {
        const [startTime, endTime] = slotTime.split('-');
        
        await db.runTransaction(async (transaction) => {
            // Get the lock
            const lockRef = db.collection('slot_locks').doc(lockId);
            const lockDoc = await transaction.get(lockRef);
            
            if (!lockDoc.exists) {
                console.log('Lock not found, may have expired');
                return;
            }
            
            // Delete the lock
            transaction.delete(lockRef);
            
            // Update slot status back to available
            const slotQuery = await db.collection(COLLECTIONS.SLOTS)
                .where('groundId', '==', groundId)
                .where('date', '==', date)
                .where('startTime', '==', startTime)
                .where('endTime', '==', endTime)
                .get();
            
            if (!slotQuery.empty) {
                const slotRef = slotQuery.docs[0].ref;
                const slot = slotQuery.docs[0].data();
                
                // Only release if still locked by this user
                if (slot.status === SLOT_LOCK_STATUS.LOCKED && slot.lockId === lockId) {
                    transaction.update(slotRef, {
                        status: SLOT_LOCK_STATUS.AVAILABLE,
                        lockedBy: null,
                        lockExpiresAt: null,
                        lockId: null,
                        updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                    });
                }
            }
        });
        
        // Clear session storage
        sessionStorage.removeItem('slotLock');
        console.log(`Slot lock released: ${lockId}`);
        return { success: true };
        
    } catch (error) {
        console.error('Error releasing slot lock:', error);
        return { success: false, error: error.message };
    }
}

/**
 * Confirm slot booking after successful payment
 */
async function confirmSlotBooking(lockId, groundId, date, slotTime, bookingId) {
    console.log('Confirming slot booking...');
    
    try {
        const [startTime, endTime] = slotTime.split('-');
        
        return await db.runTransaction(async (transaction) => {
            // Verify lock exists and is valid
            const lockRef = db.collection('slot_locks').doc(lockId);
            const lockDoc = await transaction.get(lockRef);
            
            if (!lockDoc.exists) {
                throw new Error('Slot lock not found. Please contact support.');
            }
            
            const lock = lockDoc.data();
            
            // Verify lock belongs to current user
            if (lock.userId !== currentUser.uid) {
                throw new Error('Invalid slot lock');
            }
            
            // Check if lock expired
            if (lock.expiresAt && lock.expiresAt.toDate() < new Date()) {
                throw new Error('Slot lock has expired. Please try booking again.');
            }
            
            // Delete the lock
            transaction.delete(lockRef);
            
            // Update slot to booked
            const slotQuery = await db.collection(COLLECTIONS.SLOTS)
                .where('groundId', '==', groundId)
                .where('date', '==', date)
                .where('startTime', '==', startTime)
                .where('endTime', '==', endTime)
                .get();
            
            if (!slotQuery.empty) {
                const slotRef = slotQuery.docs[0].ref;
                transaction.update(slotRef, {
                    status: SLOT_LOCK_STATUS.BOOKED,
                    bookingId: bookingId,
                    bookedBy: currentUser.uid,
                    bookedAt: firebase.firestore.FieldValue.serverTimestamp(),
                    lockedBy: null,
                    lockExpiresAt: null,
                    lockId: null,
                    updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                });
            } else {
                // Create slot record if it doesn't exist
                transaction.set(db.collection(COLLECTIONS.SLOTS).doc(), {
                    groundId: groundId,
                    date: date,
                    startTime: startTime,
                    endTime: endTime,
                    status: SLOT_LOCK_STATUS.BOOKED,
                    bookingId: bookingId,
                    bookedBy: currentUser.uid,
                    bookedAt: firebase.firestore.FieldValue.serverTimestamp(),
                    createdAt: firebase.firestore.FieldValue.serverTimestamp(),
                    updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                });
            }
            
            console.log(`Slot booking confirmed: ${lockId}`);
            return { success: true };
        });
        
    } catch (error) {
        console.error('Error confirming slot booking:', error);
        return { success: false, error: error.message };
    }
}

/**
 * Clean up expired locks (run every minute)
 */
async function cleanupExpiredLocks() {
    try {
        const now = new Date();
        
        // Get expired locks
        const expiredLocks = await db.collection('slot_locks')
            .where('expiresAt', '<=', now)
            .get();
        
        if (expiredLocks.empty) return;
        
        const batch = db.batch();
        
        for (const lockDoc of expiredLocks.docs) {
            const lock = lockDoc.data();
            
            // Delete the lock
            batch.delete(lockDoc.ref);
            
            // Update slot back to available
            const slotQuery = await db.collection(COLLECTIONS.SLOTS)
                .where('groundId', '==', lock.groundId)
                .where('date', '==', lock.date)
                .where('startTime', '==', lock.startTime)
                .where('endTime', '==', lock.endTime)
                .where('status', '==', SLOT_LOCK_STATUS.LOCKED)
                .where('lockId', '==', lock.lockId)
                .get();
            
            if (!slotQuery.empty) {
                const slotRef = slotQuery.docs[0].ref;
                batch.update(slotRef, {
                    status: SLOT_LOCK_STATUS.AVAILABLE,
                    lockedBy: null,
                    lockExpiresAt: null,
                    lockId: null,
                    updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                });
            }
        }
        
        await batch.commit();
        
        if (expiredLocks.size > 0) {
            console.log(`Cleaned up ${expiredLocks.size} expired slot locks`);
        }
        
    } catch (error) {
        console.error('Error cleaning up expired locks:', error);
    }
}

// Run lock cleanup every minute
setInterval(cleanupExpiredLocks, 60 * 1000);

