// ==================== IMAGE ERROR HANDLER ====================

/**
 * Handle image loading errors with local SVG fallbacks
 */
function handleImageError(img) {
    if (!img) return;
    
    // Get image type based on element ID or class
    let svgContent = '';
    
    // Profile images
    if (img.id === 'header-profile-img' || img.id === 'profile-image-large' || 
        img.classList.contains('profile-img') || img.closest('.profile-btn')) {
        svgContent = `<svg xmlns="http://www.w3.org/2000/svg" width="100%" height="100%" viewBox="0 0 24 24" fill="none" stroke="%23999" stroke-width="1.5">
            <circle cx="12" cy="8" r="4"/>
            <path d="M5 20v-2a7 7 0 0 1 14 0v2"/>
        </svg>`;
    }
    // Venue/Ground images
    else if (img.classList.contains('venue-image') || img.id === 'venue-gallery' || 
             img.classList.contains('ground-image')) {
        svgContent = `<svg xmlns="http://www.w3.org/2000/svg" width="100%" height="100%" viewBox="0 0 24 24" fill="none" stroke="%23999" stroke-width="1.5">
            <rect x="2" y="2" width="20" height="20" rx="2.18"/>
            <path d="M8 2v20M16 2v20M2 8h20M2 16h20"/>
            <circle cx="12" cy="12" r="3"/>
        </svg>`;
    }
    // Default
    else {
        svgContent = `<svg xmlns="http://www.w3.org/2000/svg" width="100%" height="100%" viewBox="0 0 24 24" fill="none" stroke="%23999" stroke-width="1.5">
            <circle cx="12" cy="12" r="10"/>
            <line x1="12" y1="8" x2="12" y2="12"/>
            <circle cx="12" cy="16" r="0.5" fill="currentColor"/>
        </svg>`;
    }
    
    // Convert SVG to data URL
    const svgBlob = new Blob([svgContent], { type: 'image/svg+xml' });
    const svgUrl = URL.createObjectURL(svgBlob);
    
    // Set fallback image
    img.src = svgUrl;
    img.style.objectFit = 'contain';
    img.style.padding = 'var(--space-sm)';
    img.style.backgroundColor = 'var(--gray-100)';
    
    // Clean up blob URL after image loads
    img.onload = () => URL.revokeObjectURL(svgUrl);
}

/**
 * Initialize global image error handling
 */
function initImageErrorHandling() {
    // Handle existing images
    const images = document.querySelectorAll('img');
    images.forEach(img => {
        // Skip images that already have error handlers
        if (img.hasAttribute('data-error-handled')) return;
        
        // Set error handler
        img.onerror = function() {
            handleImageError(this);
        };
        
        // Mark as handled
        img.setAttribute('data-error-handled', 'true');
        
        // If image is already broken, handle it
        if (!img.complete || img.naturalWidth === 0) {
            if (img.src && (img.src.includes('placeholder') || img.src.includes('via.placeholder'))) {
                handleImageError(img);
            }
        }
    });
    
    // Use MutationObserver for dynamically added images
    const observer = new MutationObserver(function(mutations) {
        mutations.forEach(function(mutation) {
            mutation.addedNodes.forEach(function(node) {
                if (node.nodeName === 'IMG') {
                    if (!node.hasAttribute('data-error-handled')) {
                        node.onerror = function() {
                            handleImageError(this);
                        };
                        node.setAttribute('data-error-handled', 'true');
                        
                        if (node.src && (node.src.includes('placeholder') || node.src.includes('via.placeholder'))) {
                            handleImageError(node);
                        }
                    }
                }
                if (node.querySelectorAll) {
                    const imgs = node.querySelectorAll('img:not([data-error-handled])');
                    imgs.forEach(img => {
                        img.onerror = function() {
                            handleImageError(this);
                        };
                        img.setAttribute('data-error-handled', 'true');
                        
                        if (img.src && (img.src.includes('placeholder') || img.src.includes('via.placeholder'))) {
                            handleImageError(img);
                        }
                    });
                }
            });
        });
    });
    
    observer.observe(document.body, { childList: true, subtree: true });
}

