function fixRegistrationButton() {
    console.log('Fixing registration button...');
    
    // Get the register form
    const registerForm = document.getElementById('register-form');
    if (!registerForm) {
        console.log('Register form not found yet');
        return;
    }
    
    // Remove any existing submit handlers and add new one
    const newForm = registerForm.cloneNode(true);
    registerForm.parentNode.replaceChild(newForm, registerForm);
    
    newForm.addEventListener('submit', handleUserRegister);
    console.log('Registration form handler attached successfully');
    
    // Also attach to the submit button directly as fallback
    const submitBtn = newForm.querySelector('.auth-btn-premium');
    if (submitBtn) {
        const newBtn = submitBtn.cloneNode(true);
        submitBtn.parentNode.replaceChild(newBtn, submitBtn);
        
        newBtn.addEventListener('click', function(e) {
            e.preventDefault();
            console.log('Register button clicked');
            const submitEvent = new Event('submit', { bubbles: true, cancelable: true });
            newForm.dispatchEvent(submitEvent);
        });
    }
    
    // Fix toggle password buttons
    document.querySelectorAll('#register-panel .toggle-password-modern').forEach(btn => {
        const newBtn = btn.cloneNode(true);
        btn.parentNode.replaceChild(newBtn, btn);
        
        newBtn.addEventListener('click', function() {
            const input = this.closest('.input-group-modern').querySelector('input');
            const icon = this.querySelector('i');
            
            if (input && input.type === 'password') {
                input.type = 'text';
                icon.classList.remove('fa-eye');
                icon.classList.add('fa-eye-slash');
            } else if (input) {
                input.type = 'password';
                icon.classList.remove('fa-eye-slash');
                icon.classList.add('fa-eye');
            }
        });
    });
    
    // Fix terms link
    const termsLink = document.getElementById('reg-terms-link');
    if (termsLink) {
        const newTermsLink = termsLink.cloneNode(true);
        termsLink.parentNode.replaceChild(newTermsLink, termsLink);
        newTermsLink.addEventListener('click', (e) => {
            e.preventDefault();
            showTerms();
        });
    }
    
    // Fix Google sign up button
    const googleSignUpBtn = document.getElementById('google-signin-btn-register');
    if (googleSignUpBtn) {
        const newGoogleBtn = googleSignUpBtn.cloneNode(true);
        googleSignUpBtn.parentNode.replaceChild(newGoogleBtn, googleSignUpBtn);
        newGoogleBtn.addEventListener('click', handleGoogleSignIn);
    }
}

// Update the existing handleGoogleSignIn function to handle new users properly
async function handleGoogleSignIn() {
    const provider = new firebase.auth.GoogleAuthProvider();
    
    showLoading('Signing in with Google...');
    
    try {
        const result = await auth.signInWithPopup(provider);
        const user = result.user;
        
        // Check if user exists in users collection
        const userDoc = await db.collection(COLLECTIONS.USERS).doc(user.uid).get();
        
        if (!userDoc.exists) {
            // Get referral code from URL
            const urlParams = new URLSearchParams(window.location.search);
            const refCode = urlParams.get('ref');
            let referredBy = null;
            
            if (refCode) {
                const referralSnapshot = await db.collection(COLLECTIONS.REFERRALS)
                    .where('code', '==', refCode)
                    .get();
                
                if (!referralSnapshot.empty) {
                    referredBy = referralSnapshot.docs[0].data().ownerId;
                }
            }
            
            // Create new user
            const userData = {
                uid: user.uid,
                name: user.displayName || 'User',
                email: user.email,
                phone: user.phoneNumber || '',
                profileImage: user.photoURL,
                role: 'user',
                referralCode: generateReferralCode(),
                referredBy: referredBy,
                referralCount: 0,
                createdAt: firebase.firestore.FieldValue.serverTimestamp(),
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            };
            
            await db.collection(COLLECTIONS.USERS).doc(user.uid).set(userData);
            
            if (referredBy) {
                await db.collection(COLLECTIONS.REFERRALS).add({
                    code: userData.referralCode,
                    userId: user.uid,
                    userName: userData.name,
                    referredBy: referredBy,
                    status: 'pending',
                    createdAt: firebase.firestore.FieldValue.serverTimestamp()
                });
            }
        }
        
        hideLoading();
        showToast('Login successful! Welcome to BookMyGame!', 'success');
        
    } catch (error) {
        hideLoading();
        console.error('Google Sign In error:', error);
        showToast(error.message, 'error');
    }
}

