function initPremiumAuth() {
    console.log('Initializing premium auth...');
    
    const loginTab = document.querySelector('.auth-tab[data-tab="login"]');
    const registerTab = document.querySelector('.auth-tab[data-tab="register"]');
    const loginPanel = document.getElementById('login-panel');
    const registerPanel = document.getElementById('register-panel');
    
    // Tab switching
    if (loginTab && registerTab && loginPanel && registerPanel) {
        const newLoginTab = loginTab.cloneNode(true);
        const newRegisterTab = registerTab.cloneNode(true);
        loginTab.parentNode.replaceChild(newLoginTab, loginTab);
        registerTab.parentNode.replaceChild(newRegisterTab, registerTab);
        
        newLoginTab.addEventListener('click', () => {
            newLoginTab.classList.add('active');
            newRegisterTab.classList.remove('active');
            loginPanel.classList.add('active');
            registerPanel.classList.remove('active');
        });
        
        newRegisterTab.addEventListener('click', () => {
            newRegisterTab.classList.add('active');
            newLoginTab.classList.remove('active');
            registerPanel.classList.add('active');
            loginPanel.classList.remove('active');
        });
    }
    
    // Fix toggle password buttons for both panels
    document.querySelectorAll('.toggle-password-modern').forEach(btn => {
        const newBtn = btn.cloneNode(true);
        btn.parentNode.replaceChild(newBtn, btn);
        
        newBtn.addEventListener('click', function() {
            const input = this.closest('.input-group-modern').querySelector('input');
            const icon = this.querySelector('i');
            
            if (input && input.type === 'password') {
                input.type = 'text';
                icon.classList.remove('fa-eye');
                icon.classList.add('fa-eye-slash');
            } else if (input) {
                input.type = 'password';
                icon.classList.remove('fa-eye-slash');
                icon.classList.add('fa-eye');
            }
        });
    });
    
    // Fix login form
    const loginForm = document.getElementById('login-form');
    if (loginForm) {
        const newLoginForm = loginForm.cloneNode(true);
        loginForm.parentNode.replaceChild(newLoginForm, loginForm);
        newLoginForm.addEventListener('submit', handleLogin);
    }
    
    // Fix register form
    fixRegistrationButton();
    
    // Fix Google sign in buttons
    const googleBtns = document.querySelectorAll('#google-signin-btn, #google-signin-btn-register');
    googleBtns.forEach(btn => {
        const newBtn = btn.cloneNode(true);
        btn.parentNode.replaceChild(newBtn, btn);
        newBtn.addEventListener('click', handleGoogleSignIn);
    });
    
    // Fix Forgot Password link
    const forgotLink = document.getElementById('forgot-password-link');
    if (forgotLink) {
        const newForgotLink = forgotLink.cloneNode(true);
        forgotLink.parentNode.replaceChild(newForgotLink, forgotLink);
        newForgotLink.addEventListener('click', handleForgotPassword);
    }
    
    // Fix Owner registration link
    const ownerLink = document.getElementById('show-owner-register-link');
    if (ownerLink) {
        const newOwnerLink = ownerLink.cloneNode(true);
        ownerLink.parentNode.replaceChild(newOwnerLink, ownerLink);
        newOwnerLink.addEventListener('click', (e) => {
            e.preventDefault();
            showOwnerTypeSelection();
        });
    }
}

