// ==================== DEBUG CAN ADD GROUND ====================

async function canAddGround() {
    if (!currentUser || currentUser.role !== 'owner') {
        console.log('❌ canAddGround: User not logged in or not owner');
        showToast('Please login as owner', 'error');
        return false;
    }
    
    try {
        // Always fetch fresh data from Firestore
        const ownerDoc = await safeFirestoreOperation(
            () => db.collection(COLLECTIONS.OWNERS).doc(currentUser.uid).get(),
            null
        );
        
        if (!ownerDoc || !ownerDoc.exists) {
            console.log('❌ canAddGround: Owner data not found');
            showToast('Owner data not found. Please contact support.', 'error');
            return false;
        }
        
        const owner = ownerDoc.data();
        
        console.log('📊 Owner data for canAddGround:', {
            ownerType: owner.ownerType,
            registrationPaid: owner.registrationPaid,
            registrationVerified: owner.registrationVerified,
            status: owner.status,
            isVerified: owner.isVerified,
            documentVerified: owner.documentVerified
        });
        
        // Check 1: Owner status
        if (owner.status !== OWNER_STATUS.ACTIVE) {
            console.log('❌ canAddGround: Owner account is blocked');
            showToast('Your account is blocked. Please contact support.', 'error');
            return false;
        }
        
        // Check 2: Document verification (THIS IS LIKELY THE ISSUE)
        if (!owner.documentVerified) {
            console.log('❌ canAddGround: Document not verified (electricity bill pending)');
            showToast('Your address verification is pending. Please upload electricity bill for verification.', 'warning');
            if (document.getElementById('owner-dashboard-page').classList.contains('active')) {
                loadOwnerDashboard('verification');
            }
            return false;
        }
        
        // ========== GET LIVE CONFIG FROM FIRESTORE ==========
        const configRef = db.collection('system_config').doc('owner_registration');
        const configDoc = await configRef.get();
        
        let isPaymentRequired = true;
        let paymentAmount = 499;
        
        if (configDoc.exists) {
            const config = configDoc.data();
            isPaymentRequired = config.paymentRequired === true;
            paymentAmount = config.paymentAmount || 499;
            console.log('✅ Live config loaded - Payment Required:', isPaymentRequired, 'Amount:', paymentAmount);
        } else {
            console.log('⚠️ No config found, using defaults');
        }
        
        // ========== HANDLE PAYMENT REQUIREMENT ==========
        if (isPaymentRequired) {
            console.log('💰 Payment IS required - checking owner payment status');
            
            if (!owner.registrationPaid || !owner.registrationVerified) {
                console.log('❌ canAddGround: Owner has NOT paid - blocking');
                showToast(`Please complete registration (₹${paymentAmount}) to add grounds.`, 'warning');
                
                // Show the payment banner
                const banner = document.getElementById('owner-reg-payment-banner');
                if (banner) {
                    banner.style.display = 'block';
                    const bannerText = banner.querySelector('.banner-text p');
                    if (bannerText) {
                        bannerText.textContent = `Pay ₹${paymentAmount} once and start listing your grounds instantly!`;
                    }
                    const payBtn = banner.querySelector('.pay-owner-fee-btn');
                    if (payBtn) {
                        payBtn.innerHTML = `<i class="fas fa-credit-card"></i> Pay ₹${paymentAmount} Now`;
                    }
                }
                return false;
            } else {
                console.log('✅ canAddGround: Owner has paid - allowing');
            }
        } else {
            console.log('🎉 Payment NOT required - auto-activating if needed');
            
            if (!owner.registrationPaid || !owner.registrationVerified) {
                console.log('🔄 Auto-activating owner (payment not required)');
                
                await db.collection(COLLECTIONS.OWNERS).doc(currentUser.uid).update({
                    registrationPaid: true,
                    registrationVerified: true,
                    registrationAutoApproved: true,
                    registrationAutoApprovedAt: firebase.firestore.FieldValue.serverTimestamp(),
                    registrationAmount: 0,
                    updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                });
                
                currentUser.registrationPaid = true;
                currentUser.registrationVerified = true;
                
                console.log('✅ Owner auto-activated successfully');
                
                const banner = document.getElementById('owner-reg-payment-banner');
                if (banner) banner.style.display = 'none';
                
                updateOwnerRegistrationStatus();
                showToast('Your account is now active! You can add grounds for free.', 'success');
            } else {
                console.log('✅ Owner already active');
            }
        }
        
        // Check 4: Owner type
        if (owner.ownerType === OWNER_TYPES.VENUE_OWNER || 
            owner.ownerType === OWNER_TYPES.PLOT_OWNER) {
            console.log('✅ canAddGround: ALL CHECKS PASSED - can add ground');
            return true;
        }
        
        console.log('❌ canAddGround: Invalid owner type:', owner.ownerType);
        showToast('Your account type does not allow adding grounds.', 'error');
        return false;
        
    } catch (error) {
        console.error('❌ canAddGround Error:', error);
        showToast('Error checking permissions. Please try again.', 'error');
        return false;
    }
}


