// ==================== HANDLE ADD GROUND WITH CLOUDINARY ====================

async function handleAddGround(e) {
    e.preventDefault();
    console.log('handleAddGround called');
    
    // Get all form values
    const groundName = document.getElementById('ground-name-input')?.value.trim();
    const sportType = document.getElementById('ground-sport-input')?.value;
    const pricePerHour = parseFloat(document.getElementById('ground-price-input')?.value);
    const groundAddress = document.getElementById('ground-address-input')?.value.trim();
    const fileInput = document.getElementById('ground-images');
    const groundImages = fileInput ? fileInput.files : [];
    
    // Validate inputs
    if (!groundName) {
        showToast('Please enter ground name', 'error');
        document.getElementById('ground-name-input')?.focus();
        return;
    }
    
    if (!sportType) {
        showToast('Please select sport type', 'error');
        document.getElementById('ground-sport-input')?.focus();
        return;
    }
    
    if (!pricePerHour || isNaN(pricePerHour)) {
        showToast('Please select a price per hour', 'error');
        document.getElementById('ground-price-input')?.focus();
        return;
    }
    
    const ALLOWED_PRICES = [99, 199, 299, 499, 799, 999, 1299, 1999, 2499];
    if (!ALLOWED_PRICES.includes(pricePerHour)) {
        showToast('Please select a valid price from the allowed options', 'error');
        document.getElementById('ground-price-input')?.focus();
        return;
    }
    
    // Show loading
    showLoading('Adding ground...');
    
    try {
        let imageUrls = [];
        
        // Upload images if any
        if (groundImages.length > 0) {
            imageUrls = await uploadToCloudinary(groundImages);
        }
        
        // Prepare ground data
        const groundData = {
            ownerId: currentUser.uid,
            groundName: groundName,
            sportType: sportType,
            pricePerHour: pricePerHour,
            groundAddress: groundAddress || '',
            images: imageUrls,
            rating: 0,
            totalReviews: 0,
            status: 'active',
            isVerified: false,
            createdAt: firebase.firestore.FieldValue.serverTimestamp(),
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        };
        
        // Add to Firestore
        await db.collection(COLLECTIONS.GROUNDS).add(groundData);
        
        // Update owner's grounds count
        await db.collection(COLLECTIONS.OWNERS).doc(currentUser.uid).update({
            groundsCount: firebase.firestore.FieldValue.increment(1),
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });
        
        hideLoading();
        showToast('Ground added successfully!', 'success');
        
        // Close modal
        closeModal('add-ground-modal');
        
        // Reset form
        resetAddGroundForm();
        
        // Refresh owner dashboard
        if (document.getElementById('owner-dashboard-page').classList.contains('active')) {
            loadOwnerDashboard('grounds');
        }
        
    } catch (error) {
        hideLoading();
        console.error('Error adding ground:', error);
        showToast('Error adding ground: ' + error.message, 'error');
    }
}
// ==================== COMPRESS IMAGE BEFORE UPLOAD ====================

async function compressImage(file, maxWidth = 1200, maxHeight = 1200, quality = 0.8) {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = (e) => {
            const img = new Image();
            img.src = e.target.result;
            img.onload = () => {
                const canvas = document.createElement('canvas');
                let width = img.width;
                let height = img.height;
                
                // Calculate new dimensions
                if (width > height) {
                    if (width > maxWidth) {
                        height = (height * maxWidth) / width;
                        width = maxWidth;
                    }
                } else {
                    if (height > maxHeight) {
                        width = (width * maxHeight) / height;
                        height = maxHeight;
                    }
                }
                
                canvas.width = width;
                canvas.height = height;
                
                const ctx = canvas.getContext('2d');
                ctx.drawImage(img, 0, 0, width, height);
                
                canvas.toBlob((blob) => {
                    const compressedFile = new File([blob], file.name, {
                        type: 'image/jpeg',
                        lastModified: Date.now()
                    });
                    resolve(compressedFile);
                }, 'image/jpeg', quality);
            };
            img.onerror = reject;
        };
        reader.onerror = reject;
    });
}

