// ==================== PROFESSIONAL QR SCANNER FOR OWNERS ====================


let currentScanning = false;

/**
 * Show professional QR scanner modal
 */
async function showProfessionalQRScanner() {
    console.log('showProfessionalQRScanner called');
    
    // Check if user is owner
    if (!currentUser) {
        showToast('Please login first', 'warning');
        return;
    }
    
    if (currentUser.role !== 'owner') {
        showToast('Only owners can verify bookings', 'error');
        return;
    }
    
    // Check if owner has grounds
    const hasGrounds = await checkOwnerHasGrounds();
    if (!hasGrounds) {
        showToast('Please add a ground first to verify entries', 'warning');
        setTimeout(() => {
            showOwnerDashboard();
            loadOwnerDashboard('grounds');
        }, 2000);
        return;
    }
    
    const modal = document.getElementById('professional-qr-modal');
    if (modal) {
        modal.style.display = 'flex';
        document.body.style.overflow = 'hidden';
        await initProfessionalQRScanner();
    }
}


/**
 * Check if owner has any grounds
 */
async function checkOwnerHasGrounds() {
    if (!currentUser || currentUser.role !== 'owner') return false;
    
    try {
        const groundsSnapshot = await db.collection(COLLECTIONS.GROUNDS)
            .where('ownerId', '==', currentUser.uid)
            .limit(1)
            .get();
        
        return !groundsSnapshot.empty;
    } catch (error) {
        console.error('Error checking grounds:', error);
        return false;
    }
}

/**
 * Initialize Professional QR Scanner
 */
async function initProfessionalQRScanner() {
    const readerElement = document.getElementById('professional-qr-reader');
    if (!readerElement) {
        console.error('QR reader element not found');
        showToast('Scanner not ready. Please refresh the page.', 'error');
        return;
    }
    
    // Clear previous scanner
    if (professionalScanner) {
        try {
            await professionalScanner.stop();
            professionalScanner.clear();
        } catch(e) {
            console.log('Scanner stop error:', e);
        }
        professionalScanner = null;
    }
    
    // Clear result area
    const resultDiv = document.getElementById('professional-qr-result');
    if (resultDiv) resultDiv.innerHTML = '';
    
    professionalScanner = new Html5Qrcode("professional-qr-reader");
    
    const qrConfig = {
        fps: 10,
        qrbox: { width: 250, height: 250 },
        aspectRatio: 1.0,
        showTorchButtonIfSupported: false,
        disableFlip: false
    };
    
    try {
        await professionalScanner.start(
            { facingMode: "environment" },
            qrConfig,
            onQRCodeScanned,
            (errorMessage) => {
                // Silent error handling
                if (errorMessage && !errorMessage.includes('No MultiFormat Readers')) {
                    console.log('Scan error:', errorMessage);
                }
            }
        );
        
        // Check for torch support
        await checkTorchSupport();
        
    } catch (err) {
        console.error('Scanner start error:', err);
        showToast('Camera access denied. Please ensure camera permissions are granted.', 'error');
        closeProfessionalQRScanner();
    }
}

/**
 * Check if torch is supported and show button
 */
async function checkTorchSupport() {
    const torchBtn = document.getElementById('toggle-torch');
    if (!torchBtn) return;
    
    try {
        const tracks = await navigator.mediaDevices.getUserMedia({ video: { facingMode: "environment" } });
        const track = tracks.getVideoTracks()[0];
        const capabilities = track.getCapabilities();
        
        if (capabilities.torch) {
            torchBtn.style.display = 'flex';
            track.stop();
        } else {
            torchBtn.style.display = 'none';
        }
    } catch(e) {
        console.log('Torch not supported:', e);
        torchBtn.style.display = 'none';
    }
}

/**
 * Handle QR code scan
 */
async function onQRCodeScanned(decodedText) {
    console.log('QR Code scanned:', decodedText);
    
    // Stop scanner immediately to prevent multiple scans
    await stopProfessionalScanner();
    
    // Process the QR code
    await processVerifiedQRCode(decodedText);
}

/**
 * Stop professional scanner
 */
async function stopProfessionalScanner() {
    if (professionalScanner && professionalScanner.isScanning) {
        try {
            await professionalScanner.stop();
        } catch(e) {
            console.log('Scanner stop error:', e);
        }
    }
    professionalScanner = null;
}

/**
 * Close professional QR scanner
 */
function closeProfessionalQRScanner() {
    const modal = document.getElementById('professional-qr-modal');
    if (modal) {
        modal.style.display = 'none';
        document.body.style.overflow = '';
    }
    
    stopProfessionalScanner();
    
    // Clear result area
    const resultDiv = document.getElementById('professional-qr-result');
    if (resultDiv) resultDiv.innerHTML = '';
}

/**
 * Toggle professional QR scanner (for header button)
 */
function toggleProfessionalQRScanner() {
    const modal = document.getElementById('professional-qr-modal');
    if (modal && modal.style.display === 'flex') {
        closeProfessionalQRScanner();
    } else {
        showProfessionalQRScanner();
    }
}

/**
 * Toggle torch light
 */
async function toggleTorch() {
    if (!professionalScanner || !professionalScanner.isScanning) return;
    
    try {
        torchEnabled = !torchEnabled;
        await professionalScanner.applyVideoConstraints({
            advanced: [{ torch: torchEnabled }]
        });
        
        const torchBtn = document.getElementById('toggle-torch');
        if (torchBtn) {
            torchBtn.classList.toggle('active', torchEnabled);
        }
    } catch(e) {
        console.error('Torch toggle error:', e);
        showToast('Torch not available on this device', 'error');
    }
}

/**
 * Select image from gallery and scan
 */
async function selectFromGallery() {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'image/*';
    input.onchange = async (e) => {
        const file = e.target.files[0];
        if (!file) return;
        
        showLoading('Reading QR code...');
        
        try {
            const result = await Html5Qrcode.scanFile(file, true);
            await processVerifiedQRCode(result);
            hideLoading();
        } catch (error) {
            hideLoading();
            showVerificationResult(false, null, 'Could not read QR code from image. Please try again.');
        }
    };
    input.click();
}

/**
 * Process verified QR code with security checks
 */
async function processVerifiedQRCode(qrData) {
    const resultDiv = document.getElementById('professional-qr-result');
    
    try {
        // Parse QR data
        let qrObject;
        try {
            qrObject = JSON.parse(qrData);
        } catch(e) {
            throw new Error('Invalid QR Code Format');
        }
        
        // SECURITY CHECK 1: Verify App ID
        if (!qrObject.appId || qrObject.appId !== 'BookMyGame') {
            throw new Error('This QR code was not generated by BookMyGame');
        }
        
        // SECURITY CHECK 2: Verify timestamp
        const now = new Date();
        const validFrom = new Date(qrObject.validFrom);
        const validTo = new Date(qrObject.validTo);
        
        if (now < validFrom) {
            throw new Error('QR Code is not valid yet');
        }
        
        if (now > validTo) {
            throw new Error('QR Code has expired');
        }
        
        // SECURITY CHECK 3: Get booking from database
        const bookingSnapshot = await db.collection(COLLECTIONS.BOOKINGS)
            .where('bookingId', '==', qrObject.bookingId)
            .get();
        
        if (bookingSnapshot.empty) {
            throw new Error('Booking not found in our system');
        }
        
        const bookingDoc = bookingSnapshot.docs[0];
        const booking = bookingDoc.data();
        
        // SECURITY CHECK 4: Verify ground ownership
        const groundDoc = await db.collection(COLLECTIONS.GROUNDS).doc(booking.groundId).get();
        
        if (!groundDoc.exists) {
            throw new Error('Ground not found');
        }
        
        const ground = groundDoc.data();
        
        if (ground.ownerId !== currentUser.uid) {
            throw new Error('You can only verify bookings for your own grounds');
        }
        
        // SECURITY CHECK 5: Verify ground ID matches
        if (booking.groundId !== qrObject.groundId) {
            throw new Error('QR code is for a different ground');
        }
        
        // SECURITY CHECK 6: Check if entry already used
        if (booking.entryStatus === 'used') {
            throw new Error('This entry has already been used');
        }
        
        // SECURITY CHECK 7: Check booking status
        if (booking.bookingStatus !== BOOKING_STATUS.CONFIRMED) {
            throw new Error(`Booking is not confirmed. Current status: ${booking.bookingStatus}`);
        }
        
        // SECURITY CHECK 8: Check date
        const today = new Date().toISOString().split('T')[0];
        if (booking.date !== today) {
            throw new Error(`This booking is for ${booking.date}. Today is ${today}.`);
        }
        
        // SECURITY CHECK 9: Check time window
        const [startHour, startMinute] = booking.slotTime.split('-')[0].split(':').map(Number);
        const slotStartTime = new Date(booking.date);
        slotStartTime.setHours(startHour, startMinute, 0);
        
        const entryStartTime = new Date(slotStartTime);
        entryStartTime.setMinutes(entryStartTime.getMinutes() - 15);
        
        const entryEndTime = new Date(slotStartTime);
        entryEndTime.setMinutes(entryEndTime.getMinutes() + 60);
        
        if (now < entryStartTime) {
            const minutesToWait = Math.ceil((entryStartTime - now) / 60000);
            throw new Error(`Entry will be allowed at ${entryStartTime.toLocaleTimeString()}. Please wait ${minutesToWait} minutes.`);
        }
        
        if (now > entryEndTime) {
            throw new Error(`Entry window closed at ${entryEndTime.toLocaleTimeString()}`);
        }
        
        // ALL CHECKS PASSED - Verify the entry
        await bookingDoc.ref.update({
            entryStatus: 'used',
            entryTime: firebase.firestore.FieldValue.serverTimestamp(),
            verifiedBy: currentUser.uid,
            verifiedByName: currentUser.ownerName || currentUser.name,
            verifiedAt: firebase.firestore.FieldValue.serverTimestamp(),
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });
        
        // Update ground stats
        await db.collection(COLLECTIONS.GROUNDS).doc(booking.groundId).update({
            lastVerifiedAt: firebase.firestore.FieldValue.serverTimestamp(),
            totalEntriesVerified: firebase.firestore.FieldValue.increment(1)
        });
        
        // Show success with booking details
        showVerificationResult(true, booking);
        
    } catch (error) {
        console.error('QR Verification Error:', error);
        showVerificationResult(false, null, error.message);
    }
}

/**
 * Show verification result modal
 */
function showVerificationResult(isSuccess, booking, errorMessage = '') {
    const modal = document.getElementById('verification-result-modal');
    const header = document.getElementById('verification-result-header');
    const icon = document.getElementById('result-icon');
    const title = document.getElementById('result-title');
    const body = document.getElementById('verification-result-body');
    
    if (isSuccess && booking) {
        // Success case
        if (header) header.className = 'verification-result-header success';
        if (icon) icon.innerHTML = '<i class="fas fa-check-circle"></i>';
        if (title) title.textContent = 'Entry Verified Successfully!';
        
        const bookingDate = new Date(booking.date);
        const formattedDate = bookingDate.toLocaleDateString('en-IN', {
            weekday: 'long',
            day: 'numeric',
            month: 'long',
            year: 'numeric'
        });
        
        const entryTime = booking.entryTime ? new Date(booking.entryTime.toDate()) : new Date();
        const verifiedTime = entryTime.toLocaleTimeString('en-IN', {
            hour: '2-digit',
            minute: '2-digit',
            second: '2-digit'
        });
        
        if (body) {
            body.innerHTML = `
                <div class="booking-detail-card success-card">
                    <div class="success-animation">
                        <i class="fas fa-check-circle"></i>
                    </div>
                    <h4>Entry Allowed</h4>
                    <p>Verified at ${verifiedTime}</p>
                </div>
                
                <div class="booking-detail-card">
                    <div class="detail-row">
                        <i class="fas fa-user"></i>
                        <div>
                            <span class="detail-label">Customer</span>
                            <span class="detail-value">${escapeHtml(booking.userName || 'N/A')}</span>
                        </div>
                    </div>
                    <div class="detail-row">
                        <i class="fas fa-phone"></i>
                        <div>
                            <span class="detail-label">Phone</span>
                            <span class="detail-value">${escapeHtml(booking.userPhone || 'N/A')}</span>
                        </div>
                    </div>
                    <div class="detail-row">
                        <i class="fas fa-hashtag"></i>
                        <div>
                            <span class="detail-label">Booking ID</span>
                            <span class="detail-value">${booking.bookingId}</span>
                        </div>
                    </div>
                </div>
                
                <div class="booking-detail-card">
                    <div class="detail-row">
                        <i class="fas fa-calendar"></i>
                        <div>
                            <span class="detail-label">Date</span>
                            <span class="detail-value">${formattedDate}</span>
                        </div>
                    </div>
                    <div class="detail-row">
                        <i class="fas fa-clock"></i>
                        <div>
                            <span class="detail-label">Time Slot</span>
                            <span class="detail-value">${booking.slotTime}</span>
                        </div>
                    </div>
                    <div class="detail-row">
                        <i class="fas fa-rupee-sign"></i>
                        <div>
                            <span class="detail-label">Amount</span>
                            <span class="detail-value">${formatCurrency(booking.amount)}</span>
                        </div>
                    </div>
                </div>
            `;
        }
    } else {
        // Error case
        if (header) header.className = 'verification-result-header error';
        if (icon) icon.innerHTML = '<i class="fas fa-times-circle"></i>';
        if (title) title.textContent = 'Verification Failed';
        
        if (body) {
            body.innerHTML = `
                <div class="booking-detail-card error-card">
                    <div class="error-animation">
                        <i class="fas fa-exclamation-triangle"></i>
                    </div>
                    <h4>Cannot Verify Entry</h4>
                    <p>${escapeHtml(errorMessage)}</p>
                </div>
                
                <div class="booking-detail-card info-card">
                    <div class="detail-row">
                        <i class="fas fa-info-circle"></i>
                        <div>
                            <span class="detail-label">What to do?</span>
                            <span class="detail-value">Please ask the customer to check their booking status or contact support.</span>
                        </div>
                    </div>
                </div>
            `;
        }
    }
    
    // Close QR scanner modal
    closeProfessionalQRScanner();
    
    // Show result modal
    if (modal) {
        modal.classList.add('active');
        document.body.style.overflow = 'hidden';
    }
}

