// Update your loadNearbyVenues function to use limits and avoid unnecessary queries
async function loadNearbyVenues() {
    const container = document.getElementById('nearby-venues');
    if (!container) return;
    
    // Show skeleton loading
    container.innerHTML = `
        <div class="skeleton-loading">
            <div class="skeleton-card"></div>
            <div class="skeleton-card"></div>
            <div class="skeleton-card"></div>
        </div>
    `;
    
    try {
        // Use Promise.all for parallel queries with limits
        const [venuesSnapshot, groundsSnapshot] = await Promise.all([
            db.collection(COLLECTIONS.VENUES)
                .where('hidden', '==', false)
                .limit(10)
                .get(),
            db.collection(COLLECTIONS.GROUNDS)
                .where('status', '==', 'active')
                .limit(10)
                .get()
        ]);
        
        // Process venues quickly
        let venues = [];
        venuesSnapshot.forEach(doc => {
            venues.push({ id: doc.id, type: 'venue', ...doc.data() });
        });
        
        // Process grounds quickly - don't fetch owner info for each ground
        let grounds = [];
        groundsSnapshot.forEach(doc => {
            const ground = doc.data();
            grounds.push({
                id: doc.id,
                type: 'ground',
                ...ground,
                ownerType: 'plot_owner' // Default, can be updated later
            });
        });
        
        // Combine and display
        let allItems = [...venues, ...grounds];
        
        // Display with basic info first
        displayVenueItems(container, allItems.slice(0, 4));
        
        // Then fetch owner info in background for accurate badges
        setTimeout(async () => {
            for (let i = 0; i < grounds.length; i++) {
                const ground = grounds[i];
                if (ground.ownerId) {
                    try {
                        const ownerDoc = await db.collection(COLLECTIONS.OWNERS).doc(ground.ownerId).get();
                        if (ownerDoc.exists) {
                            ground.ownerType = ownerDoc.data().ownerType || 'venue_owner';
                        }
                    } catch(e) {}
                }
            }
            // Refresh display with updated info
            displayVenueItems(container, allItems.slice(0, 4));
        }, 100);
        
    } catch (error) {
        console.error('Error loading venues:', error);
        container.innerHTML = `
            <div class="error-state">
                <i class="fas fa-exclamation-circle"></i>
                <p>Failed to load venues</p>
            </div>
        `;
    }
}

// Helper function to display venue items
function displayVenueItems(container, items) {
    if (!items.length) {
        container.innerHTML = `
            <div class="empty-state">
                <i class="fas fa-map-marker-alt"></i>
                <h3>No venues found nearby</h3>
                <p>Check back later for new listings</p>
            </div>
        `;
        return;
    }
    
    container.innerHTML = items.map(item => {
        const isPlotOwner = item.ownerType === 'plot_owner';
        const itemTypeIcon = isPlotOwner ? '<i class="fas fa-tree"></i>' : '<i class="fas fa-building"></i>';
        const itemTypeLabel = isPlotOwner ? 'Open Ground' : 'Sports Facility';
        const verifiedBadge = item.isVerified ? '<span class="verified-badge"><i class="fas fa-check-circle"></i></span>' : '';
        
        if (item.type === 'ground') {
            return `
                <div class="venue-card" data-ground-id="${item.id}" data-type="ground">
                    <img src="${item.images?.[0] || 'https://via.placeholder.com/120'}" 
                         alt="${escapeHtml(item.groundName)}" 
                         class="venue-image"
                         onerror="this.src='https://via.placeholder.com/120'">
                    <div class="venue-info">
                        <h3>${escapeHtml(item.groundName)} ${verifiedBadge}</h3>
                        <div class="venue-sport">${item.sportType || 'Multi-sport'}</div>
                        <div class="venue-type-badge">
                            <span class="badge ${isPlotOwner ? 'plot-owner-badge' : 'venue-owner-badge'}">
                                ${itemTypeIcon} ${itemTypeLabel}
                            </span>
                            ${item.pricePerHour ? `<span class="price-badge">${formatCurrency(item.pricePerHour)}/hr</span>` : ''}
                        </div>
                    </div>
                </div>
            `;
        } else {
            return `
                <div class="venue-card" data-venue-id="${item.id}" data-type="venue">
                    <img src="${item.images?.[0] || 'https://via.placeholder.com/120'}" 
                         alt="${escapeHtml(item.venueName)}" 
                         class="venue-image"
                         onerror="this.src='https://via.placeholder.com/120'">
                    <div class="venue-info">
                        <h3>${escapeHtml(item.venueName)} ${verifiedBadge}</h3>
                        <div class="venue-sport">${item.sportType || 'Multi-sport'}</div>
                        <div class="venue-type-badge">
                            <span class="badge venue-owner-badge">
                                <i class="fas fa-building"></i> Sports Facility
                            </span>
                        </div>
                    </div>
                </div>
            `;
        }
    }).join('');
    
    // Add click handlers
    document.querySelectorAll('.venue-card[data-venue-id]').forEach(card => {
        card.addEventListener('click', () => viewVenue(card.dataset.venueId));
    });
    document.querySelectorAll('.venue-card[data-ground-id]').forEach(card => {
        card.addEventListener('click', () => viewGround(card.dataset.groundId));
    });
}


async function viewVenue(venueId) {
    showLoading('Loading venue details...');
    
    try {
        const venueDoc = await db.collection(COLLECTIONS.VENUES).doc(venueId).get();
        
        if (!venueDoc.exists) {
            showToast('Venue not found', 'error');
            return;
        }
        
        currentVenue = { id: venueDoc.id, ...venueDoc.data() };
        
        document.getElementById('venue-name').textContent = currentVenue.venueName;
        document.getElementById('venue-rating').textContent = (currentVenue.rating || 0).toFixed(1);
        document.getElementById('reviews-count').textContent = `(${currentVenue.totalReviews || 0} reviews)`;
        document.getElementById('venue-address').textContent = currentVenue.address;
        document.getElementById('venue-description').textContent = currentVenue.description || 'No description available';
        
        if (currentVenue.isVerified) {
            document.getElementById('venue-verified-badge').style.display = 'inline';
        } else {
            document.getElementById('venue-verified-badge').style.display = 'none';
        }
        
        if (currentVenue.location) {
            const mapsUrl = `https://www.google.com/maps/search/?api=1&query=${currentVenue.location.latitude},${currentVenue.location.longitude}`;
            document.getElementById('open-maps').href = mapsUrl;
        }
        
        const gallery = document.getElementById('venue-gallery');
        const dots = document.getElementById('gallery-dots');
        
       if (currentVenue.images && currentVenue.images.length > 0) {
    gallery.innerHTML = '';
    currentVenue.images.forEach((img, idx) => {
        const imgElement = document.createElement('img');
        imgElement.src = img;
        imgElement.alt = currentVenue.venueName;
        imgElement.onerror = function() { this.src = 'https://via.placeholder.com/400x200'; };
        imgElement.style.cursor = 'pointer';
        imgElement.addEventListener('click', () => openImageViewer(currentVenue.images, idx));
        gallery.appendChild(imgElement);
    });
            gallery.innerHTML = currentVenue.images.map(img => 
                `<img src="${img}" alt="${currentVenue.venueName}" onerror="this.src='https://via.placeholder.com/400x200'">`
            ).join('');
            
            dots.innerHTML = currentVenue.images.map((_, i) => 
                `<span class="gallery-dot ${i === 0 ? 'active' : ''}"></span>`
            ).join('');
            
            let currentIndex = 0;
            const interval = setInterval(() => {
                if (!document.getElementById('venue-page').classList.contains('active')) {
                    clearInterval(interval);
                    return;
                }
                currentIndex = (currentIndex + 1) % currentVenue.images.length;
                gallery.style.transform = `translateX(-${currentIndex * 100}%)`;
                document.querySelectorAll('.gallery-dot').forEach((dot, i) => {
                    dot.classList.toggle('active', i === currentIndex);
                });
            }, 3000);
        } else {
            gallery.innerHTML = '<img src="https://via.placeholder.com/400x200" alt="No Image">';
            dots.innerHTML = '<span class="gallery-dot active"></span>';
        }
        
        await loadGrounds(venueId);
        
        hideLoading();
        showPage('venue-page');
    } catch (error) {
        hideLoading();
        showToast(error.message, 'error');
    }
}

async function loadGrounds(venueId) {
    const container = document.getElementById('grounds-list');
    
    if (!container) {
        console.error('Grounds list container not found');
        return;
    }
    
    try {
        if (!currentVenue) {
            container.innerHTML = '<p class="text-center">Venue information not available</p>';
            return;
        }
        
        const snapshot = await db.collection(COLLECTIONS.GROUNDS)
            .where('ownerId', '==', currentVenue.ownerId)
            .where('status', '==', 'active')
            .get();
        
        if (snapshot.empty) {
            container.innerHTML = '<p class="text-center">No grounds available at this venue</p>';
            return;
        }
        
        let html = '';
        snapshot.forEach(doc => {
            const ground = doc.data();
            const verifiedBadge = ground.isVerified ? 
                '<span class="verified-badge"><i class="fas fa-check-circle"></i></span>' : '';
            
            html += `
                <div class="ground-card" data-ground-id="${doc.id}">
                    <div class="ground-card-header">
                        <span class="ground-name">${ground.groundName || 'Unnamed Ground'} ${verifiedBadge}</span>
                        <span class="ground-price">${formatCurrency(ground.pricePerHour || 0)}/hr</span>
                    </div>
                    <div class="ground-sport">${ground.sportType || 'Multi-sport'}</div>
                    ${ground.groundAddress ? `<div class="ground-address-small">${ground.groundAddress}</div>` : ''}
                </div>
            `;
        });
        
        container.innerHTML = html;
        
        document.querySelectorAll('.ground-card').forEach(card => {
            card.addEventListener('click', () => {
                viewGround(card.dataset.groundId);
            });
        });
    } catch (error) {
        console.error('Error loading grounds:', error);
        container.innerHTML = '<p class="text-center">Failed to load grounds</p>';
    }
}

// ==================== COMPLETE FIXED VIEW GROUND FUNCTION ====================

async function viewGround(groundId) {
    showLoading('Loading ground details...');
    
    try {
        const groundDoc = await db.collection(COLLECTIONS.GROUNDS).doc(groundId).get();
        
        if (!groundDoc.exists) {
            showToast('Ground not found', 'error');
            hideLoading();
            return;
        }
        
        currentGround = { id: groundDoc.id, ...groundDoc.data() };
        
        // ========== STEP 1: STORE GROUND DATA ==========
        sessionStorage.setItem('currentGround', JSON.stringify(currentGround));
        sessionStorage.setItem('currentGroundId', currentGround.id);
        console.log('✅ Ground stored in session:', currentGround.groundName);
        
        // Get owner information
        const ownerDoc = await db.collection(COLLECTIONS.OWNERS).doc(currentGround.ownerId).get();
        let ownerInfo = '';
        let ownerVerified = false;
        let isPlotOwner = false;
        
        if (ownerDoc.exists) {
            const owner = ownerDoc.data();
            ownerVerified = owner.isVerified || false;
            isPlotOwner = owner.ownerType === OWNER_TYPES.PLOT_OWNER;
            ownerInfo = `
                <i class="fas fa-user"></i>
                <span>Owner: ${owner.ownerName || 'Unknown'} | Phone: ${owner.phone || 'Not available'}</span>
                ${isPlotOwner ? '<span class="plot-owner-badge"><i class="fas fa-tree"></i> Open Ground Owner</span>' : ''}
            `;
        }
        
        // Store plot owner status
        sessionStorage.setItem('isPlotOwnerGround', isPlotOwner ? 'true' : 'false');
        
        // Try to get venue information if this ground belongs to a venue owner
        let venueInfo = null;
        let groundAddress = '';
        
        if (!isPlotOwner) {
            const venueSnapshot = await db.collection(COLLECTIONS.VENUES)
                .where('ownerId', '==', currentGround.ownerId)
                .get();
            
            if (!venueSnapshot.empty) {
                const venue = venueSnapshot.docs[0].data();
                currentVenue = { id: venueSnapshot.docs[0].id, ...venue };
                sessionStorage.setItem('currentVenue', JSON.stringify(currentVenue));
                groundAddress = venue.address;
                if (currentGround.groundAddress) {
                    groundAddress += ' - ' + currentGround.groundAddress;
                }
                venueInfo = currentVenue;
            } else {
                groundAddress = currentGround.groundAddress || 'Address not available';
                currentVenue = null;
                sessionStorage.removeItem('currentVenue');
            }
        } else {
            groundAddress = currentGround.groundAddress || 'Location available upon booking';
            currentVenue = null;
            sessionStorage.removeItem('currentVenue');
        }
        
        // Initialize and display image gallery
        initializeGroundGallery(currentGround.images || []);
        
        const groundNameEl = document.getElementById('ground-name');
        const groundPriceEl = document.getElementById('ground-price');
        const groundSportEl = document.getElementById('ground-sport');
        const groundAddressEl = document.getElementById('ground-address');
        const groundOwnerContactEl = document.getElementById('ground-owner-contact');
        const ownerVerifiedEl = document.getElementById('owner-verified-badge');
        const plotOwnerBadge = document.getElementById('plot-owner-badge');
        
        if (!groundNameEl || !groundPriceEl || !groundSportEl || !groundAddressEl || !groundOwnerContactEl) {
            console.error('Ground page elements not found');
            showToast('Error loading ground page - elements missing', 'error');
            hideLoading();
            return;
        }
        
        groundNameEl.textContent = currentGround.groundName || 'Unknown Ground';
        groundPriceEl.textContent = formatCurrency(currentGround.pricePerHour) + '/hour';
        groundSportEl.textContent = currentGround.sportType || 'Multi-sport';
        
        if (isPlotOwner) {
            groundAddressEl.innerHTML = `
                <i class="fas fa-tree"></i>
                <span>${escapeHtml(groundAddress)}</span>
                <span class="plot-owner-tag" style="margin-left: auto; font-size: var(--font-xs); color: var(--success);">
                    <i class="fas fa-check-circle"></i> Open Ground
                </span>
            `;
        } else {
            groundAddressEl.innerHTML = `
                <i class="fas fa-map-pin"></i>
                <span>${escapeHtml(groundAddress)}</span>
            `;
        }
        
        groundOwnerContactEl.innerHTML = ownerInfo || '<i class="fas fa-user"></i><span>Owner information not available</span>';
        
        if (ownerVerifiedEl) {
            ownerVerifiedEl.style.display = ownerVerified ? 'flex' : 'none';
        }
        
        if (plotOwnerBadge) {
            if (isPlotOwner) {
                plotOwnerBadge.style.display = 'inline-flex';
                plotOwnerBadge.innerHTML = '<i class="fas fa-tree"></i> Open Ground';
            } else {
                plotOwnerBadge.style.display = 'none';
            }
        }
        
        if (currentUser) {
            document.getElementById('sticky-book-btn').style.display = 'block';
        }
        
        loadDateSelector();
        await loadSlots(groundId, selectedDate);
        await loadGroundReviews(groundId);
        
        hideLoading();
        showPage('ground-page');
        
    } catch (error) {
        hideLoading();
        console.error('Error loading ground:', error);
        showToast('Error loading ground details: ' + error.message, 'error');
    }
}

// ==================== INITIALIZE GROUND GALLERY ====================

let currentGalleryIndex = 0;
let galleryImages = [];
let galleryInterval = null;

// Update the initializeGroundGallery function to add click handlers
function initializeGroundGallery(images) {
    galleryImages = images || [];
    
    const galleryContainer = document.getElementById('ground-gallery');
    const dotsContainer = document.getElementById('gallery-dots');
    const prevBtn = document.getElementById('gallery-prev');
    const nextBtn = document.getElementById('gallery-next');
    
    if (!galleryContainer) return;
    
    // Clear existing gallery
    galleryContainer.innerHTML = '';
    if (dotsContainer) dotsContainer.innerHTML = '';
    
    // Stop any existing interval
    if (galleryInterval) {
        clearInterval(galleryInterval);
        galleryInterval = null;
    }
    
    // If no images, show placeholder
    if (!galleryImages || galleryImages.length === 0) {
        galleryContainer.innerHTML = `
            <div class="no-images-placeholder">
                <i class="fas fa-camera"></i>
                <p>No images available</p>
            </div>
        `;
        if (prevBtn) prevBtn.style.display = 'none';
        if (nextBtn) nextBtn.style.display = 'none';
        return;
    }
    
    if (prevBtn) prevBtn.style.display = 'flex';
    if (nextBtn) nextBtn.style.display = 'flex';
    
    // Create slides
    galleryImages.forEach((image, index) => {
        const slide = document.createElement('div');
        slide.className = `gallery-slide ${index === 0 ? 'active' : ''}`;
        
        const img = document.createElement('img');
        img.src = image;
        img.alt = `Ground image ${index + 1}`;
        img.onerror = function() {
            this.src = 'https://via.placeholder.com/400x300?text=Image+Not+Found';
        };
        
        // Add click handler for fullscreen view
        img.style.cursor = 'pointer';
        img.addEventListener('click', (e) => {
            e.stopPropagation();
            openImageViewer(galleryImages, index);
        });
        
        slide.appendChild(img);
        galleryContainer.appendChild(slide);
        
        // Create dot
        if (dotsContainer) {
            const dot = document.createElement('span');
            dot.className = `gallery-dot ${index === 0 ? 'active' : ''}`;
            dot.addEventListener('click', () => goToGallerySlide(index));
            dotsContainer.appendChild(dot);
        }
    });
    
    // Add navigation event listeners
    if (prevBtn) {
        const newPrevBtn = prevBtn.cloneNode(true);
        prevBtn.parentNode.replaceChild(newPrevBtn, prevBtn);
        newPrevBtn.addEventListener('click', previousGallerySlide);
    }
    
    if (nextBtn) {
        const newNextBtn = nextBtn.cloneNode(true);
        nextBtn.parentNode.replaceChild(newNextBtn, nextBtn);
        newNextBtn.addEventListener('click', nextGallerySlide);
    }
    
    // Start auto-play slideshow
    startGallerySlideshow();
    
    // Pause slideshow on hover
    const galleryContainerElement = document.querySelector('.ground-gallery-container');
    if (galleryContainerElement) {
        galleryContainerElement.addEventListener('mouseenter', () => {
            if (galleryInterval) {
                clearInterval(galleryInterval);
                galleryInterval = null;
            }
        });
        
        galleryContainerElement.addEventListener('mouseleave', () => {
            startGallerySlideshow();
        });
    }
}

function startGallerySlideshow() {
    if (galleryInterval) {
        clearInterval(galleryInterval);
    }
    
    if (galleryImages.length > 1) {
        galleryInterval = setInterval(() => {
            nextGallerySlide();
        }, 4000);
    }
}

function goToGallerySlide(index) {
    if (index === currentGalleryIndex) return;
    if (index < 0 || index >= galleryImages.length) return;
    
    // Update slides
    const slides = document.querySelectorAll('.ground-gallery .gallery-slide');
    const dots = document.querySelectorAll('.gallery-dot');
    
    if (slides[currentGalleryIndex]) {
        slides[currentGalleryIndex].classList.remove('active');
    }
    if (dots[currentGalleryIndex]) {
        dots[currentGalleryIndex].classList.remove('active');
    }
    
    currentGalleryIndex = index;
    
    if (slides[currentGalleryIndex]) {
        slides[currentGalleryIndex].classList.add('active');
    }
    if (dots[currentGalleryIndex]) {
        dots[currentGalleryIndex].classList.add('active');
    }
}

function previousGallerySlide() {
    if (galleryImages.length === 0) return;
    let newIndex = currentGalleryIndex - 1;
    if (newIndex < 0) newIndex = galleryImages.length - 1;
    goToGallerySlide(newIndex);
    
    // Reset slideshow timer
    if (galleryInterval) {
        clearInterval(galleryInterval);
        startGallerySlideshow();
    }
}

function nextGallerySlide() {
    if (galleryImages.length === 0) return;
    let newIndex = currentGalleryIndex + 1;
    if (newIndex >= galleryImages.length) newIndex = 0;
    goToGallerySlide(newIndex);
    
    // Reset slideshow timer
    if (galleryInterval) {
        clearInterval(galleryInterval);
        startGallerySlideshow();
    }
}


// ==================== CLEAR BOOKING SESSION ====================

function clearBookingSession() {
    console.log('Clearing booking session data');
    sessionStorage.removeItem('currentGround');
    sessionStorage.removeItem('currentGroundId');
    sessionStorage.removeItem('currentVenue');
    sessionStorage.removeItem('selectedDate');
    sessionStorage.removeItem('selectedSlot');
    sessionStorage.removeItem('pendingBooking');
    sessionStorage.removeItem('isPlotOwnerGround');
    sessionStorage.removeItem('slotLock');
    
    currentGround = null;
    currentVenue = null;
    selectedDate = null;
    selectedSlot = null;
}

// ==================== CREATE PENDING SLOT ====================

async function createPendingSlot(bookingDetails) {
    try {
        const [startTime, endTime] = bookingDetails.slotTime.split('-');
        
        // Check if slot already exists
        const existingSlot = await db.collection(COLLECTIONS.SLOTS)
            .where('groundId', '==', bookingDetails.groundId)
            .where('date', '==', bookingDetails.date)
            .where('startTime', '==', startTime)
            .where('endTime', '==', endTime)
            .get();
        
        if (existingSlot.empty) {
            // Create new pending slot
            await db.collection(COLLECTIONS.SLOTS).add({
                groundId: bookingDetails.groundId,
                date: bookingDetails.date,
                startTime: startTime,
                endTime: endTime,
                status: 'pending',
                bookingId: bookingDetails.bookingId,
                createdAt: firebase.firestore.FieldValue.serverTimestamp(),
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            });
        } else {
            // Update existing slot to pending
            await existingSlot.docs[0].ref.update({
                status: 'pending',
                bookingId: bookingDetails.bookingId,
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            });
        }
        
        console.log('Pending slot created for:', bookingDetails.slotTime);
        
    } catch (error) {
        console.error('Error creating pending slot:', error);
    }
}

