// ==================== VERIFY BOOKING PAYMENT MANUALLY ====================

async function verifyBookingPaymentManually(bookingDetails) {
    let confirmModal = document.getElementById('payment-verification-modal');
    
    if (!confirmModal) {
        const modalHtml = `
            <div id="payment-verification-modal" class="modal">
                <div class="modal-content" style="max-width: 350px;">
                    <div class="modal-header">
                        <h3><i class="fas fa-question-circle"></i> Verify Payment</h3>
                        <button class="close-btn" id="close-verification-modal">&times;</button>
                    </div>
                    <div class="modal-body" style="text-align: center;">
                        <div style="margin-bottom: var(--space-lg);">
                            <i class="fas fa-clock" style="font-size: 3rem; color: var(--warning);"></i>
                        </div>
                        <h4>Have you completed the payment?</h4>
                        <p style="margin: var(--space-md) 0;">Amount: <strong>${formatCurrency(bookingDetails.amount)}</strong></p>
                        <p style="margin-bottom: var(--space-lg);">Booking ID: <strong>${bookingDetails.bookingId}</strong></p>
                        <div class="payment-note" style="background: var(--primary-50); padding: var(--space-md); border-radius: var(--radius); margin-bottom: var(--space-xl);">
                            <i class="fas fa-info-circle"></i>
                            <span style="font-size: var(--font-xs);">Please make sure the payment was successful before confirming.</span>
                        </div>
                        <div style="display: flex; gap: var(--space-md);">
                            <button class="auth-btn" id="confirm-payment-yes" style="margin: 0; flex: 1;">Yes, I've Paid</button>
                            <button class="home-btn" id="confirm-payment-no" style="margin: 0; flex: 1;">Not Yet</button>
                        </div>
                    </div>
                </div>
            </div>
        `;
        document.body.insertAdjacentHTML('beforeend', modalHtml);
        
        document.getElementById('close-verification-modal').addEventListener('click', () => {
            confirmModal.classList.remove('active');
        });
    }
    
    confirmModal = document.getElementById('payment-verification-modal');
    confirmModal.classList.add('active');
    
    document.getElementById('confirm-payment-yes').onclick = async () => {
        confirmModal.classList.remove('active');
        showLoading('Confirming booking...');
        
        try {
            // Check slot availability again
            const [startTime, endTime] = bookingDetails.slotTime.split('-');
            const isAvailable = await checkSlotAvailability(
                bookingDetails.groundId,
                bookingDetails.date,
                startTime,
                endTime
            );
            
            if (!isAvailable) {
                throw new Error('Slot is no longer available');
            }
            
            // Create confirmed booking
            const confirmedBooking = {
                ...bookingDetails,
                bookingStatus: BOOKING_STATUS.CONFIRMED,
                paymentStatus: PAYMENT_STATUS.SUCCESS,
                paymentMethod: 'upi',
                confirmedAt: firebase.firestore.FieldValue.serverTimestamp(),
                createdAt: firebase.firestore.FieldValue.serverTimestamp(),
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            };
            
            await db.collection(COLLECTIONS.BOOKINGS).add(confirmedBooking);
            
            // Update slot to confirmed
            const slotQuery = await db.collection(COLLECTIONS.SLOTS)
                .where('groundId', '==', bookingDetails.groundId)
                .where('date', '==', bookingDetails.date)
                .where('startTime', '==', startTime)
                .where('endTime', '==', endTime)
                .get();
            
            if (!slotQuery.empty) {
                await slotQuery.docs[0].ref.update({
                    status: SLOT_STATUS.CONFIRMED,
                    bookingId: bookingDetails.bookingId,
                    updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                });
            }
            
            // Update owner's earnings
            await db.collection(COLLECTIONS.OWNERS).doc(bookingDetails.ownerId).update({
                totalEarnings: firebase.firestore.FieldValue.increment(bookingDetails.ownerAmount),
                totalBookings: firebase.firestore.FieldValue.increment(1),
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            });
            
            hideLoading();
            showToast('Booking confirmed successfully!', 'success');
            
            // Clear session storage
            clearBookingSession();
            
            // Apply first booking offer if applicable
            if (bookingDetails.appliedOffer) {
                localStorage.setItem('firstBookingOffer_' + currentUser.uid, 'true');
            }
            
            // Show success confirmation
            showBookingSuccessConfirmation(confirmedBooking);
            
        } catch (error) {
            hideLoading();
            console.error('Error confirming booking:', error);
            showToast('Error confirming booking: ' + error.message, 'error');
        }
    };
    
    document.getElementById('confirm-payment-no').onclick = () => {
        confirmModal.classList.remove('active');
    };
}


// ==================== COMPLETE TIME SLOT FUNCTIONS ====================


/**
 * Load date selector (7 days)
 */
function loadDateSelector() {
    const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    const dates = [];
    const today = new Date();
    
    for (let i = 0; i < 7; i++) {
        const date = new Date(today);
        date.setDate(today.getDate() + i);
        const dateStr = date.toISOString().split('T')[0];
        dates.push({
            day: days[date.getDay()],
            dateNum: date.getDate(),
            month: months[date.getMonth()],
            value: dateStr,
            isToday: i === 0
        });
    }
    
    const selector = document.getElementById('date-selector');
    if (!selector) return;
    
    selector.innerHTML = dates.map((d, index) => `
        <div class="date-chip ${index === 0 ? 'active' : ''}" data-date="${d.value}">
            <span class="day">${d.day}</span>
            <span class="date">${d.dateNum} ${d.month}</span>
        </div>
    `).join('');
    
    // Add click handlers
    document.querySelectorAll('.date-chip').forEach(chip => {
        chip.addEventListener('click', async function() {
            document.querySelectorAll('.date-chip').forEach(c => c.classList.remove('active'));
            this.classList.add('active');
            selectedDate = this.dataset.date;
            
            // Store selected date in session
            sessionStorage.setItem('selectedDate', selectedDate);
            console.log('✅ Date selected:', selectedDate);
            
            // Reload slots for the selected date
            if (currentGround && currentGround.id) {
                await loadSlots(currentGround.id, selectedDate);
            }
        });
    });
}

/**
 * Load time slots for a specific ground and date
 * Creates 24-hour time slots (00:00 to 23:00)
 */
async function loadSlots(groundId, date) {
    const container = document.getElementById('time-slots');
    
    if (!container) {
        console.error('Time slots container not found');
        return;
    }
    
    // Show loading state
    container.innerHTML = `
        <div class="loading-spinner" style="padding: var(--space-3xl);">
            <div class="loader-spinner"></div>
            <p style="margin-top: var(--space-md); color: var(--gray-500);">Loading available slots...</p>
        </div>
    `;
    
    try {
        // Fetch existing slots from Firestore
        const snapshot = await db.collection(COLLECTIONS.SLOTS)
            .where('groundId', '==', groundId)
            .where('date', '==', date)
            .get();
        
        // Create 24-hour slots (00:00 to 23:00)
        const defaultSlots = [];
        for (let hour = 0; hour < 24; hour++) {
            const startHour = hour.toString().padStart(2, '0');
            const endHour = (hour + 1).toString().padStart(2, '0');
            defaultSlots.push(`${startHour}:00-${endHour}:00`);
        }
        
        // Create status map from Firestore
        let slotStatusMap = {};
        snapshot.forEach(doc => {
            const slot = doc.data();
            const slotKey = `${slot.startTime}-${slot.endTime}`;
            slotStatusMap[slotKey] = slot.status;
        });
        
        const now = new Date();
        const currentTime = now.getHours() * 60 + now.getMinutes();
        const today = new Date().toISOString().split('T')[0];
        const isToday = date === today;
        
        // Build slots HTML
        let slotsHtml = '';
        
        defaultSlots.forEach(slot => {
            const status = slotStatusMap[slot] || SLOT_STATUS.AVAILABLE;
            let statusClass = '';
            let isDisabled = false;
            
            // Parse slot time
            const [startHour, startMinute] = slot.split('-')[0].split(':').map(Number);
            const slotStartTime = startHour * 60 + (startMinute || 0);
            
            // Check if slot is in the past (for today only)
            if (isToday && slotStartTime <= currentTime) {
                statusClass = 'past';
                isDisabled = true;
            }
            
            // Set status class based on slot status
            if (!isDisabled) {
                if (status === SLOT_STATUS.AVAILABLE) {
                    statusClass = 'available';
                } else if (status === SLOT_STATUS.CONFIRMED) {
                    statusClass = 'confirmed';
                    isDisabled = true;
                } else if (status === SLOT_STATUS.CLOSED) {
                    statusClass = 'closed';
                    isDisabled = true;
                } else if (status === 'pending') {
                    statusClass = 'pending';
                    isDisabled = true;
                } else if (status === 'locked') {
                    statusClass = 'locked';
                    isDisabled = true;
                }
            }
            
            // Format display time (remove leading zero for cleaner look)
            const displayTime = slot.replace('-', ' - ');
            
            slotsHtml += `
                <div class="time-slot ${statusClass}" 
                     data-slot="${slot}" 
                     data-status="${isDisabled ? 'disabled' : status}"
                     ${statusClass === 'available' && !isDisabled ? 'data-available="true"' : ''}>
                    ${displayTime}
                </div>
            `;
        });
        
        container.innerHTML = slotsHtml;
        
        // Add click handlers for available slots
        document.querySelectorAll('.time-slot.available').forEach(slot => {
            const newSlot = slot.cloneNode(true);
            slot.parentNode.replaceChild(newSlot, slot);
            
            newSlot.addEventListener('click', function() {
                const slotTime = this.dataset.slot;
                if (slotTime) {
                    selectSlot(slotTime);
                }
            });
        });
        
        // Highlight selected slot
        if (selectedSlot) {
            document.querySelectorAll('.time-slot').forEach(slot => {
                if (slot.dataset.slot === selectedSlot) {
                    slot.classList.add('selected');
                }
            });
        }
        
        console.log(`✅ Loaded ${defaultSlots.length} slots for ${date}`);
        
    } catch (error) {
        console.error('Error loading slots:', error);
        container.innerHTML = `
            <div class="error-state" style="text-align: center; padding: var(--space-3xl);">
                <i class="fas fa-exclamation-circle" style="font-size: 2rem; color: var(--danger); margin-bottom: var(--space-md);"></i>
                <p>Failed to load time slots</p>
                <button class="retry-btn" onclick="retryLoadSlots()" style="margin-top: var(--space-md);">Retry</button>
            </div>
        `;
    }
}

/**
 * Retry loading slots
 */
function retryLoadSlots() {
    if (currentGround && currentGround.id && selectedDate) {
        loadSlots(currentGround.id, selectedDate);
    }
}

/**
 * Retry loading slots
 */
async function retryLoadSlots() {
    if (currentGround && currentGround.id && selectedDate) {
        await loadSlots(currentGround.id, selectedDate);
    }
}

/**
 * Highlight the selected slot
 */
function highlightSelectedSlot(slot) {
    // Remove highlight from all slots
    document.querySelectorAll('.time-slot').forEach(s => {
        s.classList.remove('selected');
    });
    
    // Add highlight to selected slot
    const selectedElement = document.querySelector(`.time-slot[data-slot="${slot}"]`);
    if (selectedElement) {
        selectedElement.classList.add('selected');
        selectedElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
}

/**
 * Select a time slot
 */
function selectSlot(slot) {
    console.log('=== selectSlot called ===');
    console.log('Selected slot:', slot);
    
    if (!currentUser) {
        showToast('Please login to book', 'warning');
        return;
    }
    
    if (!currentGround) {
        showToast('Ground information not found. Please go back and select a ground again.', 'error');
        return;
    }
    
    const today = new Date().toISOString().split('T')[0];
    if (selectedDate === today) {
        const now = new Date();
        const currentTime = now.getHours() * 60 + now.getMinutes();
        const [startHour, startMinute] = slot.split('-')[0].split(':').map(Number);
        const slotStartTime = startHour * 60 + startMinute;
        
        if (slotStartTime <= currentTime) {
            showToast('This time slot has already passed', 'error');
            loadSlots(currentGround.id, selectedDate);
            return;
        }
    }
    
    selectedSlot = slot;
    
    // Store in session
    sessionStorage.setItem('selectedSlot', selectedSlot);
    console.log('✅ Slot stored:', selectedSlot);
    
    if (currentGround) {
        sessionStorage.setItem('currentGround', JSON.stringify(currentGround));
        sessionStorage.setItem('currentGroundId', currentGround.id);
    }
    if (selectedDate) {
        sessionStorage.setItem('selectedDate', selectedDate);
    }
    
    // Get venue info
    let venueName = '';
    let venueAddress = '';
    if (currentVenue) {
        venueName = currentVenue.venueName || '';
        venueAddress = currentVenue.address || '';
    }
    
    // Check if this is a plot owner ground
    const isPlotGround = currentGround.ownerType === 'plot_owner' || 
                         (currentGround.isPlotOwner === true);
    
    let amount;
    if (isPlotGround) {
        amount = PLOT_OWNER_FIXED_PRICE || 299;
    } else {
        amount = currentGround.pricePerHour;
    }
    
    // Check for first booking offer (20% off)
    const hasFirstBookingOffer = !localStorage.getItem('firstBookingOffer_' + currentUser.uid);
    const finalAmount = hasFirstBookingOffer ? amount * 0.8 : amount;
    
    const bookingDetails = {
        bookingId: generateId('BKG'),
        userId: currentUser.uid,
        userName: currentUser.name || currentUser.ownerName || 'User',
        userEmail: currentUser.email,
        userPhone: currentUser.phone || '',
        ownerId: currentGround.ownerId,
        groundId: currentGround.id,
        groundName: currentGround.groundName,
        venueName: venueName || (isPlotGround ? 'Open Ground' : 'Sports Facility'),
        venueAddress: venueAddress,
        groundAddress: currentGround.groundAddress || '',
        slotTime: selectedSlot,
        date: selectedDate,
        amount: finalAmount,
        originalAmount: amount,
        ownerAmount: finalAmount * 0.9,
        platformAmount: finalAmount * 0.1,
        sportType: currentGround.sportType,
        appliedOffer: hasFirstBookingOffer ? 'FIRST20' : null,
        isPlotOwner: isPlotGround,
        type: 'booking'
    };
    
    console.log('Booking details prepared:', bookingDetails);
    
    // Store pending booking for manual verification
    sessionStorage.setItem('pendingBooking', JSON.stringify(bookingDetails));
    sessionStorage.setItem('pendingCashfreeBooking', JSON.stringify(bookingDetails));
    
    // Also create pending record in Firestore
    db.collection('pending_bookings').doc(bookingDetails.bookingId).set({
        ...bookingDetails,
        orderId: bookingDetails.bookingId,
        createdAt: firebase.firestore.FieldValue.serverTimestamp(),
        status: 'pending_payment'
    }).catch(error => console.error('Error saving pending booking:', error));
    
    // Show booking page with Cashfree button
    showBookingPage(bookingDetails);
}

async function checkSlotAvailability(groundId, date, startTime, endTime) {
    try {
        const snapshot = await db.collection(COLLECTIONS.SLOTS)
            .where('groundId', '==', groundId)
            .where('date', '==', date)
            .where('startTime', '==', startTime)
            .where('endTime', '==', endTime)
            .get();
        
        if (snapshot.empty) {
            return true; // No slot record exists, so available
        }
        
        const slot = snapshot.docs[0].data();
        const now = new Date();
        
        // Check if slot is booked
        if (slot.status === 'booked' || slot.status === 'confirmed') {
            return false;
        }
        
        // Check if slot is locked by someone else
        if (slot.status === 'locked') {
            if (slot.lockExpiresAt) {
                const lockExpiresAt = slot.lockExpiresAt.toDate ? slot.lockExpiresAt.toDate() : new Date(slot.lockExpiresAt);
                if (lockExpiresAt > now) {
                    return false; // Still locked
                }
            }
        }
        
        return true;
        
    } catch (error) {
        console.error('Error checking slot availability:', error);
        return true; // Assume available on error
    }
}

/**
 * Get slot status text
 */
function getSlotStatusText(status) {
    switch(status) {
        case 'available': return 'Available';
        case 'booked': return 'Booked';
        case 'confirmed': return 'Booked';
        case 'pending': return 'Pending Payment';
        case 'locked': return 'Being Booked';
        case 'closed': return 'Closed';
        case 'past': return 'Slot Passed';
        default: return status;
    }
}

/**
 * Get slot status color
 */
function getSlotStatusColor(status) {
    switch(status) {
        case 'available': return 'var(--success)';
        case 'booked': return 'var(--danger)';
        case 'confirmed': return 'var(--danger)';
        case 'pending': return 'var(--warning)';
        case 'locked': return 'var(--info)';
        case 'closed': return 'var(--gray-500)';
        case 'past': return 'var(--gray-400)';
        default: return 'var(--gray-500)';
    }
}

/**
 * Format time for display
 */
function formatTimeSlot(slot) {
    return slot.replace('-', ' - ');
}

/**
 * Get time slot hour (for grouping)
 */
function getSlotHour(slot) {
    return parseInt(slot.split(':')[0]);
}

/**
 * Check if slot is in the past
 */
function isSlotInPast(slot, date) {
    const today = new Date().toISOString().split('T')[0];
    if (date !== today) return false;
    
    const now = new Date();
    const currentTime = now.getHours() * 60 + now.getMinutes();
    const [startHour, startMinute] = slot.split('-')[0].split(':').map(Number);
    const slotStartTime = startHour * 60 + (startMinute || 0);
    
    return slotStartTime <= currentTime;
}

/**
 * Get upcoming slots (for quick booking)
 */
function getUpcomingSlots() {
    const now = new Date();
    const currentHour = now.getHours();
    const slots = [];
    
    for (let i = 1; i <= 4; i++) {
        const hour = currentHour + i;
        if (hour < 24) {
            const startHour = hour.toString().padStart(2, '0');
            const endHour = (hour + 1).toString().padStart(2, '0');
            slots.push(`${startHour}:00-${endHour}:00`);
        }
    }
    
    return slots;
}

// ==================== PAYMENT FUNCTIONS ====================

function handleUPIPayment(upiApp) {
    if (!currentUser) {
        showToast('Please login to continue', 'warning');
        return;
    }
    
    if (!currentGround || !currentVenue) {
        showToast('Booking information missing', 'error');
        return;
    }
    
    if (!selectedSlot) {
        showToast('Please select a time slot first', 'error');
        return;
    }
    
    const [startTime, endTime] = selectedSlot.split('-');
    checkSlotAvailability(currentGround.id, selectedDate, startTime, endTime).then(isAvailable => {
        if (!isAvailable) {
            showToast('This slot is no longer available. Please select another slot.', 'error');
            loadSlots(currentGround.id, selectedDate);
            return;
        }
        
        const venueAddress = currentVenue ? currentVenue.address : '';
        const groundAddress = currentGround.groundAddress || '';
        const fullAddress = groundAddress ? `${venueAddress} - ${groundAddress}` : venueAddress;
        
        // Check for first booking offer
        let amount = currentGround.pricePerHour;
        const hasFirstBookingOffer = localStorage.getItem('firstBookingOffer_' + currentUser.uid) === 'true' ? false : true;
        
        if (hasFirstBookingOffer) {
            amount = amount * 0.8; // 20% off
        }
        
        const bookingDetails = {
            bookingId: generateId('BKG'),
            userId: currentUser.uid,
            userName: currentUser.name || 'User',
            userEmail: currentUser.email,
            userPhone: currentUser.phone,
            ownerId: currentGround.ownerId,
            groundId: currentGround.id,
            groundName: currentGround.groundName,
            venueName: currentVenue.venueName || 'Unknown Venue',
            venueAddress: venueAddress,
            groundAddress: fullAddress,
            slotTime: selectedSlot,
            date: selectedDate,
            amount: amount,
            originalAmount: currentGround.pricePerHour,
            commission: amount * COMMISSION_RATE,
            ownerAmount: amount * (1 - COMMISSION_RATE),
            sportType: currentGround.sportType,
            appliedOffer: hasFirstBookingOffer ? 'FIRST20' : null
        };
        
        initiatePhonePePayment(bookingDetails);
    });
}

// Add this function to app.js
// ==================== PHONEPE PAYMENT INTEGRATION ====================

/**
 * Initiate PhonePe Payment for Ground Booking
 * @param {Object} bookingDetails - Contains all booking information
 */
// ==================== FIXED PHONEPE PAYMENT WITH SAFE CRYPTO ====================
async function initiatePhonePePayment(bookingDetails) {
    console.log('=== Initiating PhonePe Payment ===');
    console.log('Booking Details:', bookingDetails);
    
    showLoading('Initiating payment...');
    
    try {
        // Validate required fields
        if (!bookingDetails) {
            throw new Error('Booking details are missing');
        }
        
        if (!bookingDetails.amount || bookingDetails.amount <= 0) {
            throw new Error('Invalid amount: ' + bookingDetails.amount);
        }
        
        if (!currentUser || !currentUser.uid) {
            throw new Error('User not logged in');
        }
        
        if (!bookingDetails.bookingId) {
            throw new Error('Booking ID is missing');
        }
        
        console.log('Validation passed. Amount: ₹' + bookingDetails.amount);
        
        // Store booking details in session storage for callback
        sessionStorage.setItem('pendingBooking', JSON.stringify({
            bookingId: bookingDetails.bookingId,
            groundId: bookingDetails.groundId,
            date: bookingDetails.date,
            slotTime: bookingDetails.slotTime,
            amount: bookingDetails.amount,
            initiatedAt: new Date().toISOString()
        }));
        
        const merchantId = 'PGTESTPAYUAT';
        const saltKey = '099eb0cd-02cf-4e2a-8aca-3e6c6aff0399';
        const saltIndex = 1;
        
        // Generate unique transaction ID
        const transactionId = generateTransactionId('TXN');
        const amountInPaise = Math.round(bookingDetails.amount * 100);
        
        console.log('Generated Transaction ID:', transactionId);
        
        // Create payload for PhonePe
        const payload = {
            merchantId: merchantId,
            merchantTransactionId: transactionId,
            merchantUserId: currentUser.uid,
            amount: amountInPaise,
            redirectUrl: `${window.location.origin}/payment-callback.html`,
            redirectMode: 'REDIRECT',
            callbackUrl: `${window.location.origin}/payment-webhook.html`,
            mobileNumber: currentUser.phone || '9999999999',
            paymentInstrument: {
                type: 'PAY_PAGE'
            }
        };
        
        console.log('PhonePe Payload:', payload);
        
        // Encode payload to base64
        const payloadString = JSON.stringify(payload);
        const base64Payload = btoa(unescape(encodeURIComponent(payloadString)));
        
        // Create signature
        const endpoint = '/pg/v1/pay';
        const stringToSign = base64Payload + endpoint + saltKey;
        
        // FIX: Safe crypto check with fallback
        let hashHex;
        
        // Check if crypto is available and ready
        if (typeof window !== 'undefined' && window.crypto && window.crypto.subtle) {
            try {
                // Wait for crypto to be ready
                await new Promise(resolve => setTimeout(resolve, 100));
                
                const encoder = new TextEncoder();
                const data = encoder.encode(stringToSign);
                const hashBuffer = await window.crypto.subtle.digest('SHA-256', data);
                const hashArray = Array.from(new Uint8Array(hashBuffer));
                hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
                console.log('Crypto hash generated successfully');
            } catch (cryptoError) {
                console.error('Crypto error:', cryptoError);
                // Fallback to simple hash for demonstration only
                // In production, you should use a server-side API for payment
                hashHex = generateFallbackHash(stringToSign);
                console.log('Using fallback hash');
            }
        } else {
            console.warn('Crypto API not available, using fallback');
            hashHex = generateFallbackHash(stringToSign);
        }
        
        const signature = hashHex + '###' + saltIndex;
        
        console.log('Signature created');
        
        // Determine API URL (UAT for testing)
        const apiUrl = 'https://api-preprod.phonepe.com/apis/pg-sandbox/pg/v1/pay';
        
        // Make API call to PhonePe
        console.log('Calling PhonePe API...');
        
        const response = await fetch(apiUrl, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'X-VERIFY': signature,
                'accept': 'application/json'
            },
            body: JSON.stringify({
                request: base64Payload
            })
        });
        
        const result = await response.json();
        console.log('PhonePe API Response:', result);
        
        if (result && result.success === true) {
            // Get payment URL from response
            const paymentUrl = result.data.instrumentResponse.redirectInfo.url;
            
            console.log('Payment URL received:', paymentUrl);
            
            // Store transaction details for verification
            sessionStorage.setItem('currentTransaction', transactionId);
            sessionStorage.setItem('currentBookingDetails', JSON.stringify(bookingDetails));
            
            // Create a pending slot in Firestore
            await createPendingSlot(bookingDetails, transactionId);
            
            // Create payment record in Firestore
            await createPaymentRecord({
                transactionId: transactionId,
                bookingId: bookingDetails.bookingId,
                userId: currentUser.uid,
                amount: bookingDetails.amount,
                status: 'initiated'
            });
            
            hideLoading();
            showToast('Redirecting to payment...', 'info');
            
            // Redirect to PhonePe payment page
            window.location.href = paymentUrl;
            
        } else {
            console.error('PhonePe API Error:', result);
            throw new Error(result.message || result.data?.message || 'Payment initiation failed');
        }
        
    } catch (error) {
        console.error('Payment Initiation Error:', error);
        console.error('Error Stack:', error.stack);
        
        hideLoading();
        
        // Show detailed error message
        let errorMessage = 'Payment failed: ';
        
        if (error.message.includes('Failed to fetch')) {
            errorMessage += 'Network error. Please check your internet connection.';
        } else if (error.message.includes('CORS')) {
            errorMessage += 'CORS error. Please check server configuration.';
        } else {
            errorMessage += error.message;
        }
        
        showToast(errorMessage, 'error');
        
        // Release the pending slot if any
        if (bookingDetails && bookingDetails.groundId && bookingDetails.date && bookingDetails.slotTime) {
            await releasePendingSlot(bookingDetails);
        }
        
        return false;
    }
}

// ==================== FALLBACK HASH GENERATOR ====================
// ==================== FALLBACK HASH GENERATOR ====================
function generateFallbackHash(string) {
    // Simple hash function for demonstration only
    // DO NOT use this for production - use proper crypto or server-side
    let hash = 0;
    for (let i = 0; i < string.length; i++) {
        const char = string.charCodeAt(i);
        hash = ((hash << 5) - hash) + char;
        hash = hash & hash;
    }
    return Math.abs(hash).toString(16).padStart(64, '0');
}
// ==================== HELPER FUNCTIONS ====================

/**
 * Generate unique transaction ID
 */
function generateTransactionId(prefix) {
    const timestamp = Date.now();
    const random = Math.floor(Math.random() * 1000000);
    const randomStr = random.toString().padStart(6, '0');
    return `${prefix}_${timestamp}_${randomStr}`;
}

/**
 * Create a pending slot in Firestore
 */
async function createPendingSlot(bookingDetails, transactionId) {
    try {
        const [startTime, endTime] = bookingDetails.slotTime.split('-');
        
        const slotData = {
            groundId: bookingDetails.groundId,
            date: bookingDetails.date,
            startTime: startTime,
            endTime: endTime,
            status: 'pending',
            bookingId: bookingDetails.bookingId,
            transactionId: transactionId,
            createdAt: firebase.firestore.FieldValue.serverTimestamp(),
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        };
        
        await db.collection('slots').add(slotData);
        console.log('Pending slot created');
        
    } catch (error) {
        console.error('Error creating pending slot:', error);
    }
}

/**
 * Create payment record in Firestore
 */
async function createPaymentRecord(paymentData) {
    try {
        const paymentRecord = {
            paymentId: generateTransactionId('PAY'),
            transactionId: paymentData.transactionId,
            bookingId: paymentData.bookingId,
            userId: paymentData.userId,
            amount: paymentData.amount,
            status: paymentData.status,
            initiatedAt: firebase.firestore.FieldValue.serverTimestamp(),
            createdAt: firebase.firestore.FieldValue.serverTimestamp()
        };
        
        await db.collection('payments').add(paymentRecord);
        console.log('Payment record created');
        
    } catch (error) {
        console.error('Error creating payment record:', error);
    }
}

/**
 * Release a pending slot if payment fails
 */
async function releasePendingSlot(bookingDetails) {
    try {
        const [startTime, endTime] = bookingDetails.slotTime.split('-');
        
        const snapshot = await db.collection('slots')
            .where('groundId', '==', bookingDetails.groundId)
            .where('date', '==', bookingDetails.date)
            .where('startTime', '==', startTime)
            .where('endTime', '==', endTime)
            .where('status', '==', 'pending')
            .get();
        
        if (!snapshot.empty) {
            const batch = db.batch();
            snapshot.forEach(doc => {
                batch.update(doc.ref, {
                    status: 'available',
                    bookingId: null,
                    updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                });
            });
            await batch.commit();
            console.log('Pending slot released');
        }
        
    } catch (error) {
        console.error('Error releasing pending slot:', error);
    }
}

/**
 * Verify payment status
 */
async function verifyPaymentStatus(transactionId) {
    try {
        const merchantId = 'PGTESTPAYUAT';
        const saltKey = '099eb0cd-02cf-4e2a-8aca-3e6c6aff0399';
        const saltIndex = 1;
        
        const endpoint = `/pg/v1/status/${merchantId}/${transactionId}`;
        const stringToSign = endpoint + saltKey;
        
        const encoder = new TextEncoder();
        const data = encoder.encode(stringToSign);
        const hashBuffer = await crypto.subtle.digest('SHA-256', data);
        const hashArray = Array.from(new Uint8Array(hashBuffer));
        const hashHex = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
        const signature = hashHex + '###' + saltIndex;
        
        const apiUrl = `https://api-preprod.phonepe.com/apis/pg-sandbox${endpoint}`;
        
        const response = await fetch(apiUrl, {
            method: 'GET',
            headers: {
                'Content-Type': 'application/json',
                'X-VERIFY': signature,
                'X-MERCHANT-ID': merchantId
            }
        });
        
        const result = await response.json();
        console.log('Payment verification result:', result);
        
        return {
            success: result.code === 'PAYMENT_SUCCESS',
            data: result
        };
        
    } catch (error) {
        console.error('Payment verification error:', error);
        return {
            success: false,
            error: error.message
        };
    }
}



