async function deleteGround(groundId, groundName) {
    // Validate inputs
    if (!groundId || !groundName) {
        showToast('Invalid ground information', 'error');
        return;
    }
    
    if (!currentUser || currentUser.role !== 'owner') {
        showToast('You must be logged in as an owner to delete grounds', 'error');
        return;
    }
    
    // Show confirmation dialog
    const confirmed = await showDeleteConfirmationModal(
        'Delete Ground',
        `Are you sure you want to delete "${groundName}"?`,
        'This action cannot be undone. All associated bookings and slots will be permanently removed.'
    );
    
    if (!confirmed) return;
    
    showLoading('Deleting ground...');
    
    try {
        // First, verify the ground exists and the user owns it
        const groundRef = db.collection(COLLECTIONS.GROUNDS).doc(groundId);
        const groundDoc = await groundRef.get();
        
        if (!groundDoc.exists) {
            throw new Error('Ground not found');
        }
        
        const ground = groundDoc.data();
        
        // Verify the current user owns this ground
        if (ground.ownerId !== currentUser.uid) {
            throw new Error('You do not have permission to delete this ground');
        }
        
        // Check for upcoming confirmed bookings
        const today = new Date().toISOString().split('T')[0];
        const upcomingBookingsSnapshot = await db.collection(COLLECTIONS.BOOKINGS)
            .where('groundId', '==', groundId)
            .where('date', '>=', today)
            .where('bookingStatus', '==', BOOKING_STATUS.CONFIRMED)
            .get();
        
        if (upcomingBookingsSnapshot.size > 0) {
            throw new Error(`Cannot delete ground with ${upcomingBookingsSnapshot.size} upcoming confirmed bookings. Please contact support for assistance.`);
        }
        
        // Get all slots for this ground
        const slotsSnapshot = await db.collection(COLLECTIONS.SLOTS)
            .where('groundId', '==', groundId)
            .get();
        
        // Get all bookings for this ground (including past and cancelled)
        const bookingsSnapshot = await db.collection(COLLECTIONS.BOOKINGS)
            .where('groundId', '==', groundId)
            .get();
        
        // Use batch operations for better performance and atomicity
        const batch = db.batch();
        
        // Delete all slots
        slotsSnapshot.forEach(doc => {
            batch.delete(doc.ref);
        });
        
        // Delete all bookings
        bookingsSnapshot.forEach(doc => {
            batch.delete(doc.ref);
        });
        
        // Delete the ground
        batch.delete(groundRef);
        
        // Commit all deletions
        await batch.commit();
        
        // Update owner's grounds count
        const ownerRef = db.collection(COLLECTIONS.OWNERS).doc(currentUser.uid);
        const ownerDoc = await ownerRef.get();
        
        if (ownerDoc.exists) {
            const currentGroundsCount = ownerDoc.data().groundsCount || 0;
            await ownerRef.update({
                groundsCount: Math.max(0, currentGroundsCount - 1),
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            });
        }
        
        hideLoading();
        showToast(`Ground "${groundName}" deleted successfully!`, 'success');
        
        // Refresh the owner dashboard grounds tab
        if (document.getElementById('owner-dashboard-page').classList.contains('active')) {
            loadOwnerDashboard('grounds');
        }
        
        // Also refresh the main page if ground was visible there
        if (document.getElementById('main-page').classList.contains('active')) {
            loadNearbyVenues();
        }
        
    } catch (error) {
        hideLoading();
        console.error('Error deleting ground:', error);
        
        // Handle specific error types
        if (error.code === 'permission-denied') {
            showToast('You don\'t have permission to delete this ground. Please contact support.', 'error');
        } else if (error.message.includes('upcoming confirmed bookings')) {
            showToast(error.message, 'error');
        } else {
            showToast('Error deleting ground: ' + error.message, 'error');
        }
    }
}

async function deleteVenue(venueId, venueName) {
    if (!venueId || !venueName) {
        showToast('Invalid venue information', 'error');
        return;
    }
    
    if (!currentUser || currentUser.role !== 'owner') {
        showToast('You must be logged in as an owner to delete a venue', 'error');
        return;
    }
    
    // Show confirmation dialog
    const confirmed = await showDeleteConfirmationModal(
        'Delete Venue',
        `Are you sure you want to delete "${venueName}"?`,
        'This action cannot be undone. All associated grounds, slots, and bookings will be permanently removed.'
    );
    
    if (!confirmed) return;
    
    showLoading('Deleting venue...');
    
    try {
        const venueRef = db.collection(COLLECTIONS.VENUES).doc(venueId);
        const venueDoc = await venueRef.get();
        
        if (!venueDoc.exists) {
            throw new Error('Venue not found');
        }
        
        const venue = venueDoc.data();
        
        // Verify the current user owns this venue
        if (venue.ownerId !== currentUser.uid) {
            throw new Error('You do not have permission to delete this venue');
        }
        
        // Get all grounds for this venue
        const groundsSnapshot = await db.collection(COLLECTIONS.GROUNDS)
            .where('ownerId', '==', currentUser.uid)
            .get();
        
        // Check if there are any future confirmed bookings across all grounds
        const today = new Date().toISOString().split('T')[0];
        let hasFutureBookings = false;
        let futureBookingCount = 0;
        
        for (const doc of groundsSnapshot.docs) {
            const bookingsSnapshot = await db.collection(COLLECTIONS.BOOKINGS)
                .where('groundId', '==', doc.id)
                .where('date', '>=', today)
                .where('bookingStatus', '==', BOOKING_STATUS.CONFIRMED)
                .get();
            
            if (!bookingsSnapshot.empty) {
                hasFutureBookings = true;
                futureBookingCount += bookingsSnapshot.size;
            }
        }
        
        if (hasFutureBookings) {
            throw new Error(`Cannot delete venue with ${futureBookingCount} upcoming confirmed bookings across its grounds. Please cancel them first or contact support.`);
        }
        
        // Use batch for all deletions
        const batch = db.batch();
        
        // Delete all grounds and their associated data
        for (const doc of groundsSnapshot.docs) {
            const groundId = doc.id;
            
            // Get slots for this ground
            const slotsSnapshot = await db.collection(COLLECTIONS.SLOTS)
                .where('groundId', '==', groundId)
                .get();
            
            slotsSnapshot.forEach(slotDoc => {
                batch.delete(slotDoc.ref);
            });
            
            // Get bookings for this ground
            const bookingsSnapshot = await db.collection(COLLECTIONS.BOOKINGS)
                .where('groundId', '==', groundId)
                .get();
            
            bookingsSnapshot.forEach(bookingDoc => {
                batch.delete(bookingDoc.ref);
            });
            
            // Delete the ground
            batch.delete(doc.ref);
        }
        
        // Delete the venue
        batch.delete(venueRef);
        
        // Commit all deletions
        await batch.commit();
        
        // Update owner's grounds count to 0
        await db.collection(COLLECTIONS.OWNERS).doc(currentUser.uid).update({
            groundsCount: 0,
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });
        
        hideLoading();
        showToast(`Venue "${venueName}" and all its grounds deleted successfully!`, 'success');
        
        // Refresh the owner dashboard
        if (document.getElementById('owner-dashboard-page').classList.contains('active')) {
            loadOwnerDashboard('grounds');
        }
        
    } catch (error) {
        hideLoading();
        console.error('Error deleting venue:', error);
        
        if (error.code === 'permission-denied') {
            showToast('You don\'t have permission to delete this venue. Please contact support.', 'error');
        } else {
            showToast('Error deleting venue: ' + error.message, 'error');
        }
    }
}

// ==================== SHOW DELETE CONFIRMATION MODAL ====================

function showDeleteConfirmationModal(title, message, detail) {
    return new Promise((resolve) => {
        let modal = document.getElementById('delete-confirmation-modal');
        
        if (!modal) {
            const modalHtml = `
                <div id="delete-confirmation-modal" class="modal">
                    <div class="modal-content" style="max-width: 400px;">
                        <div class="modal-header">
                            <h3><i class="fas fa-exclamation-triangle" style="color: var(--danger);"></i> ${title}</h3>
                            <button class="close-btn" id="close-delete-confirmation-modal">&times;</button>
                        </div>
                        <div class="modal-body">
                            <div class="delete-confirmation-content">
                                <div class="warning-icon" style="font-size: 3rem; color: var(--danger); text-align: center; margin-bottom: var(--space-lg);">
                                    <i class="fas fa-trash-alt"></i>
                                </div>
                                <h4 class="confirmation-title" style="text-align: center; margin-bottom: var(--space-md);">${message}</h4>
                                <p class="confirmation-detail" style="text-align: center; color: var(--gray-600); margin-bottom: var(--space-xl);">${detail}</p>
                                <div class="confirmation-actions" style="display: flex; gap: var(--space-md);">
                                    <button class="confirmation-btn confirm delete" id="confirm-delete-btn" style="flex: 1; background: var(--danger); color: white; padding: var(--space-md); border: none; border-radius: var(--radius); font-weight: 600; cursor: pointer;">
                                        <i class="fas fa-trash-alt"></i> Delete Permanently
                                    </button>
                                    <button class="confirmation-btn cancel" id="cancel-delete-btn" style="flex: 1; background: var(--gray-100); color: var(--gray-700); padding: var(--space-md); border: none; border-radius: var(--radius); font-weight: 600; cursor: pointer;">
                                        Cancel
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            `;
            document.body.insertAdjacentHTML('beforeend', modalHtml);
            
            document.getElementById('close-delete-confirmation-modal').addEventListener('click', () => {
                closeModal('delete-confirmation-modal');
                resolve(false);
            });
            
            document.getElementById('cancel-delete-btn').addEventListener('click', () => {
                closeModal('delete-confirmation-modal');
                resolve(false);
            });
        }
        
        // Update modal content with dynamic values
        const modalTitle = document.querySelector('#delete-confirmation-modal .modal-header h3');
        const modalMessage = document.querySelector('#delete-confirmation-modal .confirmation-title');
        const modalDetail = document.querySelector('#delete-confirmation-modal .confirmation-detail');
        
        if (modalTitle) modalTitle.innerHTML = `<i class="fas fa-exclamation-triangle" style="color: var(--danger);"></i> ${title}`;
        if (modalMessage) modalMessage.textContent = message;
        if (modalDetail) modalDetail.textContent = detail;
        
        const modalEl = document.getElementById('delete-confirmation-modal');
        modalEl.classList.add('active');
        
        // Add event listener for confirm button
        const confirmBtn = document.getElementById('confirm-delete-btn');
        const newConfirmBtn = confirmBtn.cloneNode(true);
        confirmBtn.parentNode.replaceChild(newConfirmBtn, confirmBtn);
        
        newConfirmBtn.addEventListener('click', () => {
            closeModal('delete-confirmation-modal');
            resolve(true);
        });
        
        // Handle modal close via backdrop click
        modalEl.addEventListener('click', (e) => {
            if (e.target === modalEl) {
                closeModal('delete-confirmation-modal');
                resolve(false);
            }
        });
    });
}


