// Update showAddGroundModal function to remove payment check (around line 3820-3840)

// ==================== SHOW ADD GROUND MODAL (FIXED) ====================
function showAddGroundModal() {
    console.log('showAddGroundModal called - opening add ground modal');
    
    // Check if user is logged in as owner
    if (!currentUser) {
        showToast('Please login first', 'warning');
        return;
    }
    
    if (currentUser.role !== 'owner') {
        showToast('Only owners can add grounds', 'error');
        return;
    }
    
    // Check if owner has paid registration fee
    if (!currentUser.registrationPaid || !currentUser.registrationVerified) {
        showToast('Please complete registration (₹499) to add grounds', 'warning');
        showOwnerRegistrationPayment();
        return;
    }
    
    // Get the modal element
    const modal = document.getElementById('add-ground-modal');
    if (!modal) {
        console.error('Add ground modal not found in DOM');
        showToast('Error: Modal not found. Please refresh the page.', 'error');
        return;
    }
    
    // Reset form
    const form = document.getElementById('add-ground-form');
    if (form) form.reset();
    
    // Reset image preview
    const previewGrid = document.getElementById('image-preview-grid');
    if (previewGrid) {
        previewGrid.innerHTML = `
            <div class="preview-placeholder">
                <i class="fas fa-camera"></i>
                <p>No photos selected yet</p>
                <span>Photos are optional (you can add them later)</span>
            </div>
        `;
        previewGrid.classList.remove('has-images');
    }
    
    // Reset upload progress
    const uploadProgress = document.getElementById('upload-progress');
    if (uploadProgress) uploadProgress.style.display = 'none';
    
    // Reset to step 1
    const steps = document.querySelectorAll('#add-ground-modal .form-step');
    const progressSteps = document.querySelectorAll('#add-ground-modal .progress-step');
    
    steps.forEach(step => step.classList.remove('active'));
    progressSteps.forEach(step => step.classList.remove('active', 'completed'));
    
    const firstStep = document.querySelector('#add-ground-modal .form-step[data-step="1"]');
    const firstProgress = document.querySelector('#add-ground-modal .progress-step[data-step="1"]');
    if (firstStep) firstStep.classList.add('active');
    if (firstProgress) firstProgress.classList.add('active');
    
    // Reset navigation buttons
    const prevBtn = document.getElementById('prev-step-btn');
    const nextBtn = document.getElementById('next-step-btn');
    const submitBtn = document.getElementById('submit-ground-btn');
    
    if (prevBtn) prevBtn.disabled = true;
    if (nextBtn) nextBtn.style.display = 'flex';
    if (submitBtn) submitBtn.style.display = 'none';
    
    // Reset price preview
    if (typeof updateEarningsPreview === 'function') {
        updateEarningsPreview(0);
    }
    
    // Reset price input
    const priceInput = document.getElementById('ground-price-input');
    if (priceInput) priceInput.value = '';
    
    // Reset selectedFiles
    if (typeof selectedFiles !== 'undefined') {
        selectedFiles = [];
    }
    
    // Reset current step
    if (typeof currentGroundStep !== 'undefined') {
        currentGroundStep = 1;
    }
    
    // Make sure submit button is properly connected
    const submitGroundBtn = document.getElementById('submit-ground-btn');
    if (submitGroundBtn) {
        // Remove any existing listeners
        const newSubmitBtn = submitGroundBtn.cloneNode(true);
        submitGroundBtn.parentNode.replaceChild(newSubmitBtn, submitGroundBtn);
        
        newSubmitBtn.addEventListener('click', function(e) {
            e.preventDefault();
            e.stopPropagation();
            console.log('Submit button clicked directly');
            // Manually trigger form submit
            const form = document.getElementById('add-ground-form');
            if (form) {
                const submitEvent = new Event('submit', { bubbles: true, cancelable: true });
                form.dispatchEvent(submitEvent);
            }
        });
    }
    
    // Open modal
    modal.classList.add('active');
    
    // Prevent body scroll
    document.body.style.overflow = 'hidden';
    document.body.style.position = 'fixed';
    document.body.style.width = '100%';
    
    // Also ensure the form submit handler is attached
    const addGroundForm = document.getElementById('add-ground-form');
    if (addGroundForm) {
        // Remove existing listeners to avoid duplicates
        const newForm = addGroundForm.cloneNode(true);
        addGroundForm.parentNode.replaceChild(newForm, addGroundForm);
        newForm.addEventListener('submit', handleAddGround);
    }
    
    console.log('Add ground modal opened successfully');
}

// ==================== INITIALIZE STEP NAVIGATION (FIXED) ====================

function initializeStepNavigation() {
    const prevBtn = document.getElementById('prev-step-btn');
    const nextBtn = document.getElementById('next-step-btn');
    const submitBtn = document.getElementById('submit-ground-btn');
    
    if (!prevBtn || !nextBtn || !submitBtn) return;
    
    // Remove all 'required' attributes from hidden steps initially
    function updateRequiredAttributes(currentStep) {
        const allSteps = document.querySelectorAll('.form-step');
        allSteps.forEach((step, index) => {
            const stepNum = index + 1;
            const inputs = step.querySelectorAll('input, select, textarea');
            
            inputs.forEach(input => {
                if (stepNum === currentStep) {
                    // Add required attribute back for current step
                    if (input.hasAttribute('data-required') || input.id === 'ground-name-input' || 
                        input.id === 'ground-sport-input' || input.id === 'ground-price-input') {
                        input.setAttribute('required', 'required');
                    }
                } else {
                    // Remove required attribute from hidden steps
                    input.removeAttribute('required');
                    // Store that it was required
                    if (input.hasAttribute('required') || input.id === 'ground-name-input' || 
                        input.id === 'ground-sport-input' || input.id === 'ground-price-input') {
                        input.setAttribute('data-required', 'true');
                    }
                }
            });
        });
    }
    
function updateStep(step) {
    // Hide all form steps
    document.querySelectorAll('.form-step').forEach(s => s.classList.remove('active'));
    document.querySelectorAll('.progress-step').forEach(s => s.classList.remove('active', 'completed'));
    
    // Show current step
    const currentStepEl = document.querySelector(`.form-step[data-step="${step}"]`);
    const currentProgressEl = document.querySelector(`.progress-step[data-step="${step}"]`);
    if (currentStepEl) currentStepEl.classList.add('active');
    if (currentProgressEl) currentProgressEl.classList.add('active');
    
    // Mark completed steps
    for (let i = 1; i < step; i++) {
        const completedStep = document.querySelector(`.progress-step[data-step="${i}"]`);
        if (completedStep) completedStep.classList.add('completed');
    }
    
    // Update required attributes
    updateRequiredAttributes(step);
    
    // Update navigation buttons
    const prevBtn = document.getElementById('prev-step-btn');
    const nextBtn = document.getElementById('next-step-btn');
    const submitBtn = document.getElementById('submit-ground-btn');
    
    if (prevBtn) prevBtn.disabled = (step === 1);
    
    // CRITICAL FIX: Show submit button on last step
    if (step === totalGroundSteps) {
        if (nextBtn) nextBtn.style.display = 'none';
        if (submitBtn) {
            submitBtn.style.display = 'flex';
            submitBtn.disabled = false;
            console.log('Submit button should now be visible');
        }
    } else {
        if (nextBtn) nextBtn.style.display = 'flex';
        if (submitBtn) submitBtn.style.display = 'none';
    }
    
    currentGroundStep = step;
}
    
    // Clone and replace buttons to remove existing listeners
    const newPrevBtn = prevBtn.cloneNode(true);
    const newNextBtn = nextBtn.cloneNode(true);
    prevBtn.parentNode.replaceChild(newPrevBtn, prevBtn);
    nextBtn.parentNode.replaceChild(newNextBtn, nextBtn);
    
    newPrevBtn.addEventListener('click', () => {
        if (currentGroundStep > 1) {
            updateStep(currentGroundStep - 1);
        }
    });
    
    newNextBtn.addEventListener('click', () => {
        if (validateStep(currentGroundStep)) {
            if (currentGroundStep < totalGroundSteps) {
                updateStep(currentGroundStep + 1);
            }
        }
    });
    
    // Progress step click handlers
    document.querySelectorAll('.progress-step').forEach(step => {
        const newStep = step.cloneNode(true);
        step.parentNode.replaceChild(newStep, step);
        
        newStep.addEventListener('click', () => {
            const stepNum = parseInt(newStep.dataset.step);
            if (stepNum < currentGroundStep) {
                updateStep(stepNum);
            }
        });
    });
    
    // Initialize required attributes
    updateRequiredAttributes(1);
}
    
// ==================== VALIDATE STEP (FIXED) ====================

function validateStep(step) {
    if (step === 1) {
        const groundName = document.getElementById('ground-name-input')?.value.trim();
        const sportType = document.getElementById('ground-sport-input')?.value;
        
        if (!groundName) {
            showToast('Please enter ground name', 'error');
            document.getElementById('ground-name-input')?.focus();
            return false;
        }
        if (groundName.length < 2) {
            showToast('Ground name must be at least 2 characters', 'error');
            return false;
        }
        if (!sportType) {
            showToast('Please select sport type', 'error');
            document.getElementById('ground-sport-input')?.focus();
            return false;
        }
        return true;
    }
    
    if (step === 2) {
        const priceInput = document.getElementById('ground-price-input');
        const price = parseFloat(priceInput?.value);
        
        if (!priceInput?.value) {
            showToast('Please select a price per hour', 'error');
            return false;
        }
        
        const ALLOWED_PRICES = [99, 199, 299, 499, 799, 999, 1299, 1999, 2499];
        if (isNaN(price) || !ALLOWED_PRICES.includes(price)) {
            showToast('Please select a valid price from the options', 'error');
            return false;
        }
        
        return true;
    }
    
    // Step 3 validation - images are optional
    if (step === 3) {
        // No validation needed - images are optional
        return true;
    }
    
    return true;
}

// ==================== RESET ADD GROUND MODAL ====================
function resetAddGroundModal() {
    const form = document.getElementById('add-ground-form');
    if (form) form.reset();
    
    selectedFiles = [];
    
    const fileInput = document.getElementById('ground-images');
    if (fileInput) fileInput.value = '';
    
    const previewGrid = document.getElementById('image-preview-grid');
    if (previewGrid) {
        previewGrid.innerHTML = `
            <div class="preview-placeholder">
                <i class="fas fa-camera"></i>
                <p>No photos selected yet</p>
                <span>Photos are optional (you can add them later)</span>
            </div>
        `;
        previewGrid.classList.remove('has-images');
    }
    
    const uploadProgress = document.getElementById('upload-progress');
    if (uploadProgress) uploadProgress.style.display = 'none';
    
    const steps = document.querySelectorAll('.form-step');
    const progressSteps = document.querySelectorAll('.progress-step');
    
    steps.forEach(step => step.classList.remove('active'));
    progressSteps.forEach(step => step.classList.remove('active', 'completed'));
    
    const firstStep = document.querySelector('.form-step[data-step="1"]');
    const firstProgress = document.querySelector('.progress-step[data-step="1"]');
    if (firstStep) firstStep.classList.add('active');
    if (firstProgress) firstProgress.classList.add('active');
    
    const prevBtn = document.getElementById('prev-step-btn');
    const nextBtn = document.getElementById('next-step-btn');
    const submitBtn = document.getElementById('submit-ground-btn');
    
    if (prevBtn) prevBtn.disabled = true;
    if (nextBtn) nextBtn.style.display = 'flex';
    if (submitBtn) submitBtn.style.display = 'none';
    
    currentGroundStep = 1;
    
    updateEarningsPreview(0);
    
    const priceInput = document.getElementById('ground-price-input');
    if (priceInput) priceInput.value = '';
}
