// Add global image error handling
document.addEventListener('DOMContentLoaded', function() {
    // Handle all images with placeholder.com
    const images = document.querySelectorAll('img[src*="via.placeholder.com"], img[src*="placeholder.com"]');
    
    images.forEach(img => {
        img.onerror = function() {
            const type = this.id.includes('profile') || this.id.includes('header-profile') ? 'profile' : 'default';
            handleImageError(this, type);
        };
        
        // Also set a background color
        img.style.backgroundColor = 'var(--gray-200)';
    });
    
    // Use MutationObserver for dynamically added images
    const observer = new MutationObserver(function(mutations) {
        mutations.forEach(function(mutation) {
            mutation.addedNodes.forEach(function(node) {
                if (node.nodeName === 'IMG') {
                    if (node.src && node.src.includes('placeholder.com')) {
                        node.onerror = function() {
                            const type = this.id.includes('profile') ? 'profile' : 'default';
                            handleImageError(this, type);
                        };
                        node.style.backgroundColor = 'var(--gray-200)';
                    }
                }
                if (node.querySelectorAll) {
                    const imgs = node.querySelectorAll('img[src*="placeholder.com"]');
                    imgs.forEach(img => {
                        img.onerror = function() {
                            const type = this.id.includes('profile') ? 'profile' : 'default';
                            handleImageError(this, type);
                        };
                        img.style.backgroundColor = 'var(--gray-200)';
                    });
                }
            });
        });
    });
    
    observer.observe(document.body, { childList: true, subtree: true });
});
