                            <i class="fas ${statusIcon === 'verified' ? 'fa-check' : statusIcon === 'pending' ? 'fa-hourglass-half' : statusIcon === 'rejected' ? 'fa-exclamation-triangle' : 'fa-info-circle'}"></i>
