// Submit Electricity Bill for Verification
async function submitElectricityBill(e) {
    e.preventDefault();
    
    const billFile = document.getElementById('electricity-bill').files[0];
    
    if (!billFile) {
        showToast('Please select your electricity bill', 'error');
        return;
    }
    
    showLoading('Uploading document...');
    
    // Show progress bar
    const progressContainer = document.getElementById('electricity-upload-progress');
    const progressFill = document.getElementById('electricity-upload-progress-fill');
    const uploadStatus = document.getElementById('electricity-upload-status');
    
    if (progressContainer) progressContainer.style.display = 'block';
    if (progressFill) progressFill.style.width = '0%';
    if (uploadStatus) uploadStatus.textContent = 'Uploading electricity bill...';
    
    try {
        // Upload file to Cloudinary
        let billUrl;
        try {
            billUrl = await uploadVerificationDocument(billFile, 'electricity_bill');
        } catch (error) {
            throw new Error('Failed to upload electricity bill: ' + error.message);
        }
        
        if (progressFill) progressFill.style.width = '100%';
        
        const documentId = generateId('DOC');
        
        // Create document verification record
        const documentData = {
            documentId: documentId,
            ownerId: currentUser.uid,
            ownerName: currentUser.ownerName || currentUser.name,
            ownerEmail: currentUser.email,
            documentType: DOCUMENT_TYPES.ELECTRICITY_BILL,
            documentUrl: billUrl,
            status: DOCUMENT_STATUS.PENDING,
            submittedAt: firebase.firestore.FieldValue.serverTimestamp(),
            createdAt: firebase.firestore.FieldValue.serverTimestamp()
        };
        
        await db.collection(COLLECTIONS.DOCUMENT_VERIFICATIONS).add(documentData);
        
        // Update owner document verification status
        await db.collection(COLLECTIONS.OWNERS).doc(currentUser.uid).update({
            documentVerified: false,
            documentStatus: DOCUMENT_STATUS.PENDING,
            documentSubmittedAt: firebase.firestore.FieldValue.serverTimestamp(),
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });
        
        hideLoading();
        if (progressContainer) progressContainer.style.display = 'none';
        showToast('Electricity bill submitted for verification! You will be notified once approved.', 'success');
        
        // Refresh the verification page
        loadOwnerDashboard('verification');
        
    } catch (error) {
        hideLoading();
        if (progressContainer) progressContainer.style.display = 'none';
        console.error('Error submitting electricity bill:', error);
        showToast('Error submitting document: ' + error.message, 'error');
    }
}

// Function to resubmit electricity bill
function showResubmitElectricityBill() {
    // Scroll to the upload section and focus
    const billCard = document.getElementById('electricity-bill-card');
    if (billCard) {
        billCard.scrollIntoView({ behavior: 'smooth', block: 'center' });
        billCard.style.border = '2px solid var(--primary)';
        setTimeout(() => {
            billCard.style.border = '';
        }, 2000);
    }
    
    // Create or show resubmit form
    let modal = document.getElementById('resubmit-electricity-modal');
    
    if (!modal) {
        const modalHtml = `
            <div id="resubmit-electricity-modal" class="modal">
                <div class="modal-content" style="max-width: 450px;">
                    <div class="modal-header">
                        <h3><i class="fas fa-file-invoice"></i> Resubmit Electricity Bill</h3>
                        <button class="close-btn" id="close-resubmit-modal">&times;</button>
                    </div>
                    <div class="modal-body">
                        <div class="info-note" style="margin-bottom: var(--space-lg);">
                            <i class="fas fa-info-circle"></i>
                            Please upload a clear, readable electricity bill in the owner's name from the last 3 months.
                        </div>
                        <form id="resubmit-electricity-form">
                            <div class="document-card" id="resubmit-bill-card">
                                <div class="document-icon">
                                    <i class="fas fa-file-invoice"></i>
                                </div>
                                <div class="document-name">Electricity Bill (Address Proof)</div>
                                <div class="document-requirement">Required - JPEG, PNG or PDF (Max 5MB)</div>
                                <div class="document-status pending" id="resubmit-bill-status">
                                    <i class="fas fa-clock"></i> No file selected
                                </div>
                                <div class="file-name" id="resubmit-bill-filename"></div>
                                <input type="file" id="resubmit-electricity-bill" class="document-input" accept="image/jpeg,image/png,image/jpg,application/pdf" required>
                            </div>
                            <div id="resubmit-upload-progress" class="upload-progress" style="display: none;">
                                <div class="progress-bar-wrapper">
                                    <div class="progress-bar-fill" id="resubmit-upload-progress-fill"></div>
                                </div>
                                <span id="resubmit-upload-status">Uploading document...</span>
                            </div>
                            <button type="submit" class="verification-submit-btn" style="margin-top: var(--space-xl);">
                                <i class="fas fa-paper-plane"></i> Resubmit for Verification
                            </button>
                        </form>
                    </div>
                </div>
            </div>
        `;
        document.body.insertAdjacentHTML('beforeend', modalHtml);
        
        document.getElementById('close-resubmit-modal').addEventListener('click', () => {
            closeModal('resubmit-electricity-modal');
        });
        
        document.getElementById('resubmit-electricity-form').addEventListener('submit', handleResubmitElectricityBill);
        
        // Add file input handler
        const resubmitInput = document.getElementById('resubmit-electricity-bill');
        if (resubmitInput) {
            resubmitInput.addEventListener('change', function() {
                const statusSpan = document.getElementById('resubmit-bill-status');
                const filenameSpan = document.getElementById('resubmit-bill-filename');
                const card = document.getElementById('resubmit-bill-card');
                
                if (this.files && this.files[0]) {
                    const file = this.files[0];
                    const fileSizeMB = file.size / 1024 / 1024;
                    
                    if (fileSizeMB > 5) {
                        showToast('File size must be less than 5MB', 'error');
                        this.value = '';
                        statusSpan.innerHTML = '<i class="fas fa-times-circle"></i> File too large';
                        statusSpan.className = 'document-status error';
                        return;
                    }
                    
                    if (filenameSpan) filenameSpan.textContent = file.name.length > 30 ? file.name.substring(0, 27) + '...' : file.name;
                    statusSpan.innerHTML = `<i class="fas fa-check-circle"></i> File selected: ${file.name.substring(0, 25)}${file.name.length > 25 ? '...' : ''}`;
                    statusSpan.className = 'document-status uploaded';
                    card.classList.add('uploaded');
                } else {
                    statusSpan.innerHTML = '<i class="fas fa-clock"></i> No file selected';
                    statusSpan.className = 'document-status pending';
                    card.classList.remove('uploaded');
                    if (filenameSpan) filenameSpan.textContent = '';
                }
            });
        }
    }
    
    document.getElementById('resubmit-electricity-modal').classList.add('active');
}

