// ==================== SLOT MANAGEMENT ====================

async function manageSlots(groundId, groundName) {
    showLoading('Loading slots...');
    
    try {
        const today = new Date().toISOString().split('T')[0];
        const sevenDaysLater = new Date();
        sevenDaysLater.setDate(sevenDaysLater.getDate() + 7);
        
        // Create slot management modal if it doesn't exist
        let modal = document.getElementById('slot-management-modal');
        if (!modal) {
            const modalHtml = `
                <div id="slot-management-modal" class="modal">
                    <div class="modal-content modal-lg slot-management-modal">
                        <div class="modal-header">
                            <div class="modal-header-left">
                                <div class="modal-icon">
                                    <i class="fas fa-clock"></i>
                                </div>
                                <div>
                                    <h3>Manage Slots</h3>
                                    <p class="modal-subtitle" id="slot-ground-name">Loading...</p>
                                </div>
                            </div>
                            <button class="close-btn" id="close-slot-management-modal">
                                <i class="fas fa-times"></i>
                            </button>
                        </div>
                        <div class="modal-body">
                            <div id="slot-management-content"></div>
                        </div>
                    </div>
                </div>
            `;
            document.body.insertAdjacentHTML('beforeend', modalHtml);
            
            // Add close button listener safely
            const closeBtn = document.getElementById('close-slot-management-modal');
            if (closeBtn) {
                closeBtn.addEventListener('click', () => {
                    closeModal('slot-management-modal');
                });
            }
        }
        
        // Update ground name - check if element exists first
        const groundNameElement = document.getElementById('slot-ground-name');
        if (groundNameElement) {
            groundNameElement.textContent = groundName;
        }
        
        // Load slots for the next 7 days
        await loadSlotsForDays(groundId, today, sevenDaysLater);
        
        // Get modal and add active class
        modal = document.getElementById('slot-management-modal');
        if (modal) {
            modal.classList.add('active');
        }
        
        hideLoading();
        
    } catch (error) {
        hideLoading();
        console.error('Error managing slots:', error);
        showToast('Error loading slots: ' + error.message, 'error');
    }
}

/**
 * Load slots for multiple days
 */
async function loadSlotsForDays(groundId, startDate, endDate) {
    const container = document.getElementById('slot-management-content');
    if (!container) return;
    
    try {
        // Get all slots for this ground
        const slotsSnapshot = await db.collection(COLLECTIONS.SLOTS)
            .where('groundId', '==', groundId)
            .get();
        
        // Create a map of slot statuses by date and time
        const slotStatusMap = {};
        slotsSnapshot.forEach(doc => {
            const slot = doc.data();
            const key = `${slot.date}_${slot.startTime}-${slot.endTime}`;
            slotStatusMap[key] = {
                status: slot.status,
                id: doc.id
            };
        });
        
        const defaultSlots = [
            '06:00-07:00', '07:00-08:00', '08:00-09:00',
            '09:00-10:00', '10:00-11:00', '11:00-12:00',
            '12:00-13:00', '13:00-14:00', '14:00-15:00',
            '15:00-16:00', '16:00-17:00', '17:00-18:00',
            '18:00-19:00', '19:00-20:00', '20:00-21:00',
            '21:00-22:00', '22:00-23:00'
        ];
        
        // Build HTML for date selector and slots
        let html = `
            <div class="slot-management-header">
                <div class="date-navigation">
                    <button class="date-nav-btn" id="prev-week-btn">
                        <i class="fas fa-chevron-left"></i>
                    </button>
                    <div class="date-range" id="date-range-display"></div>
                    <button class="date-nav-btn" id="next-week-btn">
                        <i class="fas fa-chevron-right"></i>
                    </button>
                </div>
                <div class="slot-bulk-actions">
                    <button class="bulk-action-btn open-all" id="bulk-open-all">
                        <i class="fas fa-unlock-alt"></i> Open All
                    </button>
                    <button class="bulk-action-btn close-all" id="bulk-close-all">
                        <i class="fas fa-lock"></i> Close All
                    </button>
                    <button class="bulk-action-btn reset" id="bulk-reset">
                        <i class="fas fa-undo-alt"></i> Reset
                    </button>
                </div>
            </div>
            <div id="slots-week-view" class="slots-week-view"></div>
        `;
        
        container.innerHTML = html;
        
        // Initialize date picker
        let currentDate = new Date(startDate);
        const weekDays = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
        
        function updateWeekView() {
            const weekStart = new Date(currentDate);
            weekStart.setDate(weekStart.getDate() - weekStart.getDay() + 1); // Start from Monday
            const weekEnd = new Date(weekStart);
            weekEnd.setDate(weekStart.getDate() + 6);
            
            const dateRangeDisplay = document.getElementById('date-range-display');
            if (dateRangeDisplay) {
                const startStr = weekStart.toLocaleDateString('en-IN', { day: 'numeric', month: 'short' });
                const endStr = weekEnd.toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' });
                dateRangeDisplay.textContent = `${startStr} - ${endStr}`;
            }
            
            // Build week view table
            let weekHtml = `
                <div class="slots-week-table">
                    <div class="slots-week-header">
                        <div class="time-column">Time</div>
            `;
            
            for (let i = 0; i < 7; i++) {
                const date = new Date(weekStart);
                date.setDate(weekStart.getDate() + i);
                const dateStr = date.toISOString().split('T')[0];
                const dayName = weekDays[i];
                const dayNum = date.getDate();
                const isToday = dateStr === new Date().toISOString().split('T')[0];
                
                weekHtml += `
                    <div class="day-column ${isToday ? 'today' : ''}" data-date="${dateStr}">
                        <div class="day-name">${dayName}</div>
                        <div class="day-date">${dayNum}</div>
                    </div>
                `;
            }
            
            weekHtml += `</div><div class="slots-week-body">`;
            
            // Add rows for each time slot
            for (const slot of defaultSlots) {
                weekHtml += `
                    <div class="slot-row">
                        <div class="time-column">${slot}</div>
                `;
                
                for (let i = 0; i < 7; i++) {
                    const date = new Date(weekStart);
                    date.setDate(weekStart.getDate() + i);
                    const dateStr = date.toISOString().split('T')[0];
                    const key = `${dateStr}_${slot}`;
                    const slotData = slotStatusMap[key] || { status: 'available', id: null };
                    const statusClass = slotData.status;
                    const statusText = slotData.status === 'available' ? 'Available' : 
                                      slotData.status === 'closed' ? 'Closed' : 
                                      slotData.status === 'booked' ? 'Booked' : 'Pending';
                    
                    const isDisabled = slotData.status === 'booked' || slotData.status === 'pending';
                    
                    weekHtml += `
                        <div class="slot-cell ${statusClass}" 
                             data-ground-id="${groundId}"
                             data-date="${dateStr}"
                             data-slot="${slot}"
                             data-slot-id="${slotData.id || ''}"
                             data-start="${slot.split('-')[0]}"
                             data-end="${slot.split('-')[1]}">
                            <div class="slot-status ${statusClass}">
                                <span class="slot-time">${slot}</span>
                                <span class="slot-badge ${statusClass}">${statusText}</span>
                            </div>
                            ${!isDisabled ? `
                                <div class="slot-actions">
                                    <button class="slot-action available" data-action="available">✓ Available</button>
                                    <button class="slot-action closed" data-action="closed">✗ Closed</button>
                                </div>
                            ` : `
                                <div class="slot-disabled-message">
                                    <i class="fas fa-ban"></i> ${statusText}
                                </div>
                            `}
                        </div>
                    `;
                }
                
                weekHtml += `</div>`;
            }
            
            weekHtml += `</div></div>`;
            
            const weekView = document.getElementById('slots-week-view');
            if (weekView) {
                weekView.innerHTML = weekHtml;
                attachSlotActionHandlers(groundId);
            }
        }
        
        updateWeekView();
        
        // Add navigation handlers
        // Inside loadSlotsForDays function, update the navigation handlers section:

// Add navigation handlers with null checks
const prevWeekBtn = document.getElementById('prev-week-btn');
const nextWeekBtn = document.getElementById('next-week-btn');

if (prevWeekBtn) {
    const newPrev = prevWeekBtn.cloneNode(true);
    prevWeekBtn.parentNode.replaceChild(newPrev, prevWeekBtn);
    newPrev.addEventListener('click', () => {
        currentDate.setDate(currentDate.getDate() - 7);
        updateWeekView();
    });
}

if (nextWeekBtn) {
    const newNext = nextWeekBtn.cloneNode(true);
    nextWeekBtn.parentNode.replaceChild(newNext, nextWeekBtn);
    newNext.addEventListener('click', () => {
        currentDate.setDate(currentDate.getDate() + 7);
        updateWeekView();
    });
}
        
        // Add bulk action handlers
        // Add bulk action handlers with null checks
const bulkOpenAll = document.getElementById('bulk-open-all');
const bulkCloseAll = document.getElementById('bulk-close-all');
const bulkReset = document.getElementById('bulk-reset');

if (bulkOpenAll) {
    const newOpen = bulkOpenAll.cloneNode(true);
    bulkOpenAll.parentNode.replaceChild(newOpen, bulkOpenAll);
    newOpen.addEventListener('click', () => bulkUpdateSlots(groundId, 'available'));
}

if (bulkCloseAll) {
    const newClose = bulkCloseAll.cloneNode(true);
    bulkCloseAll.parentNode.replaceChild(newClose, bulkCloseAll);
    newClose.addEventListener('click', () => bulkUpdateSlots(groundId, 'closed'));
}

if (bulkReset) {
    const newReset = bulkReset.cloneNode(true);
    bulkReset.parentNode.replaceChild(newReset, bulkReset);
    newReset.addEventListener('click', () => bulkUpdateSlots(groundId, 'available'));
}
        
    } catch (error) {
        console.error('Error loading slots for days:', error);
        container.innerHTML = `<p class="text-center">Error loading slots: ${error.message}</p>`;
    }
}

/**
 * Attach handlers to slot action buttons
 */
function attachSlotActionHandlers(groundId) {
    document.querySelectorAll('.slot-cell .slot-action').forEach(btn => {
        const newBtn = btn.cloneNode(true);
        btn.parentNode.replaceChild(newBtn, btn);
        
        newBtn.addEventListener('click', async (e) => { 
            e.stopPropagation();
            const action = newBtn.dataset.action;
            const slotCell = newBtn.closest('.slot-cell');
            const date = slotCell.dataset.date;
            const slot = slotCell.dataset.slot;
            const slotId = slotCell.dataset.slotId;
            const startTime = slotCell.dataset.start;
            const endTime = slotCell.dataset.end;
            
            await updateSlotStatus(slotId, groundId, date, startTime, endTime, action);
        });
    });
}

/**
 * Update a single slot status
 */
async function updateSlotStatus(slotId, groundId, date, startTime, endTime, status) {
    showLoading('Updating slot...');
    
    try {
        if (slotId && slotId !== '') {
            // Update existing slot
            await db.collection(COLLECTIONS.SLOTS).doc(slotId).update({
                status: status,
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            });
        } else {
            // Create new slot
            await db.collection(COLLECTIONS.SLOTS).add({
                groundId: groundId,
                date: date,
                startTime: startTime,
                endTime: endTime,
                status: status,
                createdAt: firebase.firestore.FieldValue.serverTimestamp(),
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            });
        }
        
        hideLoading();
        showToast(`Slot ${status === 'available' ? 'opened' : 'closed'} successfully`, 'success');
        
        // Refresh the slot view
        const modal = document.getElementById('slot-management-modal');
        if (modal && modal.classList.contains('active')) {
            const groundName = document.getElementById('slot-ground-name').textContent;
            await manageSlots(groundId, groundName);
        }
        
    } catch (error) {
        hideLoading();
        console.error('Error updating slot:', error);
        showToast('Error updating slot: ' + error.message, 'error');
    }
}

/**
 * Bulk update slots for a ground
 */
async function bulkUpdateSlots(groundId, status) {
    const actionText = status === 'available' ? 'open all slots' : 'close all slots';
    const confirmed = confirm(`Are you sure you want to ${actionText} for the current week?`);
    if (!confirmed) return;
    
    showLoading(`Updating ${actionText}...`);
    
    try {
        // Get all slots for this ground
        const slotsSnapshot = await db.collection(COLLECTIONS.SLOTS)
            .where('groundId', '==', groundId)
            .get();
        
        const batch = db.batch();
        
        // Update existing slots
        slotsSnapshot.forEach(doc => {
            const slot = doc.data();
            // Only update if not booked or pending
            if (slot.status !== 'booked' && slot.status !== 'pending') {
                batch.update(doc.ref, {
                    status: status,
                    updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                });
            }
        });
        
        await batch.commit();
        
        hideLoading();
        showToast(`Successfully ${actionText.replace('all', '')} for current week`, 'success');
        
        // Refresh the slot view
        const groundName = document.getElementById('slot-ground-name').textContent;
        await manageSlots(groundId, groundName);
        
    } catch (error) {
        hideLoading();
        console.error('Error in bulk update:', error);
        showToast('Error updating slots: ' + error.message, 'error');
    }
}

async function closeAllSlots(groundId, date) {
    if (!confirm('Are you sure you want to close all slots for this day?')) return;
    
    showLoading('Closing slots...');
    
    try {
        const slots = [
            '06:00-07:00', '07:00-08:00', '08:00-09:00',
            '16:00-17:00', '17:00-18:00', '18:00-19:00',
            '19:00-20:00', '20:00-21:00', '21:00-22:00'
        ];
        
        const batch = db.batch();
        
        for (const slot of slots) {
            const [start, end] = slot.split('-');
            const snapshot = await db.collection(COLLECTIONS.SLOTS)
                .where('groundId', '==', groundId)
                .where('date', '==', date)
                .where('startTime', '==', start)
                .where('endTime', '==', end)
                .get();
            
            if (snapshot.empty) {
                const newSlotRef = db.collection(COLLECTIONS.SLOTS).doc();
                batch.set(newSlotRef, {
                    groundId,
                    date,
                    startTime: start,
                    endTime: end,
                    status: SLOT_STATUS.CLOSED,
                    createdAt: firebase.firestore.FieldValue.serverTimestamp(),
                    updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                });
            } else {
                batch.update(snapshot.docs[0].ref, {
                    status: SLOT_STATUS.CLOSED,
                    updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                });
            }
        }
        
        await batch.commit();
        
        hideLoading();
        showToast('All slots closed');
        manageSlots(groundId, '');
    } catch (error) {
        hideLoading();
        showToast(error.message, 'error');
    }
}

