// ==================== FIXED EDIT PROFILE MODAL INITIALIZATION ====================

function initializeEditProfileModal() {
    console.log('Initializing edit profile modal...');
    
    // Get modal elements
    const modal = document.getElementById('edit-profile-modal');
    const closeBtn = document.getElementById('close-edit-profile-modal');
    const editProfileForm = document.getElementById('edit-profile-form');
    const editProfileBtn = document.getElementById('edit-profile-btn');
    
    // If modal doesn't exist, create it
    if (!modal) {
        console.log('Edit profile modal not found, creating...');
        createEditProfileModal();
        // Re-get references after creation
        const newModal = document.getElementById('edit-profile-modal');
        if (newModal) {
            attachModalEventListeners(newModal);
        }
    } else {
        attachModalEventListeners(modal);
    }
    
    // Ensure edit profile button has click handler
    if (editProfileBtn) {
        // Remove existing listeners by cloning
        const newBtn = editProfileBtn.cloneNode(true);
        editProfileBtn.parentNode.replaceChild(newBtn, editProfileBtn);
        
        newBtn.addEventListener('click', function(e) {
            e.preventDefault();
            e.stopPropagation();
            console.log('Edit profile button clicked');
            editProfile();
        });
        console.log('Edit profile button handler attached');
    } else {
        console.log('Edit profile button not found in DOM');
    }
}

function attachModalEventListeners(modal) {
    const closeBtn = document.getElementById('close-edit-profile-modal');
    const editProfileForm = document.getElementById('edit-profile-form');
    
    // Close button handler - FIXED
    if (closeBtn) {
        // Remove existing listeners by cloning
        const newCloseBtn = closeBtn.cloneNode(true);
        closeBtn.parentNode.replaceChild(newCloseBtn, closeBtn);
        
        newCloseBtn.addEventListener('click', function(e) {
            e.preventDefault();
            e.stopPropagation();
            console.log('Close button clicked');
            modal.classList.remove('active');
            restoreBodyScroll();
        });
    } else {
        console.log('Close button not found');
    }
    
    // Form submit handler
    if (editProfileForm) {
        const newForm = editProfileForm.cloneNode(true);
        editProfileForm.parentNode.replaceChild(newForm, editProfileForm);
        newForm.addEventListener('submit', handleEditProfile);
    }
    
    // Close on backdrop click (clicking outside the modal)
    modal.addEventListener('click', function(e) {
        if (e.target === modal) {
            console.log('Backdrop clicked - closing modal');
            modal.classList.remove('active');
            restoreBodyScroll();
        }
    });
    
    // Also handle Escape key
    document.addEventListener('keydown', function escapeHandler(e) {
        if (e.key === 'Escape' && modal.classList.contains('active')) {
            console.log('Escape key pressed - closing modal');
            modal.classList.remove('active');
            restoreBodyScroll();
            document.removeEventListener('keydown', escapeHandler);
        }
    });
}

function createEditProfileModal() {
    // Check if modal already exists
    if (document.getElementById('edit-profile-modal')) {
        return;
    }
    
    const modalHtml = `
        <div id="edit-profile-modal" class="modal">
            <div class="modal-content" style="max-width: 400px;">
                <div class="modal-header">
                    <h3><i class="fas fa-user-edit"></i> Edit Profile</h3>
                    <button type="button" class="close-btn" id="close-edit-profile-modal">
                        <i class="fas fa-times"></i>
                    </button>
                </div>
                <div class="modal-body">
                    <form id="edit-profile-form">
                        <div class="input-group floating" style="margin-bottom: var(--space-xl);">
                            <input type="text" id="edit-name" required placeholder=" ">
                            <label>Full Name</label>
                            <i class="fas fa-user input-icon"></i>
                        </div>
                        
                        <div class="input-group floating" style="margin-bottom: var(--space-xl);">
                            <input type="tel" id="edit-phone" required placeholder=" " maxlength="10">
                            <label>Phone Number</label>
                            <i class="fas fa-phone input-icon"></i>
                        </div>
                        
                        <div class="input-group floating" style="margin-bottom: var(--space-xl);">
                            <input type="email" id="edit-email" disabled placeholder=" ">
                            <label>Email Address (Cannot be changed)</label>
                            <i class="fas fa-envelope input-icon"></i>
                        </div>
                        
                        <button type="submit" class="auth-btn" style="margin-top: var(--space-lg);">
                            <i class="fas fa-save"></i> Save Changes
                        </button>
                    </form>
                </div>
            </div>
        </div>
    `;
    
    document.body.insertAdjacentHTML('beforeend', modalHtml);
    console.log('Edit profile modal created');
}

