// ==================== FIX ADD GROUND FORM SUBMISSION ====================

function fixAddGroundFormSubmission() {
    console.log('Fixing add ground form submission...');
    
    const addGroundForm = document.getElementById('add-ground-form');
    const submitBtn = document.getElementById('submit-ground-btn');
    
    if (!addGroundForm) {
        console.error('Add ground form not found');
        return;
    }
    
    // Remove any existing submit listeners by cloning
    const newForm = addGroundForm.cloneNode(true);
    addGroundForm.parentNode.replaceChild(newForm, addGroundForm);
    
    // Add new submit listener
    newForm.addEventListener('submit', async function(e) {
        e.preventDefault();
        e.stopPropagation();
        console.log('Add ground form submitted!');
        
        // Manually call handleAddGround
        await handleAddGround(e);
    });
    
    // Also attach click handler directly to submit button as fallback
    const newSubmitBtn = document.getElementById('submit-ground-btn');
    if (newSubmitBtn) {
        const clonedBtn = newSubmitBtn.cloneNode(true);
        newSubmitBtn.parentNode.replaceChild(clonedBtn, newSubmitBtn);
        
        clonedBtn.addEventListener('click', async function(e) {
            e.preventDefault();
            e.stopPropagation();
            console.log('Submit button clicked directly');
            
            // Manually trigger form submit
            const form = document.getElementById('add-ground-form');
            if (form) {
                const submitEvent = new Event('submit', { bubbles: true, cancelable: true });
                form.dispatchEvent(submitEvent);
            }
        });
    }
    
    console.log('Add ground form handlers attached');
}

// Call this function when the page loads and when modal opens
document.addEventListener('DOMContentLoaded', function() {
    fixAddGroundFormSubmission();
});

