// ==================== ADMIN PAYMENT TOGGLE UI ====================

async function loadPaymentToggleControl(container) {
    const isPaymentRequired = await isOwnerRegistrationPaymentRequired();
    const paymentAmount = await getOwnerRegistrationAmount();
    
    const html = `
        <div class="payment-toggle-card" style="background: var(--white); border-radius: 20px; padding: 24px; margin-bottom: 24px; box-shadow: var(--shadow);">
            <div class="toggle-header" style="display: flex; align-items: center; gap: 16px; margin-bottom: 20px;">
                <div class="toggle-icon" style="width: 50px; height: 50px; background: linear-gradient(135deg, var(--primary), var(--primary-dark)); border-radius: 15px; display: flex; align-items: center; justify-content: center;">
                    <i class="fas fa-rupee-sign" style="color: white; font-size: 1.5rem;"></i>
                </div>
                <div>
                    <h3 style="margin: 0; font-size: 1.2rem;">Owner Registration Fee Control</h3>
                    <p style="margin: 4px 0 0; font-size: 12px; color: var(--gray-500);">Enable/disable ₹${paymentAmount} registration fee for owners</p>
                </div>
            </div>
            
            <div class="toggle-status" style="background: ${isPaymentRequired ? '#fee2e2' : '#dcfce7'}; border-radius: 12px; padding: 16px; margin-bottom: 20px;">
                <div style="display: flex; align-items: center; justify-content: space-between; flex-wrap: wrap; gap: 12px;">
                    <div>
                        <span style="font-size: 14px; font-weight: 500;">Current Status:</span>
                        <span style="font-size: 18px; font-weight: 700; margin-left: 8px; color: ${isPaymentRequired ? 'var(--danger)' : 'var(--success)'};">
                            ${isPaymentRequired ? 'PAYMENT REQUIRED' : 'FREE REGISTRATION'}
                        </span>
                    </div>
                    <div class="toggle-switch" style="position: relative; display: inline-block; width: 60px; height: 34px;">
                        <input type="checkbox" id="payment-toggle-switch" ${isPaymentRequired ? 'checked' : ''} style="opacity: 0; width: 0; height: 0;">
                        <span class="toggle-slider" style="position: absolute; cursor: pointer; top: 0; left: 0; right: 0; bottom: 0; background-color: ${isPaymentRequired ? 'var(--primary)' : '#ccc'}; transition: .4s; border-radius: 34px;"></span>
                        <span class="toggle-slider:before" style="position: absolute; content: ''; height: 26px; width: 26px; left: 4px; bottom: 4px; background-color: white; transition: .4s; border-radius: 50%; transform: ${isPaymentRequired ? 'translateX(26px)' : 'translateX(0)'};"></span>
                    </div>
                </div>
            </div>
            
            <div class="amount-control" style="margin-bottom: 20px;">
                <label style="display: block; font-size: 13px; font-weight: 600; margin-bottom: 8px;">Registration Amount (₹)</label>
                <div style="display: flex; gap: 12px;">
                    <input type="number" id="payment-amount-input" value="${paymentAmount}" min="0" max="10000" step="100" style="flex: 1; padding: 12px; border: 2px solid var(--gray-200); border-radius: 12px; font-size: 16px;">
                    <button id="update-amount-btn" class="auth-btn" style="width: auto; margin: 0; padding: 12px 24px;">Update</button>
                </div>
                <p class="form-hint" style="margin-top: 8px;">Set to 0 to make registration completely free</p>
            </div>
            
            <div class="toggle-note" style="background: var(--primary-50); border-radius: 12px; padding: 12px; font-size: 12px; color: var(--gray-600);">
                <i class="fas fa-info-circle" style="margin-right: 8px;"></i>
                <strong>Note:</strong> When payment is OFF, owners can register and add grounds for free. When payment is ON, owners must pay ₹${paymentAmount} before adding grounds.
            </div>
        </div>
        
        <style>
            .toggle-switch input:checked + .toggle-slider {
                background-color: var(--primary);
            }
            .toggle-switch input:checked + .toggle-slider:before {
                transform: translateX(26px);
            }
        </style>
    `;
    
    if (container) {
        container.innerHTML = html;
        
        // Add event listeners
        const toggleSwitch = document.getElementById('payment-toggle-switch');
        const updateAmountBtn = document.getElementById('update-amount-btn');
        const amountInput = document.getElementById('payment-amount-input');
        
        if (toggleSwitch) {
            toggleSwitch.addEventListener('change', async (e) => {
                const isChecked = e.target.checked;
                const confirmed = confirm(`Are you sure you want to ${isChecked ? 'ENABLE' : 'DISABLE'} the registration payment requirement?\n\n${isChecked ? 'Owners will need to pay ₹' + (amountInput?.value || 499) + ' to add grounds.' : 'Owners can add grounds for FREE.'}`);
                
                if (confirmed) {
                    const amount = parseInt(amountInput?.value) || 499;
                    await toggleOwnerRegistrationPayment(isChecked, amount);
                    await loadPaymentToggleControl(container);
                } else {
                    toggleSwitch.checked = !isChecked;
                }
            });
        }
        
        if (updateAmountBtn && amountInput) {
            updateAmountBtn.addEventListener('click', async () => {
                const newAmount = parseInt(amountInput.value);
                if (isNaN(newAmount) || newAmount < 0) {
                    showToast('Please enter a valid amount', 'error');
                    return;
                }
                
                const currentRequired = await isOwnerRegistrationPaymentRequired();
                const confirmed = confirm(`Update registration amount to ₹${newAmount}?`);
                
                if (confirmed) {
                    await toggleOwnerRegistrationPayment(currentRequired, newAmount);
                    showToast(`Registration amount updated to ₹${newAmount}`, 'success');
                }
            });
        }
    }
}

// Add this to your admin dashboard tabs
function addPaymentToggleToAdminDashboard() {
    // Add a new tab for payment control
    const adminTabs = document.querySelector('.admin-tabs');
    if (adminTabs && !document.getElementById('admin-payment-toggle-tab')) {
        const newTab = document.createElement('button');
        newTab.className = 'tab-btn';
        newTab.id = 'admin-payment-toggle-tab';
        newTab.innerHTML = '<i class="fas fa-toggle-on"></i> Payment Control';
        adminTabs.appendChild(newTab);
        
        newTab.addEventListener('click', () => {
            loadAdminDashboard('payment-toggle');
        });
    }
}

// Add this to your loadAdminDashboard function (around line 3500)
async function loadAdminDashboard(tab) {
    const container = document.getElementById('admin-dashboard-content');
    if (!container) {
        console.error('Admin dashboard content container not found');
        return;
    }
    
    console.log(`Loading admin dashboard tab: ${tab}`);
    
    container.innerHTML = '<div class="loading-spinner"><div class="loader-spinner"></div></div>';
    
    try {
        if (tab === 'overview') {
            await loadAdminOverview(container);
        } else if (tab === 'owners') {
            await loadAdminOwners(container);
        } else if (tab === 'venues') {
            await loadAdminVenues(container);
        } else if (tab === 'bookings') {
            await loadAdminBookings(container);
        } else if (tab === 'tournaments') {
            await loadAdminTournaments(container);
        } else if (tab === 'payouts') {
            await loadAdminPayouts(container);
        } else if (tab === 'verification') {
            await loadAdminVerification(container);
        } else if (tab === 'reports') {
            await loadAdminReports(container);
        } else if (tab === 'document-verification') {
            await loadAdminDocumentVerification(container);
        } else if (tab === 'delete') {
            await loadAdminDeleteManagement(container);
        } else {
            container.innerHTML = '<p class="text-center">Tab not implemented yet</p>';
        }
    } catch (error) {
        console.error(`Error loading admin ${tab}:`, error);
        container.innerHTML = `<p class="text-center">Failed to load ${tab}</p>`;
    }
}

