async function approveDocumentVerification(requestId, ownerId) {
    if (!confirm('Approve this address verification? The owner will be able to list grounds after approval.')) return;
    
    showLoading('Approving address verification...');
    
    try {
        const requestDoc = await db.collection(COLLECTIONS.DOCUMENT_VERIFICATIONS).doc(requestId).get();
        
        if (!requestDoc.exists) {
            throw new Error('Document verification request not found');
        }
        
        const request = requestDoc.data();
        
        // Update document verification request
        await db.collection(COLLECTIONS.DOCUMENT_VERIFICATIONS).doc(requestId).update({
            status: DOCUMENT_STATUS.VERIFIED,
            approvedAt: firebase.firestore.FieldValue.serverTimestamp(),
            approvedBy: currentUser.uid,
            approvedByName: currentUser.name || currentUser.email,
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });
        
        // Update owner document
        await db.collection(COLLECTIONS.OWNERS).doc(ownerId).update({
            documentVerified: true,
            documentStatus: DOCUMENT_STATUS.VERIFIED,
            documentVerifiedAt: firebase.firestore.FieldValue.serverTimestamp(),
            documentVerifiedBy: currentUser.uid,
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });
        
        hideLoading();
        showToast('Address verification approved! Owner can now list grounds.', 'success');
        
        // Refresh the verification list
        if (document.getElementById('admin-dashboard-page').classList.contains('active')) {
            loadAdminDashboard('document-verification');
        } else if (document.getElementById('ceo-dashboard-page').classList.contains('active')) {
            loadCEODashboard('document-verification');
        }
        
    } catch (error) {
        hideLoading();
        console.error('Error approving document verification:', error);
        showToast('Error approving verification: ' + error.message, 'error');
    }
}

async function rejectDocumentVerification(requestId) {
    const reason = prompt('Please provide a reason for rejection (required):');
    
    if (!reason || reason.trim() === '') {
        showToast('Please provide a rejection reason', 'error');
        return;
    }
    
    if (!confirm('Reject this address verification request? The owner will need to resubmit.')) return;
    
    showLoading('Rejecting verification...');
    
    try {
        const requestDoc = await db.collection(COLLECTIONS.DOCUMENT_VERIFICATIONS).doc(requestId).get();
        
        if (!requestDoc.exists) {
            throw new Error('Document verification request not found');
        }
        
        const request = requestDoc.data();
        
        await db.collection(COLLECTIONS.DOCUMENT_VERIFICATIONS).doc(requestId).update({
            status: DOCUMENT_STATUS.REJECTED,
            rejectionReason: reason.trim(),
            rejectedAt: firebase.firestore.FieldValue.serverTimestamp(),
            rejectedBy: currentUser.uid,
            rejectedByName: currentUser.name || currentUser.email,
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });
        
        await db.collection(COLLECTIONS.OWNERS).doc(request.ownerId).update({
            documentVerified: false,
            documentStatus: DOCUMENT_STATUS.REJECTED,
            documentRejectionReason: reason.trim(),
            documentRejectedAt: firebase.firestore.FieldValue.serverTimestamp(),
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });
        
        hideLoading();
        showToast('Address verification request rejected', 'info');
        
        // Refresh the verification list
        if (document.getElementById('admin-dashboard-page').classList.contains('active')) {
            loadAdminDashboard('document-verification');
        } else if (document.getElementById('ceo-dashboard-page').classList.contains('active')) {
            loadCEODashboard('document-verification');
        }
        
    } catch (error) {
        hideLoading();
        console.error('Error rejecting document verification:', error);
        showToast('Error rejecting verification: ' + error.message, 'error');
    }
}


// Function to view documents in a modal
function viewDocument(documentUrl, documentName) {
    // Create modal to view document
    let modal = document.getElementById('document-viewer-modal');
    
    if (!modal) {
        const modalHtml = `
            <div id="document-viewer-modal" class="modal">
                <div class="modal-content document-viewer-content">
                    <div class="modal-header">
                        <h3><i class="fas fa-file-alt"></i> Document Viewer</h3>
                        <button class="close-btn" id="close-document-viewer-modal">&times;</button>
                    </div>
                    <div class="modal-body document-viewer-body">
                        <div class="document-viewer-container">
                            <iframe id="document-iframe" src="" frameborder="0"></iframe>
                            <div class="document-viewer-actions">
                                <a href="#" id="download-document-btn" class="download-doc-btn" target="_blank">
                                    <i class="fas fa-download"></i> Download
                                </a>
                                <button class="close-viewer-btn" onclick="closeModal('document-viewer-modal')">Close</button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        `;
        document.body.insertAdjacentHTML('beforeend', modalHtml);
        
        document.getElementById('close-document-viewer-modal').addEventListener('click', () => {
            closeModal('document-viewer-modal');
        });
    }
    
    // Update modal content
    const titleEl = document.querySelector('#document-viewer-modal .modal-header h3');
    if (titleEl) titleEl.innerHTML = `<i class="fas fa-file-alt"></i> ${escapeHtml(documentName)}`;
    
    const iframe = document.getElementById('document-iframe');
    if (iframe) {
        iframe.src = documentUrl;
    }
    
    const downloadBtn = document.getElementById('download-document-btn');
    if (downloadBtn) {
        downloadBtn.href = documentUrl;
        downloadBtn.download = `${documentName.replace(/\s/g, '_')}.jpg`;
    }
    
    modal = document.getElementById('document-viewer-modal');
    modal.classList.add('active');
}

// Replace the approveVerification function

async function approveVerification(requestId, ownerId) {
    if (!confirm('Approve this verification request? This will mark the owner as verified and show a verified badge on their listings.')) return;
    
    showLoading('Approving verification...');
    
    try {
        // Get the verification request
        const requestDoc = await db.collection(COLLECTIONS.VERIFICATION_REQUESTS).doc(requestId).get();
        
        if (!requestDoc.exists) {
            throw new Error('Verification request not found');
        }
        
        const request = requestDoc.data();
        
        // Update verification request
        await db.collection(COLLECTIONS.VERIFICATION_REQUESTS).doc(requestId).update({
            status: VERIFICATION_STATUS.VERIFIED,
            approvedAt: firebase.firestore.FieldValue.serverTimestamp(),
            approvedBy: currentUser.uid,
            approvedByName: currentUser.name || currentUser.email,
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });
        
        // Update owner document
        await db.collection(COLLECTIONS.OWNERS).doc(ownerId).update({
            verificationStatus: VERIFICATION_STATUS.VERIFIED,
            isVerified: true,
            verifiedAt: firebase.firestore.FieldValue.serverTimestamp(),
            verifiedBy: currentUser.uid,
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });
        
        // Update all grounds owned by this owner to show as verified
        const groundsSnapshot = await db.collection(COLLECTIONS.GROUNDS)
            .where('ownerId', '==', ownerId)
            .get();
        
        const batch = db.batch();
        groundsSnapshot.forEach(doc => {
            batch.update(doc.ref, {
                isVerified: true,
                verifiedAt: firebase.firestore.FieldValue.serverTimestamp(),
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            });
        });
        
        // Also update venue if exists
        const venueSnapshot = await db.collection(COLLECTIONS.VENUES)
            .where('ownerId', '==', ownerId)
            .get();
        
        venueSnapshot.forEach(doc => {
            batch.update(doc.ref, {
                isVerified: true,
                verifiedAt: firebase.firestore.FieldValue.serverTimestamp(),
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            });
        });
        
        await batch.commit();
        
        hideLoading();
        showToast('Owner verified successfully! Verified badge will appear on their listings.', 'success');
        
        // Refresh the verification list
        if (document.getElementById('admin-dashboard-page').classList.contains('active')) {
            loadAdminDashboard('verification');
        } else if (document.getElementById('ceo-dashboard-page').classList.contains('active')) {
            loadCEODashboard('verification');
        }
        
    } catch (error) {
        hideLoading();
        console.error('Error approving verification:', error);
        showToast('Error approving verification: ' + error.message, 'error');
    }
}

