// ==================== ADMIN PAYMENT TOGGLE UI ====================

async function loadPaymentToggleControl(container) {
    const isPaymentRequired = await isOwnerRegistrationPaymentRequired();
    const paymentAmount = await getOwnerRegistrationAmount();
    
    const html = `
        <div class="payment-toggle-card" style="background: var(--white); border-radius: 20px; padding: 24px; margin-bottom: 24px; box-shadow: var(--shadow);">
            <div class="toggle-header" style="display: flex; align-items: center; gap: 16px; margin-bottom: 20px;">
                <div class="toggle-icon" style="width: 50px; height: 50px; background: linear-gradient(135deg, var(--primary), var(--primary-dark)); border-radius: 15px; display: flex; align-items: center; justify-content: center;">
                    <i class="fas fa-rupee-sign" style="color: white; font-size: 1.5rem;"></i>
                </div>
                <div>
                    <h3 style="margin: 0; font-size: 1.2rem;">Owner Registration Fee Control</h3>
                    <p style="margin: 4px 0 0; font-size: 12px; color: var(--gray-500);">Enable/disable ₹${paymentAmount} registration fee for owners</p>
                </div>
            </div>
            
            <div class="toggle-status" style="background: ${isPaymentRequired ? '#fee2e2' : '#dcfce7'}; border-radius: 12px; padding: 16px; margin-bottom: 20px;">
                <div style="display: flex; align-items: center; justify-content: space-between; flex-wrap: wrap; gap: 12px;">
                    <div>
                        <span style="font-size: 14px; font-weight: 500;">Current Status:</span>
                        <span style="font-size: 18px; font-weight: 700; margin-left: 8px; color: ${isPaymentRequired ? 'var(--danger)' : 'var(--success)'};">
                            ${isPaymentRequired ? 'PAYMENT REQUIRED' : 'FREE REGISTRATION'}
                        </span>
                    </div>
                    <div class="toggle-switch" style="position: relative; display: inline-block; width: 60px; height: 34px;">
                        <input type="checkbox" id="payment-toggle-switch" ${isPaymentRequired ? 'checked' : ''} style="opacity: 0; width: 0; height: 0;">
                        <span class="toggle-slider" style="position: absolute; cursor: pointer; top: 0; left: 0; right: 0; bottom: 0; background-color: ${isPaymentRequired ? 'var(--primary)' : '#ccc'}; transition: .4s; border-radius: 34px;"></span>
                        <span class="toggle-slider:before" style="position: absolute; content: ''; height: 26px; width: 26px; left: 4px; bottom: 4px; background-color: white; transition: .4s; border-radius: 50%; transform: ${isPaymentRequired ? 'translateX(26px)' : 'translateX(0)'};"></span>
                    </div>
                </div>
            </div>
            
            <div class="amount-control" style="margin-bottom: 20px;">
                <label style="display: block; font-size: 13px; font-weight: 600; margin-bottom: 8px;">Registration Amount (₹)</label>
                <div style="display: flex; gap: 12px;">
                    <input type="number" id="payment-amount-input" value="${paymentAmount}" min="0" max="10000" step="100" style="flex: 1; padding: 12px; border: 2px solid var(--gray-200); border-radius: 12px; font-size: 16px;">
                    <button id="update-amount-btn" class="auth-btn" style="width: auto; margin: 0; padding: 12px 24px;">Update</button>
                </div>
                <p class="form-hint" style="margin-top: 8px;">Set to 0 to make registration completely free</p>
            </div>
            
            <div class="toggle-note" style="background: var(--primary-50); border-radius: 12px; padding: 12px; font-size: 12px; color: var(--gray-600);">
                <i class="fas fa-info-circle" style="margin-right: 8px;"></i>
                <strong>Note:</strong> When payment is OFF, owners can register and add grounds for free. When payment is ON, owners must pay ₹${paymentAmount} before adding grounds.
            </div>
        </div>
        
        <style>
            .toggle-switch input:checked + .toggle-slider {
                background-color: var(--primary);
            }
            .toggle-switch input:checked + .toggle-slider:before {
                transform: translateX(26px);
            }
        </style>
    `;
    
    if (container) {
        container.innerHTML = html;
        
        // Add event listeners
        const toggleSwitch = document.getElementById('payment-toggle-switch');
        const updateAmountBtn = document.getElementById('update-amount-btn');
        const amountInput = document.getElementById('payment-amount-input');
        
        if (toggleSwitch) {
            toggleSwitch.addEventListener('change', async (e) => {
                const isChecked = e.target.checked;
                const confirmed = confirm(`Are you sure you want to ${isChecked ? 'ENABLE' : 'DISABLE'} the registration payment requirement?\n\n${isChecked ? 'Owners will need to pay ₹' + (amountInput?.value || 499) + ' to add grounds.' : 'Owners can add grounds for FREE.'}`);
                
                if (confirmed) {
                    const amount = parseInt(amountInput?.value) || 499;
                    await toggleOwnerRegistrationPayment(isChecked, amount);
                    await loadPaymentToggleControl(container);
                } else {
                    toggleSwitch.checked = !isChecked;
                }
            });
        }
        
        if (updateAmountBtn && amountInput) {
            updateAmountBtn.addEventListener('click', async () => {
                const newAmount = parseInt(amountInput.value);
                if (isNaN(newAmount) || newAmount < 0) {
                    showToast('Please enter a valid amount', 'error');
                    return;
                }
                
                const currentRequired = await isOwnerRegistrationPaymentRequired();
                const confirmed = confirm(`Update registration amount to ₹${newAmount}?`);
                
                if (confirmed) {
                    await toggleOwnerRegistrationPayment(currentRequired, newAmount);
                    showToast(`Registration amount updated to ₹${newAmount}`, 'success');
                }
            });
        }
    }
}

// Add this to your admin dashboard tabs
function addPaymentToggleToAdminDashboard() {
    // Add a new tab for payment control
    const adminTabs = document.querySelector('.admin-tabs');
    if (adminTabs && !document.getElementById('admin-payment-toggle-tab')) {
        const newTab = document.createElement('button');
        newTab.className = 'tab-btn';
        newTab.id = 'admin-payment-toggle-tab';
        newTab.innerHTML = '<i class="fas fa-toggle-on"></i> Payment Control';
        adminTabs.appendChild(newTab);
        
        newTab.addEventListener('click', () => {
            loadAdminDashboard('payment-toggle');
        });
    }
}

function showCEODashboard() {
    if (!currentUser || (currentUser.role !== 'ceo' && currentUser.email !== CEO_EMAIL)) {
        showToast('Access denied', 'error');
        return;
    }
    
    document.getElementById('ceo-id-display').innerHTML = `
        <i class="fas fa-crown"></i> CEO Dashboard
    `;
    
    loadCEODashboard('overview');
    showPage('ceo-dashboard-page');
}

// Add this to your loadCEODashboard function

async function loadCEODashboard(tab) {
    const container = document.getElementById('ceo-dashboard-content');
    
    // Update active tab styling
    document.querySelectorAll('.ceo-tabs .tab-btn').forEach(btn => {
        btn.classList.remove('active');
    });
    document.getElementById(`ceo-${tab}-tab`).classList.add('active');
    
    container.innerHTML = '<div class="loading-spinner"><div class="loader-spinner"></div></div>';
    
    if (tab === 'overview') {
        await loadCEOOverview(container);
    } else if (tab === 'admins') {
        await loadAdminsList(container);
    } else if (tab === 'owners') {
        await loadOwnersList(container);
    } else if (tab === 'bookings') {
        await loadAllBookings(container);
    } else if (tab === 'tournaments') {
        await loadTournamentsList(container);
    } else if (tab === 'payouts') {
        await loadPayoutsList(container);
    } else if (tab === 'analytics') {
        await loadAnalytics(container);
    } else if (tab === 'referrals') {
        await loadReferrals(container);
    } else if (tab === 'verification') {
        await loadCEOVerification(container);
    }
}

// Add the CEO verification function
async function loadCEOVerification(container) {
    showLoading('Loading verification requests...');
    
    try {
        const snapshot = await db.collection(COLLECTIONS.VERIFICATION_REQUESTS)
            .orderBy('submittedAt', 'desc')
            .get();
        
        const pendingRequests = [];
        const approvedRequests = [];
        const rejectedRequests = [];
        
        snapshot.forEach(doc => {
            const request = doc.data();
            if (request.status === 'pending') {
                pendingRequests.push({ id: doc.id, ...request });
            } else if (request.status === 'approved' || request.status === 'verified') {
                approvedRequests.push({ id: doc.id, ...request });
            } else if (request.status === 'rejected') {
                rejectedRequests.push({ id: doc.id, ...request });
            }
        });
        
        let html = `
            <div class="verification-stats-grid">
                <div class="verification-stat-card pending">
                    <div class="stat-icon"><i class="fas fa-clock"></i></div>
                    <div class="stat-info">
                        <span class="stat-number">${pendingRequests.length}</span>
                        <span class="stat-label">Pending Requests</span>
                    </div>
                </div>
                <div class="verification-stat-card approved">
                    <div class="stat-icon"><i class="fas fa-check-circle"></i></div>
                    <div class="stat-info">
                        <span class="stat-number">${approvedRequests.length}</span>
                        <span class="stat-label">Verified Owners</span>
                    </div>
                </div>
                <div class="verification-stat-card rejected">
                    <div class="stat-icon"><i class="fas fa-times-circle"></i></div>
                    <div class="stat-info">
                        <span class="stat-number">${rejectedRequests.length}</span>
                        <span class="stat-label">Rejected Requests</span>
                    </div>
                </div>
            </div>
        `;
        
        // Pending Requests Section
        html += `
            <div class="verification-section">
                <div class="section-header-enhanced">
                    <h4><i class="fas fa-hourglass-half"></i> Pending Verification Requests</h4>
                    <span class="badge">${pendingRequests.length} Pending</span>
                </div>
                <div class="verification-requests-list">
        `;
        
        if (pendingRequests.length === 0) {
            html += `<div class="empty-state"><p>No pending verification requests</p></div>`;
        } else {
            for (const request of pendingRequests) {
                const submittedDate = request.submittedAt ? new Date(request.submittedAt.toDate()) : new Date();
                const formattedDate = submittedDate.toLocaleDateString('en-IN', {
                    day: 'numeric',
                    month: 'long',
                    year: 'numeric'
                });
                
                html += `
                    <div class="verification-request-card-enhanced">
                        <div class="request-header-enhanced">
                            <div class="owner-info">
                                <div class="owner-avatar">
                                    <i class="fas fa-user-circle"></i>
                                </div>
                                <div>
                                    <h4>${escapeHtml(request.ownerName || 'Owner')}</h4>
                                    <p>${escapeHtml(request.ownerEmail || 'No email')}</p>
                                    <p><i class="fas fa-phone"></i> ${escapeHtml(request.ownerPhone || 'No phone')}</p>
                                </div>
                            </div>
                            <div class="request-date-badge">
                                <i class="fas fa-calendar"></i> ${formattedDate}
                            </div>
                        </div>
                        
                        <div class="document-previews-grid">
                            <div class="doc-preview" onclick="viewDocument('${request.aadhaarFront}', 'Aadhaar Card Front')">
                                <i class="fas fa-id-card"></i>
                                <span>Aadhaar Front</span>
                                <button class="view-btn">View</button>
                            </div>
                            <div class="doc-preview" onclick="viewDocument('${request.aadhaarBack}', 'Aadhaar Card Back')">
                                <i class="fas fa-id-card"></i>
                                <span>Aadhaar Back</span>
                                <button class="view-btn">View</button>
                            </div>
                            <div class="doc-preview" onclick="viewDocument('${request.panImage}', 'PAN Card')">
                                <i class="fas fa-file-invoice"></i>
                                <span>PAN Card</span>
                                <button class="view-btn">View</button>
                            </div>
                        </div>
                        
                        <div class="owner-details-mini">
                            <div class="detail-item">
                                <i class="fas fa-id-card"></i>
                                <span>Aadhaar: ${maskAadhaar(request.aadhaarNumber)}</span>
                            </div>
                            <div class="detail-item">
                                <i class="fas fa-file-invoice"></i>
                                <span>PAN: ${maskPan(request.panNumber)}</span>
                            </div>
                        </div>
                        
                        <div class="verification-actions-enhanced">
                            <button class="approve-btn" onclick="approveVerification('${request.id}', '${request.ownerId}')">
                                <i class="fas fa-check-circle"></i> Approve & Verify
                            </button>
                            <button class="reject-btn" onclick="rejectVerification('${request.id}')">
                                <i class="fas fa-times-circle"></i> Reject
                            </button>
                        </div>
                    </div>
                `;
            }
        }
        
        html += `</div></div>`;
        
        // Approved/Verified Section
        if (approvedRequests.length > 0) {
            html += `
                <div class="verification-section">
                    <div class="section-header-enhanced">
                        <h4><i class="fas fa-check-circle"></i> Verified Owners</h4>
                        <span class="badge success">${approvedRequests.length} Verified</span>
                    </div>
                    <div class="verified-owners-list">
            `;
            
            for (const request of approvedRequests) {
                const approvedDate = request.approvedAt ? new Date(request.approvedAt.toDate()) : null;
                const approvedByName = request.approvedByName || 'Admin';
                
                html += `
                    <div class="verified-owner-card">
                        <div class="verified-icon">
                            <i class="fas fa-check-circle"></i>
                        </div>
                        <div class="verified-info">
                            <h4>${escapeHtml(request.ownerName)}</h4>
                            <p>${escapeHtml(request.ownerEmail)}</p>
                            <p><i class="fas fa-phone"></i> ${escapeHtml(request.ownerPhone || 'No phone')}</p>
                            ${approvedDate ? `<p><i class="fas fa-calendar-check"></i> Verified on ${approvedDate.toLocaleDateString()}</p>` : ''}
                            <p><i class="fas fa-user-check"></i> Verified by: ${escapeHtml(approvedByName)}</p>
                        </div>
                    </div>
                `;
            }
            
            html += `</div></div>`;
        }
        
        container.innerHTML = html;
        hideLoading();
        
    } catch (error) {
        hideLoading();
        console.error('Error loading CEO verification:', error);
        container.innerHTML = '<p class="text-center">Failed to load verification requests</p>';
    }
}

async function loadCEOOverview(container) {
    showLoading('Loading analytics...');
    
    try {
        const today = new Date().toISOString().split('T')[0];
        const lastWeek = new Date();
        lastWeek.setDate(lastWeek.getDate() - 7);
        const weekStart = lastWeek.toISOString().split('T')[0];
        const lastMonth = new Date();
        lastMonth.setMonth(lastMonth.getMonth() - 1);
        const monthStart = lastMonth.toISOString().split('T')[0];
        
        const adminsSnapshot = await db.collection(COLLECTIONS.ADMINS).get();
        const ownersSnapshot = await db.collection(COLLECTIONS.OWNERS).get();
        const usersSnapshot = await db.collection(COLLECTIONS.USERS).get();
        const venuesSnapshot = await db.collection(COLLECTIONS.VENUES).get();
        const groundsSnapshot = await db.collection(COLLECTIONS.GROUNDS).get();
        const tournamentsSnapshot = await db.collection(COLLECTIONS.TOURNAMENTS).get();
        const bookingsSnapshot = await db.collection(COLLECTIONS.BOOKINGS).get();
        const referralsSnapshot = await db.collection(COLLECTIONS.REFERRALS).get();
        
        let totalRevenue = 0;
        let todayRevenue = 0;
        let weekRevenue = 0;
        let monthRevenue = 0;
        
        bookingsSnapshot.forEach(doc => {
            const booking = doc.data();
            const bookingDate = booking.date;
            const commission = booking.commission || 0;
            
            totalRevenue += commission;
            
            if (bookingDate === today) {
                todayRevenue += commission;
            }
            
            if (bookingDate >= weekStart) {
                weekRevenue += commission;
            }
            
            if (bookingDate >= monthStart) {
                monthRevenue += commission;
            }
        });
        
        const plotOwners = ownersSnapshot.docs.filter(doc => doc.data().ownerType === 'plot_owner').length;
        const venueOwners = ownersSnapshot.docs.filter(doc => doc.data().ownerType === 'venue_owner').length;
        
        container.innerHTML = `
            <div class="stats-grid">
                <div class="stat-card">
                    <div class="stat-value">${adminsSnapshot.size}</div>
                    <div class="stat-label">Admins</div>
                </div>
                <div class="stat-card">
                    <div class="stat-value">${ownersSnapshot.size}</div>
                    <div class="stat-label">Total Owners</div>
                </div>
                <div class="stat-card">
                    <div class="stat-value">${usersSnapshot.size}</div>
                    <div class="stat-label">Users</div>
                </div>
                <div class="stat-card">
                    <div class="stat-value">${venuesSnapshot.size}</div>
                    <div class="stat-label">Venues</div>
                </div>
            </div>
            
            <div class="stats-grid">
                <div class="stat-card">
                    <div class="stat-value">${groundsSnapshot.size}</div>
                    <div class="stat-label">Grounds</div>
                </div>
                <div class="stat-card">
                    <div class="stat-value">${tournamentsSnapshot.size}</div>
                    <div class="stat-label">Tournaments</div>
                </div>
                <div class="stat-card">
                    <div class="stat-value">${bookingsSnapshot.size}</div>
                    <div class="stat-label">Total Bookings</div>
                </div>
                <div class="stat-card">
                    <div class="stat-value">${referralsSnapshot.size}</div>
                    <div class="stat-label">Referrals</div>
                </div>
            </div>
            
            <div class="revenue-card">
                <h4>Platform Revenue (10% Commission)</h4>
                <div class="revenue-amount">${formatCurrency(totalRevenue)}</div>
                <div class="stats-grid" style="margin-top: var(--space-md);">
                    <div class="stat-card" style="background: var(--gradient-warning);">
                        <div class="stat-value">${formatCurrency(todayRevenue)}</div>
                        <div class="stat-label">Today</div>
                    </div>
                    <div class="stat-card" style="background: var(--gradient-secondary);">
                        <div class="stat-value">${formatCurrency(weekRevenue)}</div>
                        <div class="stat-label">This Week</div>
                    </div>
                    <div class="stat-card" style="background: var(--gradient-accent);">
                        <div class="stat-value">${formatCurrency(monthRevenue)}</div>
                        <div class="stat-label">This Month</div>
                    </div>
                </div>
            </div>
            
            <div class="stats-grid">
                <div class="stat-card" style="background: var(--gradient-secondary);">
                    <div class="stat-value">${venueOwners}</div>
                    <div class="stat-label">Venue Owners</div>
                </div>
                <div class="stat-card" style="background: var(--gradient-warning);">
                    <div class="stat-value">${plotOwners}</div>
                    <div class="stat-label">Plot Owners</div>
                </div>
            </div>
        `;
        
        hideLoading();
    } catch (error) {
        hideLoading();
        console.error('Error loading analytics:', error);
        container.innerHTML = '<p class="text-center">Failed to load analytics</p>';
    }
}

async function loadReferrals(container) {
    showLoading('Loading referral data...');
    
    try {
        const referralsSnapshot = await db.collection(COLLECTIONS.REFERRALS)
            .orderBy('createdAt', 'desc')
            .limit(50)
            .get();
        
        let html = '<h3>Recent Referrals</h3>';
        
        if (referralsSnapshot.empty) {
            html += '<p class="text-center">No referrals yet</p>';
        } else {
            html += `
                <table class="report-table" style="width: 100%; border-collapse: collapse;">
                    <thead>
                        <tr style="background: var(--gray-100);">
                            <th style="padding: var(--space-md); text-align: left;">Referral Code</th>
                            <th style="padding: var(--space-md); text-align: left;">Referred By</th>
                            <th style="padding: var(--space-md); text-align: left;">Date</th>
                        </tr>
                    </thead>
                    <tbody>
            `;
            referralsSnapshot.forEach(doc => {
                const ref = doc.data();
                html += `
                    <tr style="border-bottom: 1px solid var(--gray-200);">
                        <td style="padding: var(--space-md);">${ref.code || 'N/A'}</td>
                        <td style="padding: var(--space-md);">${ref.referredBy || 'N/A'}</td>
                        <td style="padding: var(--space-md);">${ref.createdAt ? new Date(ref.createdAt.toDate()).toLocaleDateString() : 'N/A'}</td>
                    </tr>
                `;
            });
            html += '</tbody></table>';
        }
        
        // Add referral statistics
        const ownersWithReferrals = await db.collection(COLLECTIONS.OWNERS)
            .where('referralCount', '>', 0)
            .orderBy('referralCount', 'desc')
            .limit(10)
            .get();
        
        if (!ownersWithReferrals.empty) {
            html += '<h4 style="margin-top: var(--space-xl);">Top Referrers (Owners)</h4>';
            html += `
                <table class="report-table" style="width: 100%; border-collapse: collapse;">
                    <thead>
                        <tr style="background: var(--gray-100);">
                            <th style="padding: var(--space-md); text-align: left;">Owner Name</th>
                            <th style="padding: var(--space-md); text-align: left;">Referral Count</th>
                        </tr>
                    </thead>
                    <tbody>
            `;
            ownersWithReferrals.forEach(doc => {
                const owner = doc.data();
                html += `
                    <tr style="border-bottom: 1px solid var(--gray-200);">
                        <td style="padding: var(--space-md);">${owner.ownerName || owner.name || 'Unknown'}</td>
                        <td style="padding: var(--space-md);">${owner.referralCount || 0}</td>
                    </tr>
                `;
            });
            html += '</tbody></table>';
        }
        
        container.innerHTML = html;
        hideLoading();
        
    } catch (error) {
        hideLoading();
        console.error('Error loading referrals:', error);
        container.innerHTML = '<p class="text-center">Failed to load referrals</p>';
    }
}
