// ==================== TOGGLE VENUE VISIBILITY (ADMIN) ====================

/**
 * Toggle venue visibility (hide/show from users)
 * @param {string} venueId - The venue ID to toggle
 * @param {boolean} hide - True to hide, false to show
 */
async function toggleVenueVisibility(venueId, hide) {
    if (!currentUser || (currentUser.role !== 'admin' && currentUser.role !== 'ceo')) {
        showToast('Access denied. Admin privileges required.', 'error');
        return;
    }
    
    const action = hide ? 'hide' : 'show';
    const actionText = hide ? 'hidden from users' : 'visible to users';
    
    const confirmed = confirm(`Are you sure you want to ${action} this venue? It will be ${actionText}.`);
    if (!confirmed) return;
    
    showLoading(`${hide ? 'Hiding' : 'Showing'} venue...`);
    
    try {
        const venueRef = db.collection(COLLECTIONS.VENUES).doc(venueId);
        const venueDoc = await venueRef.get();
        
        if (!venueDoc.exists) {
            throw new Error('Venue not found');
        }
        
        // Update venue visibility
        await venueRef.update({
            hidden: hide,
            hiddenBy: currentUser.uid,
            hiddenByName: currentUser.name || currentUser.email,
            hiddenAt: hide ? firebase.firestore.FieldValue.serverTimestamp() : null,
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });
        
        // Also update all grounds under this venue
        const venue = venueDoc.data();
        const groundsSnapshot = await db.collection(COLLECTIONS.GROUNDS)
            .where('ownerId', '==', venue.ownerId)
            .get();
        
        const batch = db.batch();
        groundsSnapshot.forEach(doc => {
            batch.update(doc.ref, {
                hidden: hide,
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            });
        });
        
        await batch.commit();
        
        hideLoading();
        showToast(`Venue ${hide ? 'hidden' : 'shown'} successfully!`, 'success');
        
        // Refresh the current view
        if (document.getElementById('admin-dashboard-page').classList.contains('active')) {
            loadAdminDashboard('venues');
        } else if (document.getElementById('ceo-dashboard-page').classList.contains('active')) {
            loadCEODashboard('venues');
        }
        
    } catch (error) {
        hideLoading();
        console.error('Error toggling venue visibility:', error);
        showToast('Error updating venue: ' + error.message, 'error');
    }
}

// ==================== ADMIN DELETE GROUND FUNCTION ====================

/**
 * Admin function to delete a ground and all associated data
 * @param {string} groundId - The ground ID to delete
 * @param {string} groundName - The ground name for confirmation
 */
async function adminDeleteGround(groundId, groundName) {
    if (!currentUser || (currentUser.role !== 'admin' && currentUser.role !== 'ceo')) {
        showToast('Access denied. Admin privileges required.', 'error');
        return;
    }
    
    // Show confirmation modal
    const confirmed = await showAdminDeleteConfirmation(
        'Delete Ground',
        `Are you sure you want to delete "${groundName}"?`,
        'This action cannot be undone. All associated slots, bookings, and reviews will be permanently removed from the platform.'
    );
    
    if (!confirmed) return;
    
    showLoading('Deleting ground and associated data...');
    
    try {
        const groundRef = db.collection(COLLECTIONS.GROUNDS).doc(groundId);
        const groundDoc = await groundRef.get();
        
        if (!groundDoc.exists) {
            throw new Error('Ground not found');
        }
        
        const ground = groundDoc.data();
        const ownerId = ground.ownerId;
        
        // Use batch for all deletions
        const batch = db.batch();
        
        // 1. Delete all slots for this ground
        const slotsSnapshot = await db.collection(COLLECTIONS.SLOTS)
            .where('groundId', '==', groundId)
            .get();
        
        slotsSnapshot.forEach(slotDoc => {
            batch.delete(slotDoc.ref);
        });
        
        // 2. Delete all bookings for this ground
        const bookingsSnapshot = await db.collection(COLLECTIONS.BOOKINGS)
            .where('groundId', '==', groundId)
            .get();
        
        bookingsSnapshot.forEach(bookingDoc => {
            batch.delete(bookingDoc.ref);
        });
        
        // 3. Delete all reviews for this ground
        const reviewsSnapshot = await db.collection(COLLECTIONS.REVIEWS)
            .where('groundId', '==', groundId)
            .get();
        
        reviewsSnapshot.forEach(reviewDoc => {
            batch.delete(reviewDoc.ref);
        });
        
        // 4. Delete the ground itself
        batch.delete(groundRef);
        
        // 5. Update owner's grounds count
        if (ownerId) {
            const ownerRef = db.collection(COLLECTIONS.OWNERS).doc(ownerId);
            const ownerDoc = await ownerRef.get();
            if (ownerDoc.exists) {
                const currentGroundsCount = ownerDoc.data().groundsCount || 0;
                batch.update(ownerRef, {
                    groundsCount: Math.max(0, currentGroundsCount - 1),
                    updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                });
            }
        }
        
        // Commit all deletions
        await batch.commit();
        
        hideLoading();
        showToast(`Ground "${groundName}" and all associated data deleted successfully!`, 'success');
        
        // Log the deletion
        await logAdminAction('DELETE_GROUND', {
            groundId: groundId,
            groundName: groundName,
            ownerId: ownerId,
            slotsDeleted: slotsSnapshot.size,
            bookingsDeleted: bookingsSnapshot.size,
            reviewsDeleted: reviewsSnapshot.size
        });
        
        // Refresh the current view
        if (document.getElementById('admin-dashboard-page').classList.contains('active')) {
            loadAdminDashboard('delete');
        } else if (document.getElementById('ceo-dashboard-page').classList.contains('active')) {
            loadCEODashboard('delete');
        }
        
    } catch (error) {
        hideLoading();
        console.error('Error deleting ground:', error);
        showToast('Error deleting ground: ' + error.message, 'error');
    }
}

// ==================== ADMIN DELETE PLOT OWNER FUNCTION ====================

/**
 * Admin function to delete a plot owner and all their associated data
 * @param {string} ownerId - The owner ID to delete
 * @param {string} ownerName - The owner name for confirmation
 */
async function adminDeletePlotOwner(ownerId, ownerName) {
    if (!currentUser || (currentUser.role !== 'admin' && currentUser.role !== 'ceo')) {
        showToast('Access denied. Admin privileges required.', 'error');
        return;
    }
    
    // First, get all grounds for this owner to show in confirmation
    const groundsSnapshot = await db.collection(COLLECTIONS.GROUNDS)
        .where('ownerId', '==', ownerId)
        .get();
    
    const groundsCount = groundsSnapshot.size;
    const groundsList = groundsSnapshot.docs.map(doc => doc.data().groundName).join(', ');
    
    // Show confirmation modal with grounds info
    const confirmed = await showAdminDeleteConfirmation(
        'Delete Plot Owner',
        `Are you sure you want to delete "${ownerName}"?`,
        `This will permanently delete:\n\n` +
        `• ${groundsCount} ground(s): ${groundsList || 'None'}\n` +
        `• All slots for these grounds\n` +
        `• All bookings for these grounds\n` +
        `• All reviews for these grounds\n` +
        `• The owner account itself\n\n` +
        `This action cannot be undone!`
    );
    
    if (!confirmed) return;
    
    showLoading('Deleting plot owner and all associated data...');
    
    try {
        const ownerRef = db.collection(COLLECTIONS.OWNERS).doc(ownerId);
        const ownerDoc = await ownerRef.get();
        
        if (!ownerDoc.exists) {
            throw new Error('Plot owner not found');
        }
        
        const owner = ownerDoc.data();
        
        // Use batch for all deletions (Firestore has limit of 500 operations per batch)
        // We'll use multiple batches if needed
        let batch = db.batch();
        let operationCount = 0;
        let batches = [batch];
        
        function addToBatch(ref, operation) {
            if (operationCount >= 450) { // Leave room for other operations
                batch = db.batch();
                batches.push(batch);
                operationCount = 0;
            }
            if (operation === 'delete') {
                batch.delete(ref);
            } else if (operation === 'update') {
                // For update operations
            }
            operationCount++;
        }
        
        // 1. Process all grounds for this owner
        for (const doc of groundsSnapshot.docs) {
            const groundId = doc.id;
            const ground = doc.data();
            
            // Delete all slots for this ground
            const slotsSnapshot = await db.collection(COLLECTIONS.SLOTS)
                .where('groundId', '==', groundId)
                .get();
            
            slotsSnapshot.forEach(slotDoc => {
                addToBatch(slotDoc.ref, 'delete');
            });
            
            // Delete all bookings for this ground
            const bookingsSnapshot = await db.collection(COLLECTIONS.BOOKINGS)
                .where('groundId', '==', groundId)
                .get();
            
            bookingsSnapshot.forEach(bookingDoc => {
                addToBatch(bookingDoc.ref, 'delete');
            });
            
            // Delete all reviews for this ground
            const reviewsSnapshot = await db.collection(COLLECTIONS.REVIEWS)
                .where('groundId', '==', groundId)
                .get();
            
            reviewsSnapshot.forEach(reviewDoc => {
                addToBatch(reviewDoc.ref, 'delete');
            });
            
            // Delete the ground
            addToBatch(doc.ref, 'delete');
        }
        
        // 2. Delete all verification requests for this owner
        const verificationSnapshot = await db.collection(COLLECTIONS.VERIFICATION_REQUESTS)
            .where('ownerId', '==', ownerId)
            .get();
        
        verificationSnapshot.forEach(verificationDoc => {
            addToBatch(verificationDoc.ref, 'delete');
        });
        
        // 3. Delete all document verifications for this owner
        const docVerificationSnapshot = await db.collection(COLLECTIONS.DOCUMENT_VERIFICATIONS)
            .where('ownerId', '==', ownerId)
            .get();
        
        docVerificationSnapshot.forEach(docVerificationDoc => {
            addToBatch(docVerificationDoc.ref, 'delete');
        });
        
        // 4. Delete all payout requests for this owner
        const payoutRequestsSnapshot = await db.collection(COLLECTIONS.PAYOUT_REQUESTS)
            .where('ownerId', '==', ownerId)
            .get();
        
        payoutRequestsSnapshot.forEach(payoutDoc => {
            addToBatch(payoutDoc.ref, 'delete');
        });
        
        // 5. Delete the owner account
        addToBatch(ownerRef, 'delete');
        
        // Commit all batches
        for (const b of batches) {
            await b.commit();
        }
        
        hideLoading();
        showToast(`Plot owner "${ownerName}" and all ${groundsCount} ground(s) deleted successfully!`, 'success');
        
        // Log the deletion
        await logAdminAction('DELETE_PLOT_OWNER', {
            ownerId: ownerId,
            ownerName: ownerName,
            ownerEmail: owner.email,
            groundsDeleted: groundsCount,
            slotsDeleted: 0, // Would need to count
            bookingsDeleted: 0 // Would need to count
        });
        
        // Refresh the current view
        if (document.getElementById('admin-dashboard-page').classList.contains('active')) {
            loadAdminDashboard('delete');
        } else if (document.getElementById('ceo-dashboard-page').classList.contains('active')) {
            loadCEODashboard('delete');
        }
        
    } catch (error) {
        hideLoading();
        console.error('Error deleting plot owner:', error);
        showToast('Error deleting plot owner: ' + error.message, 'error');
    }
}

// ==================== ADMIN DELETE VENUE FUNCTION ====================

/**
 * Admin function to delete a venue and all associated data
 * @param {string} venueId - The venue ID to delete
 * @param {string} venueName - The venue name for confirmation
 */
async function adminDeleteVenue(venueId, venueName) {
    if (!currentUser || (currentUser.role !== 'admin' && currentUser.role !== 'ceo')) {
        showToast('Access denied. Admin privileges required.', 'error');
        return;
    }
    
    // First, get all grounds for this venue to show in confirmation
    const venueDoc = await db.collection(COLLECTIONS.VENUES).doc(venueId).get();
    if (!venueDoc.exists) {
        showToast('Venue not found', 'error');
        return;
    }
    
    const venue = venueDoc.data();
    const ownerId = venue.ownerId;
    
    const groundsSnapshot = await db.collection(COLLECTIONS.GROUNDS)
        .where('ownerId', '==', ownerId)
        .get();
    
    const groundsCount = groundsSnapshot.size;
    
    // Show confirmation modal
    const confirmed = await showAdminDeleteConfirmation(
        'Delete Venue',
        `Are you sure you want to delete "${venueName}"?`,
        `This will permanently delete:\n\n` +
        `• The venue "${venueName}"\n` +
        `• ${groundsCount} ground(s) under this venue\n` +
        `• All slots for these grounds\n` +
        `• All bookings for these grounds\n` +
        `• All reviews for these grounds\n\n` +
        `This action cannot be undone!`
    );
    
    if (!confirmed) return;
    
    showLoading('Deleting venue and associated data...');
    
    try {
        const venueRef = db.collection(COLLECTIONS.VENUES).doc(venueId);
        
        // Use batch for all deletions
        let batch = db.batch();
        let operationCount = 0;
        let batches = [batch];
        
        function addToBatch(ref, operation) {
            if (operationCount >= 450) {
                batch = db.batch();
                batches.push(batch);
                operationCount = 0;
            }
            if (operation === 'delete') {
                batch.delete(ref);
            }
            operationCount++;
        }
        
        // Process all grounds for this owner
        for (const doc of groundsSnapshot.docs) {
            const groundId = doc.id;
            
            // Delete slots
            const slotsSnapshot = await db.collection(COLLECTIONS.SLOTS)
                .where('groundId', '==', groundId)
                .get();
            slotsSnapshot.forEach(slotDoc => addToBatch(slotDoc.ref, 'delete'));
            
            // Delete bookings
            const bookingsSnapshot = await db.collection(COLLECTIONS.BOOKINGS)
                .where('groundId', '==', groundId)
                .get();
            bookingsSnapshot.forEach(bookingDoc => addToBatch(bookingDoc.ref, 'delete'));
            
            // Delete reviews
            const reviewsSnapshot = await db.collection(COLLECTIONS.REVIEWS)
                .where('groundId', '==', groundId)
                .get();
            reviewsSnapshot.forEach(reviewDoc => addToBatch(reviewDoc.ref, 'delete'));
            
            // Delete ground
            addToBatch(doc.ref, 'delete');
        }
        
        // Delete the venue
        addToBatch(venueRef, 'delete');
        
        // Update owner's grounds count to 0
        if (ownerId) {
            const ownerRef = db.collection(COLLECTIONS.OWNERS).doc(ownerId);
            addToBatch(ownerRef, 'update');
            // Need to do update separately since batch.update requires different handling
        }
        
        // Commit all batches
        for (const b of batches) {
            await b.commit();
        }
        
        // Update owner's grounds count separately if needed
        if (ownerId) {
            await db.collection(COLLECTIONS.OWNERS).doc(ownerId).update({
                groundsCount: 0,
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            });
        }
        
        hideLoading();
        showToast(`Venue "${venueName}" and all ${groundsCount} ground(s) deleted successfully!`, 'success');
        
        // Log the deletion
        await logAdminAction('DELETE_VENUE', {
            venueId: venueId,
            venueName: venueName,
            ownerId: ownerId,
            groundsDeleted: groundsCount
        });
        
        // Refresh the current view
        if (document.getElementById('admin-dashboard-page').classList.contains('active')) {
            loadAdminDashboard('delete');
        } else if (document.getElementById('ceo-dashboard-page').classList.contains('active')) {
            loadCEODashboard('delete');
        }
        
    } catch (error) {
        hideLoading();
        console.error('Error deleting venue:', error);
        showToast('Error deleting venue: ' + error.message, 'error');
    }
}

// ==================== ADMIN DELETE CONFIRMATION MODAL ====================

/**
 * Show confirmation modal for admin delete actions
 */
async function showAdminDeleteConfirmation(title, message, detail) {
    return new Promise((resolve) => {
        let modal = document.getElementById('admin-delete-confirmation-modal');
        
        if (!modal) {
            const modalHtml = `
                <div id="admin-delete-confirmation-modal" class="modal">
                    <div class="modal-content" style="max-width: 500px;">
                        <div class="modal-header" style="background: linear-gradient(135deg, #ef4444, #dc2626);">
                            <h3 style="color: white;"><i class="fas fa-exclamation-triangle"></i> ${title}</h3>
                            <button class="close-btn" id="close-admin-delete-modal" style="color: white;">&times;</button>
                        </div>
                        <div class="modal-body">
                            <div class="delete-confirmation-content">
                                <div class="warning-icon" style="font-size: 3rem; color: var(--danger); text-align: center; margin-bottom: var(--space-lg);">
                                    <i class="fas fa-trash-alt"></i>
                                </div>
                                <h4 class="confirmation-title" style="text-align: center; margin-bottom: var(--space-md); color: var(--gray-800);">${message}</h4>
                                <div class="confirmation-detail" style="background: var(--gray-50); padding: var(--space-lg); border-radius: var(--radius); margin-bottom: var(--space-xl); white-space: pre-line;">
                                    <p style="margin: 0; color: var(--gray-600); font-size: var(--font-sm);">${detail}</p>
                                </div>
                                <div class="confirmation-actions" style="display: flex; gap: var(--space-md);">
                                    <button class="confirmation-btn confirm delete" id="admin-confirm-delete" style="flex: 1; background: linear-gradient(135deg, #ef4444, #dc2626); color: white; padding: var(--space-md); border: none; border-radius: var(--radius); font-weight: 600; cursor: pointer;">
                                        <i class="fas fa-trash-alt"></i> Delete Permanently
                                    </button>
                                    <button class="confirmation-btn cancel" id="admin-cancel-delete" style="flex: 1; background: var(--gray-100); color: var(--gray-700); padding: var(--space-md); border: none; border-radius: var(--radius); font-weight: 600; cursor: pointer;">
                                        Cancel
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            `;
            document.body.insertAdjacentHTML('beforeend', modalHtml);
            
            document.getElementById('close-admin-delete-modal').addEventListener('click', () => {
                closeModal('admin-delete-confirmation-modal');
                resolve(false);
            });
            
            document.getElementById('admin-cancel-delete').addEventListener('click', () => {
                closeModal('admin-delete-confirmation-modal');
                resolve(false);
            });
        }
        
        // Update modal content with dynamic values
        const modalTitle = document.querySelector('#admin-delete-confirmation-modal .modal-header h3');
        const modalMessage = document.querySelector('#admin-delete-confirmation-modal .confirmation-title');
        const modalDetail = document.querySelector('#admin-delete-confirmation-modal .confirmation-detail p');
        
        if (modalTitle) modalTitle.innerHTML = `<i class="fas fa-exclamation-triangle"></i> ${title}`;
        if (modalMessage) modalMessage.textContent = message;
        if (modalDetail) modalDetail.textContent = detail;
        
        const modalEl = document.getElementById('admin-delete-confirmation-modal');
        modalEl.classList.add('active');
        
        // Add event listener for confirm button
        const confirmBtn = document.getElementById('admin-confirm-delete');
        const newConfirmBtn = confirmBtn.cloneNode(true);
        confirmBtn.parentNode.replaceChild(newConfirmBtn, confirmBtn);
        
        newConfirmBtn.addEventListener('click', () => {
            closeModal('admin-delete-confirmation-modal');
            resolve(true);
        });
        
        // Handle modal close via backdrop click
        modalEl.addEventListener('click', (e) => {
            if (e.target === modalEl) {
                closeModal('admin-delete-confirmation-modal');
                resolve(false);
            }
        });
    });
}

// ==================== LOG ADMIN ACTIONS ====================

/**
 * Log admin actions for audit trail
 */
async function logAdminAction(action, details) {
    try {
        const logEntry = {
            action: action,
            adminId: currentUser.uid,
            adminName: currentUser.name || currentUser.email,
            adminEmail: currentUser.email,
            timestamp: firebase.firestore.FieldValue.serverTimestamp(),
            details: details
        };
        
        // You can create an 'admin_logs' collection in Firestore
        await db.collection('admin_logs').add(logEntry);
        console.log(`Admin action logged: ${action}`);
    } catch (error) {
        console.error('Error logging admin action:', error);
        // Non-critical error, don't show to user
    }
}

