        const owner = ownerDoc.data();
        
        const venuesSnapshot = await db.collection(COLLECTIONS.VENUES)
            .where('ownerId', '==', ownerId)
            .get();
        
        const groundsSnapshot = await db.collection(COLLECTIONS.GROUNDS)
            .where('ownerId', '==', ownerId)
            .get();
        
