// ==================== CANCEL PENDING REGISTRATION (UNIFIED) ====================
async function cancelPendingRegistration(registrationId) {
    try {
        // Delete from Firestore pending collection
        const pendingRegQuery = await db.collection(COLLECTIONS.PENDING_TOURNAMENT_REGISTRATIONS)
            .where('registrationId', '==', registrationId)
            .where('userId', '==', currentUser.uid)
            .get();
        
        if (!pendingRegQuery.empty) {
            await pendingRegQuery.docs[0].ref.delete();
            console.log('Pending registration cancelled:', registrationId);
        }
        
        // Clear all session storage
        sessionStorage.removeItem('pendingTournamentRegistration');
        sessionStorage.removeItem('pendingTournamentPayment');
        sessionStorage.removeItem('currentPayUTransaction');
        
    } catch (error) {
        console.error('Error cancelling pending registration:', error);
    }
}
// ==================== GENERATE PAYTM ORDER ID ====================

function generatePaytmOrderId() {
    const timestamp = Date.now();
    const random = Math.floor(Math.random() * 1000000);
    const randomStr = random.toString().padStart(6, '0');
    return `BOOKMYGAME_${timestamp}_${randomStr}`;
}


async function cleanupExpiredPendingRegistrations() {
    try {
        const thirtyMinutesAgo = new Date(Date.now() - 30 * 60 * 1000);
        
        const expiredRegistrations = await db.collection(COLLECTIONS.PENDING_TOURNAMENT_REGISTRATIONS)
            .where('createdAt', '<=', thirtyMinutesAgo)
            .where('status', '==', 'pending')
            .get();
        
        const batch = db.batch();
        expiredRegistrations.forEach(doc => {
            batch.delete(doc.ref);
        });
        
        if (expiredRegistrations.size > 0) {
            await batch.commit();
            console.log(`Cleaned up ${expiredRegistrations.size} expired pending registrations`);
        }
        
    } catch (error) {
        console.error('Error cleaning up expired registrations:', error);
    }
}

// Run cleanup every hour
setInterval(cleanupExpiredPendingRegistrations, 60 * 60 * 1000);


