// Load referral data
async function loadReferralData() {
    if (!currentUser) return;
    
    try {
        // Get user's referral code
        const userRef = currentUser.role === 'user' ? COLLECTIONS.USERS : COLLECTIONS.OWNERS;
        const userDoc = await db.collection(userRef).doc(currentUser.uid).get();
        const userData = userDoc.data();
        
        const referralCode = userData.referralCode;
        
        // Get all referrals for this user
        const referralsSnapshot = await db.collection(COLLECTIONS.REFERRALS)
            .where('referredBy', '==', currentUser.uid)
            .get();
        
        const referrals = [];
        let completedCount = 0;
        let pendingCount = 0;
        
        referralsSnapshot.forEach(doc => {
            const ref = doc.data();
            referrals.push({
                id: doc.id,
                ...ref
            });
            if (ref.status === 'completed') {
                completedCount++;
            } else {
                pendingCount++;
            }
        });
        
        // Calculate earnings (₹50 per completed referral)
        const earnings = completedCount * 50;
        
        // Update UI elements
        const referralCountEl = document.getElementById('referral-count');
        const referralEarningsEl = document.getElementById('referral-earnings');
        const pendingReferralsEl = document.getElementById('pending-referrals');
        const inviteReferralCodeEl = document.getElementById('invite-referral-code');
        const historyCountEl = document.getElementById('history-count');
        
        if (referralCountEl) referralCountEl.textContent = completedCount;
        if (referralEarningsEl) referralEarningsEl.textContent = formatCurrency(earnings);
        if (pendingReferralsEl) pendingReferralsEl.textContent = pendingCount;
        if (inviteReferralCodeEl) inviteReferralCodeEl.textContent = referralCode;
        if (historyCountEl) historyCountEl.textContent = referrals.length;
        
        // Build referral history
        const historyList = document.getElementById('referral-history-list');
        if (historyList) {
            if (referrals.length === 0) {
                historyList.innerHTML = `
                    <div class="empty-history">
                        <i class="fas fa-user-plus"></i>
                        <p>No invites sent yet</p>
                        <span>Share your code to get started</span>
                    </div>
                `;
            } else {
                historyList.innerHTML = referrals.map(ref => {
                    const createdAt = ref.createdAt?.toDate() || new Date(ref.createdAt);
                    const formattedDate = createdAt.toLocaleDateString('en-IN', {
                        day: 'numeric',
                        month: 'short',
                        year: 'numeric'
                    });
                    
                    return `
                        <div class="history-item">
                            <div class="history-avatar">
                                <i class="fas fa-user-plus"></i>
                            </div>
                            <div class="history-info">
                                <span class="history-name">Friend Joined</span>
                                <span class="history-date">${formattedDate}</span>
                            </div>
                            <span class="history-status ${ref.status === 'completed' ? 'completed' : 'pending'}">
                                ${ref.status === 'completed' ? 'Completed' : 'Pending'}
                            </span>
                        </div>
                    `;
                }).join('');
            }
        }
        
        // Generate share link
        const shareLink = `${window.location.origin}/index.html?ref=${referralCode}`;
        const shareLinkInput = document.getElementById('share-link-input');
        if (shareLinkInput) shareLinkInput.value = shareLink;
        
        // Generate QR Code
        generateReferralQRCode(shareLink);
        
        // Store referral code globally
        window.currentReferralCode = referralCode;
        
    } catch (error) {
        console.error('Error loading referral data:', error);
    }
}

// Generate QR Code for referral
async function generateReferralQRCode(link) {
    const qrContainer = document.getElementById('invite-qr-code');
    if (!qrContainer) return;
    
    try {
        // Clear container
        qrContainer.innerHTML = '';
        
        // Generate QR code
        const qrCode = new QRCode(qrContainer, {
            text: link,
            width: 180,
            height: 180,
            colorDark: "#2563eb",
            colorLight: "#ffffff",
            correctLevel: QRCode.CorrectLevel.H
        });
        
    } catch (error) {
        console.error('QR generation error:', error);
        qrContainer.innerHTML = `
            <div class="qr-error" style="text-align: center; color: var(--danger);">
                <i class="fas fa-exclamation-circle"></i>
                <p>Could not generate QR code</p>
            </div>
        `;
    }
}

