// ==================== CLOUDINARY UPLOAD FUNCTIONS ====================

// Global variable to store upload promise
let cloudinaryUploadPromise = null;

/**
 * Upload multiple images to Cloudinary
 * @param {FileList} files - List of image files
 * @returns {Promise<string[]>} - Array of image URLs
 */
async function uploadToCloudinary(files) {
    if (!files || files.length === 0) return [];
    
    const imageUrls = [];
    const cloudName = window.CLOUDINARY_CONFIG?.cloudName;
    const uploadPreset = window.CLOUDINARY_CONFIG?.uploadPreset;
    
    if (!cloudName || !uploadPreset) {
        console.error('Cloudinary not configured. Please set CLOUDINARY_CONFIG.');
        showToast('Image upload service not configured', 'error');
        return [];
    }
    
    for (let i = 0; i < files.length; i++) {
        const file = files[i];
        
        // Validate file size (max 5MB)
        if (file.size > 5 * 1024 * 1024) {
            showToast(`${file.name}: File size must be less than 5MB`, 'error');
            continue;
        }
        
        // Validate file type
        const allowedTypes = ['image/jpeg', 'image/png', 'image/jpg', 'image/webp'];
        if (!allowedTypes.includes(file.type)) {
            showToast(`${file.name}: Only JPEG, PNG, and WebP images are allowed`, 'error');
            continue;
        }
        
        // Update progress
        const uploadStatus = document.getElementById('upload-status');
        const progressFill = document.getElementById('upload-progress-fill');
        
        if (uploadStatus) {
            uploadStatus.textContent = `Uploading ${i + 1} of ${files.length}: ${file.name}`;
        }
        
        try {
            // Create form data for Cloudinary upload
            const formData = new FormData();
            formData.append('file', file);
            formData.append('upload_preset', uploadPreset);
            formData.append('folder', window.CLOUDINARY_CONFIG.folder || 'bookmygame/grounds');
            
            // Show progress
            const xhr = new XMLHttpRequest();
            
            // Create promise for upload
            const uploadPromise = new Promise((resolve, reject) => {
                xhr.upload.addEventListener('progress', (e) => {
                    if (e.lengthComputable && progressFill) {
                        const percentComplete = ((i + (e.loaded / e.total)) / files.length) * 100;
                        progressFill.style.width = `${percentComplete}%`;
                    }
                });
                
                xhr.onload = () => {
                    if (xhr.status === 200) {
                        try {
                            const response = JSON.parse(xhr.responseText);
                            if (response.secure_url) {
                                resolve(response.secure_url);
                            } else if (response.url) {
                                resolve(response.url);
                            } else {
                                reject(new Error('Upload failed: No URL returned'));
                            }
                        } catch (e) {
                            reject(new Error('Invalid response from server'));
                        }
                    } else {
                        let errorMsg = 'Upload failed';
                        try {
                            const errorResponse = JSON.parse(xhr.responseText);
                            errorMsg = errorResponse.error?.message || 'Upload failed';
                        } catch (e) {}
                        reject(new Error(errorMsg));
                    }
                };
                
                xhr.onerror = () => {
                    reject(new Error('Network error during upload'));
                };
            });
            
            // Send the request
            xhr.open('POST', `https://api.cloudinary.com/v1_1/${cloudName}/image/upload`);
            xhr.send(formData);
            
            const url = await uploadPromise;
            imageUrls.push(url);
            
            if (uploadStatus) {
                uploadStatus.textContent = `Uploaded ${i + 1} of ${files.length}`;
            }
            
        } catch (error) {
            console.error('Cloudinary upload error:', error);
            showToast(`Failed to upload ${file.name}: ${error.message}`, 'error');
        }
    }
    
    return imageUrls;
}

/**
 * Upload a single file to Cloudinary
 * @param {File} file - Image file
 * @param {string} path - Optional path/folder (not used with Cloudinary preset)
 * @returns {Promise<string>} - Image URL
 */
async function uploadFile(file, path = '') {
    if (!file) {
        throw new Error('No file provided');
    }
    
    // Check file size (max 5MB)
    if (file.size > 5 * 1024 * 1024) {
        throw new Error('File size must be less than 5MB');
    }
    
    // Check file type
    const allowedTypes = ['image/jpeg', 'image/png', 'image/jpg', 'image/webp'];
    if (!allowedTypes.includes(file.type)) {
        throw new Error('Only JPEG, PNG, and WebP images are allowed');
    }
    
    const cloudName = window.CLOUDINARY_CONFIG?.cloudName;
    const uploadPreset = window.CLOUDINARY_CONFIG?.uploadPreset;
    
    if (!cloudName || !uploadPreset) {
        throw new Error('Cloudinary not configured');
    }
    
    const formData = new FormData();
    formData.append('file', file);
    formData.append('upload_preset', uploadPreset);
    formData.append('folder', path || window.CLOUDINARY_CONFIG.folder || 'bookmygame');
    
    const response = await fetch(`https://api.cloudinary.com/v1_1/${cloudName}/image/upload`, {
        method: 'POST',
        body: formData
    });
    
    if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error?.message || 'Upload failed');
    }
    
    const data = await response.json();
    return data.secure_url || data.url;
}

/**
 * Use Cloudinary Upload Widget for better UX
 * @returns {Promise<string[]>} - Array of image URLs
 */
function openCloudinaryUploadWidget() {
    return new Promise((resolve, reject) => {
        const cloudName = window.CLOUDINARY_CONFIG?.cloudName;
        const uploadPreset = window.CLOUDINARY_CONFIG?.uploadPreset;
        
        if (!cloudName || !uploadPreset) {
            reject(new Error('Cloudinary not configured'));
            return;
        }
        
        // Initialize Cloudinary upload widget
        const widget = cloudinary.createUploadWidget(
            {
                cloudName: cloudName,
                uploadPreset: uploadPreset,
                folder: window.CLOUDINARY_CONFIG.folder || 'bookmygame/grounds',
                multiple: true,
                maxFiles: 10,
                maxFileSize: 5000000, // 5MB
                allowedFormats: window.CLOUDINARY_CONFIG.allowedFormats || ['jpg', 'png', 'jpeg', 'webp'],
                cropping: true,
                croppingAspectRatio: 1,
                croppingDefaultSelectionRatio: 0.8,
                showAdvancedOptions: false,
                multiple: true,
                clientAllowedFormats: ['jpg', 'png', 'jpeg', 'webp'],
                styles: {
                    palette: {
                        window: '#FFFFFF',
                        windowBorder: '#90A0B3',
                        tabIcon: '#0078FF',
                        menuIcons: '#5A616A',
                        textDark: '#000000',
                        textLight: '#FFFFFF',
                        link: '#0078FF',
                        action: '#FF620C',
                        inactiveTabIcon: '#0E2F5A',
                        error: '#F44235',
                        inProgress: '#0078FF',
                        complete: '#20B832',
                        sourceBg: '#E4EBF1'
                    },
                    fonts: {
                        default: null,
                        "'Poppins', system-ui, sans-serif": {
                            url: 'https://fonts.googleapis.com/css?family=Poppins',
                            active: true
                        }
                    }
                }
            },
            (error, result) => {
                if (error) {
                    console.error('Upload widget error:', error);
                    reject(error);
                    return;
                }
                
                if (result.event === 'success') {
                    const urls = result.info.secure_url || result.info.url;
                    resolve([urls]);
                } else if (result.event === 'batch-complete') {
                    const urls = result.info.map(file => file.secure_url || file.url);
                    resolve(urls);
                }
            }
        );
        
        widget.open();
    });
}


async function handleEditGround(e) {
    e.preventDefault();
    
    const groundId = document.getElementById('edit-ground-id').value;
    const pricePerHour = parseFloat(document.getElementById('edit-ground-price')?.value);
    
    const ALLOWED_PRICES = [99, 199, 299, 499, 799, 999, 1299, 1999, 2499];
    if (!pricePerHour || !ALLOWED_PRICES.includes(pricePerHour)) {
        showToast('Please select a valid price from the allowed options', 'error');
        return;
    }
    
    showLoading('Updating ground...');
    
    try {
        await db.collection(COLLECTIONS.GROUNDS).doc(groundId).update({
            pricePerHour: pricePerHour,
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });
        
        hideLoading();
        showToast('Ground price updated successfully!', 'success');
        closeModal('edit-ground-modal');
        
        // Refresh the view
        if (currentGround && currentGround.id === groundId) {
            currentGround.pricePerHour = pricePerHour;
            if (document.getElementById('ground-page').classList.contains('active')) {
                viewGround(groundId);
            }
        }
        
        if (document.getElementById('owner-dashboard-page').classList.contains('active')) {
            loadOwnerDashboard('grounds');
        }
        
    } catch (error) {
        hideLoading();
        console.error('Error updating ground:', error);
        showToast('Error updating ground: ' + error.message, 'error');
    }
}

