async function debugDeletePermissions(groundId) {
    if (!currentUser) {
        console.log('❌ No user logged in');
        return;
    }
    
    console.log('=== DELETE PERMISSION DEBUG ===');
    console.log('Current User UID:', currentUser.uid);
    console.log('Current User Role:', currentUser.role);
    console.log('Current User Email:', currentUser.email);
    
    try {
        // Get the ground document
        const groundRef = db.collection(COLLECTIONS.GROUNDS).doc(groundId);
        const groundDoc = await groundRef.get();
        
        if (!groundDoc.exists) {
            console.log('❌ Ground not found');
            return;
        }
        
        const ground = groundDoc.data();
        console.log('Ground Owner ID:', ground.ownerId);
        console.log('Ground Name:', ground.groundName);
        console.log('Does owner match?', ground.ownerId === currentUser.uid);
        
        // Try to update instead of delete to see if write permissions work
        try {
            await groundRef.update({
                testField: firebase.firestore.FieldValue.delete()
            });
            console.log('✅ Update permission works');
        } catch (updateError) {
            console.log('❌ Update permission failed:', updateError.message);
        }
        
        // Try delete operation
        try {
            await groundRef.delete();
            console.log('✅ Delete permission works!');
            // Restore the ground
            await groundRef.set(ground);
        } catch (deleteError) {
            console.log('❌ Delete permission failed:', deleteError.message);
            console.log('Error code:', deleteError.code);
        }
        
    } catch (error) {
        console.error('Debug error:', error);
    }
}



function initPremiumAuth() {
    console.log('Initializing premium auth...'); // Debug log
    
    const loginTab = document.querySelector('.auth-tab[data-tab="login"]');
    const registerTab = document.querySelector('.auth-tab[data-tab="register"]');
    const loginPanel = document.getElementById('login-panel');
    const registerPanel = document.getElementById('register-panel');
    
    // Tab switching
    if (loginTab && registerTab && loginPanel && registerPanel) {
        // Remove existing listeners
        const newLoginTab = loginTab.cloneNode(true);
        const newRegisterTab = registerTab.cloneNode(true);
        loginTab.parentNode.replaceChild(newLoginTab, loginTab);
        registerTab.parentNode.replaceChild(newRegisterTab, registerTab);
        
        newLoginTab.addEventListener('click', () => {
            newLoginTab.classList.add('active');
            newRegisterTab.classList.remove('active');
            loginPanel.classList.add('active');
            registerPanel.classList.remove('active');
        });
        
        newRegisterTab.addEventListener('click', () => {
            newRegisterTab.classList.add('active');
            newLoginTab.classList.remove('active');
            registerPanel.classList.add('active');
            loginPanel.classList.remove('active');
        });
    }
    
    // Toggle password visibility
    document.querySelectorAll('.toggle-password-modern').forEach(btn => {
        const newBtn = btn.cloneNode(true);
        btn.parentNode.replaceChild(newBtn, btn);
        
        newBtn.addEventListener('click', function() {
            const input = this.closest('.input-group-modern').querySelector('input');
            const icon = this.querySelector('i');
            
            if (input && input.type === 'password') {
                input.type = 'text';
                icon.classList.remove('fa-eye');
                icon.classList.add('fa-eye-slash');
            } else if (input) {
                input.type = 'password';
                icon.classList.remove('fa-eye-slash');
                icon.classList.add('fa-eye');
            }
        });
    });
    
    // FIX: Re-attach form submit handlers
    const loginForm = document.getElementById('login-form');
    const registerForm = document.getElementById('register-form');
    
    if (loginForm) {
        const newLoginForm = loginForm.cloneNode(true);
        loginForm.parentNode.replaceChild(newLoginForm, loginForm);
        newLoginForm.addEventListener('submit', handleLogin);
        console.log('Login form handler attached');
    }
    
    if (registerForm) {
        const newRegisterForm = registerForm.cloneNode(true);
        registerForm.parentNode.replaceChild(newRegisterForm, registerForm);
        newRegisterForm.addEventListener('submit', handleRegister);
        console.log('Register form handler attached');
    }
    
    // FIX: Also attach click handlers to buttons directly (fallback)
    const registerBtn = document.querySelector('#register-panel .auth-btn-premium');
    if (registerBtn && registerForm) {
        const newRegisterBtn = registerBtn.cloneNode(true);
        registerBtn.parentNode.replaceChild(newRegisterBtn, registerBtn);
        
        newRegisterBtn.addEventListener('click', function(e) {
            e.preventDefault();
            console.log('Register button clicked directly');
            // Manually trigger form submit
            const submitEvent = new Event('submit', { bubbles: true, cancelable: true });
            registerForm.dispatchEvent(submitEvent);
        });
    }
    
    const loginBtn = document.querySelector('#login-panel .auth-btn-premium');
    if (loginBtn && loginForm) {
        const newLoginBtn = loginBtn.cloneNode(true);
        loginBtn.parentNode.replaceChild(newLoginBtn, loginBtn);
        
        newLoginBtn.addEventListener('click', function(e) {
            e.preventDefault();
            const submitEvent = new Event('submit', { bubbles: true, cancelable: true });
            loginForm.dispatchEvent(submitEvent);
        });
    }
    
    // Fix Google Sign In buttons
    const googleBtns = document.querySelectorAll('#google-signin-btn, #google-signin-btn-register');
    googleBtns.forEach(btn => {
        const newBtn = btn.cloneNode(true);
        btn.parentNode.replaceChild(newBtn, btn);
        newBtn.addEventListener('click', handleGoogleSignIn);
    });
    
    // Fix Forgot Password link
    const forgotLink = document.getElementById('forgot-password-link');
    if (forgotLink) {
        const newForgotLink = forgotLink.cloneNode(true);
        forgotLink.parentNode.replaceChild(newForgotLink, forgotLink);
        newForgotLink.addEventListener('click', handleForgotPassword);
    }
    
    // Fix Terms link in register form
    const termsLink = document.querySelector('#register-panel #terms-link');
    if (termsLink) {
        const newTermsLink = termsLink.cloneNode(true);
        termsLink.parentNode.replaceChild(newTermsLink, termsLink);
        newTermsLink.addEventListener('click', (e) => {
            e.preventDefault();
            showTerms();
        });
    }
    
    // Fix Owner registration link
    const ownerLink = document.getElementById('show-owner-register-link');
    if (ownerLink) {
        const newOwnerLink = ownerLink.cloneNode(true);
        ownerLink.parentNode.replaceChild(newOwnerLink, ownerLink);
        newOwnerLink.addEventListener('click', (e) => {
            e.preventDefault();
            showOwnerTypeSelection();
        });
    }
}

