async function joinMatch(matchId) {
    // Check if user is logged in
    if (!currentUser) {
        showToast('Please login to join a match', 'warning');
        return;
    }
    
    showLoading('Joining match...');
    
    try {
        // Get match data
        const matchRef = db.collection(COLLECTIONS.PLAYER_MATCHES).doc(matchId);
        const matchDoc = await matchRef.get();
        
        if (!matchDoc.exists) {
            showToast('Match not found', 'error');
            hideLoading();
            return;
        }
        
        const match = matchDoc.data();
        const now = new Date();
        const matchDateTime = new Date(`${match.date}T${match.time || '00:00'}`);
        
        // Validate match can be joined
        if (matchDateTime <= now) {
            showToast('This match has already started', 'error');
            hideLoading();
            return;
        }
        
        if (match.status !== MATCH_STATUS.OPEN) {
            showToast('This match is no longer available', 'error');
            hideLoading();
            return;
        }
        
        if (match.currentPlayers >= match.totalPlayers) {
            showToast('This match is full', 'error');
            hideLoading();
            return;
        }
        
        if ((match.participants || []).includes(currentUser.uid)) {
            showToast('You have already joined this match', 'warning');
            hideLoading();
            return;
        }
        
        // Get user name
        let userName = currentUser.name || currentUser.ownerName || currentUser.displayName;
        if (!userName && currentUser.email) {
            userName = currentUser.email.split('@')[0];
        }
        if (!userName) userName = 'Player';
        
        // Create participant record (FREE - no payment)
        const participantRecord = {
            userId: currentUser.uid,
            userName: userName,
            userProfileImage: currentUser.profileImage || null,
            userEmail: currentUser.email || '',
            userPhone: currentUser.phone || '',
            joinSource: window.isNativeApp ? 'mobile_app' : 'web_app',
            joinedAt: new Date().toISOString(),
            amountPaid: 0
        };
        
        // Calculate new player count
        const newCurrentPlayers = match.currentPlayers + 1;
        const newStatus = newCurrentPlayers >= match.totalPlayers ? MATCH_STATUS.FULL : MATCH_STATUS.OPEN;
        
        // DIRECT FIRESTORE UPDATE - NO PAYMENT GATEWAY CALLS
        await matchRef.update({
            currentPlayers: newCurrentPlayers,
            participants: firebase.firestore.FieldValue.arrayUnion(currentUser.uid),
            participantDetails: firebase.firestore.FieldValue.arrayUnion(participantRecord),
            status: newStatus,
            updatedAt: firebase.firestore.FieldValue.serverTimestamp()
        });
        
        hideLoading();
        showToast(`You joined ${match.title || 'the match'}!`, 'success');
        
        // Show success modal
        showMatchJoinSuccessModal(match);
        
        // Refresh match lists
        if (document.getElementById('main-page')?.classList.contains('active')) {
            
        }
        if (document.getElementById('all-matches-page')?.classList.contains('active')) {
            displayAllMatches();
        }
        
    } catch (error) {
        hideLoading();
        console.error('Join match error:', error);
        showToast('Error joining match: ' + error.message, 'error');
    }
}

