// ==================== MODAL SCROLL MANAGEMENT ====================

/**
 * Prevent body scroll when modal opens
 */
function preventBodyScroll() {
    const scrollY = window.scrollY;
    document.body.style.position = 'fixed';
    document.body.style.top = `-${scrollY}px`;
    document.body.style.width = '100%';
    document.body.style.overflow = 'hidden';
    document.body.classList.add('modal-open');
    
    // Store scroll position for restoration
    document.body.dataset.scrollY = scrollY;
}

/**
 * Restore body scroll when modal closes
 */
function restoreBodyScroll() {
    const scrollY = document.body.dataset.scrollY;
    document.body.style.position = '';
    document.body.style.top = '';
    document.body.style.width = '';
    document.body.style.overflow = '';
    document.body.classList.remove('modal-open');
    
    if (scrollY) {
        window.scrollTo(0, parseInt(scrollY));
        delete document.body.dataset.scrollY;
    }
}

/**
 * Enhanced modal open function
 */
function openModal(modalId) {
    const modal = document.getElementById(modalId);
    if (!modal) return;
    
    modal.classList.add('active');
    preventBodyScroll();
    
    // Add escape key listener
    document.addEventListener('keydown', function escapeHandler(e) {
        if (e.key === 'Escape') {
            closeModal(modalId);
            document.removeEventListener('keydown', escapeHandler);
        }
    });
}

/**
 * Enhanced modal close function
 */
function closeModal(modalId) {
    const modal = document.getElementById(modalId);
    if (!modal) return;
    
    modal.classList.remove('active');
    
    // Check if any other modals are open
    const anyOpenModal = document.querySelector('.modal.active');
    if (!anyOpenModal) {
        restoreBodyScroll();
    }
}

/**
 * Handle Razorpay modal events
 */
function setupRazorpayScrollHandling() {
    // Listen for Razorpay modal open
    const observer = new MutationObserver(function(mutations) {
        mutations.forEach(function(mutation) {
            if (mutation.type === 'attributes' && mutation.attributeName === 'style') {
                const razorpayContainer = document.querySelector('.razorpay-container');
                if (razorpayContainer && razorpayContainer.style.display !== 'none') {
                    // Razorpay modal is open
                    preventBodyScroll();
                } else if (razorpayContainer && razorpayContainer.style.display === 'none') {
                    // Razorpay modal closed
                    restoreBodyScroll();
                }
            }
        });
    });
    
    observer.observe(document.body, { attributes: true, subtree: true, attributeFilter: ['style'] });
}

// Call this on page load
document.addEventListener('DOMContentLoaded', function() {
    setupRazorpayScrollHandling();
    
    // Also handle all modal open/close events
    const modalTriggers = document.querySelectorAll('[data-modal-open]');
    modalTriggers.forEach(trigger => {
        trigger.addEventListener('click', function() {
            const modalId = this.dataset.modalOpen;
            openModal(modalId);
        });
    });
    
    const modalClosers = document.querySelectorAll('.close-btn, [data-modal-close]');
    modalClosers.forEach(closer => {
        closer.addEventListener('click', function() {
            const modal = this.closest('.modal');
            if (modal) {
                closeModal(modal.id);
            }
        });
    });
});

