// Add event listeners for verification modal
function initVerificationModal() {
    const modal = document.getElementById('verification-result-modal');
    const closeBtn = document.getElementById('close-verification-modal');
    const closeResultBtn = document.getElementById('close-result-btn');
    const verifyAnotherBtn = document.getElementById('verify-another-btn');
    
    if (closeBtn) {
        closeBtn.addEventListener('click', () => {
            modal.classList.remove('active');
        });
    }
    
    if (closeResultBtn) {
        closeResultBtn.addEventListener('click', () => {
            modal.classList.remove('active');
        });
    }
    
    if (verifyAnotherBtn) {
        verifyAnotherBtn.addEventListener('click', () => {
            modal.classList.remove('active');
            showProfessionalQRScanner();
        });
    }
    
    // Gallery button
    const galleryBtn = document.getElementById('select-from-gallery');
    if (galleryBtn) {
        galleryBtn.addEventListener('click', selectFromGallery);
    }
    
    // Close professional scanner
    const closeScannerBtn = document.getElementById('close-professional-qr');
    if (closeScannerBtn) {
        closeScannerBtn.addEventListener('click', closeProfessionalQRScanner);
    }
    
    // Close on backdrop click
    if (modal) {
        modal.addEventListener('click', (e) => {
            if (e.target === modal) {
                modal.classList.remove('active');
            }
        });
    }
}

