/**
 * Update owner's earnings
 */
async function updateOwnerEarnings(ownerId, amount) {
    if (!ownerId || !amount) return;
    
    try {
        const ownerRef = db.collection(COLLECTIONS.OWNERS).doc(ownerId);
        const ownerDoc = await ownerRef.get();
        
        if (ownerDoc.exists) {
            await ownerRef.update({
                totalEarnings: firebase.firestore.FieldValue.increment(amount),
                totalBookings: firebase.firestore.FieldValue.increment(1),
                updatedAt: firebase.firestore.FieldValue.serverTimestamp()
            });
            console.log(`✅ Updated owner ${ownerId} earnings by ${amount}`);
        }
    } catch (error) {
        console.error('Error updating owner earnings:', error);
    }
}

/**
 * Generate unique ID
 */
function generateId(prefix) {
    const timestamp = Date.now();
    const random = Math.floor(Math.random() * 1000000);
    const randomStr = random.toString().padStart(6, '0');
    return `${prefix}_${timestamp}_${randomStr}`;
}

/**
 * Format currency
 */
function formatCurrency(amount) {
    if (isNaN(amount)) return '₹0';
    return '₹' + Math.round(amount).toLocaleString('en-IN');
}
/**
 * Get owner's bookings (for owners to see who booked their grounds)
 */
async function loadOwnerBookingsWithPaymentDetails(container) {
    if (!currentUser || currentUser.role !== 'owner') return;
    
    showLoading('Loading bookings...');
    
    try {
        const snapshot = await db.collection(COLLECTIONS.BOOKINGS)
            .where('ownerId', '==', currentUser.uid)
            .orderBy('createdAt', 'desc')
            .get();
        
        if (snapshot.empty) {
            container.innerHTML = '<p class="text-center">No bookings yet</p>';
            hideLoading();
            return;
        }
        
        let html = '<div class="bookings-list">';
        
        for (const doc of snapshot.docs) {
            const booking = doc.data();
            
            html += `
                <div class="booking-card status-confirmed">
                    <div class="booking-status status-confirmed">CONFIRMED</div>
                    <h4>${booking.groundName || 'Ground'}</h4>
                    <p><i class="fas fa-user"></i> Customer: ${booking.userName || 'N/A'}</p>
                    <p><i class="fas fa-envelope"></i> Email: ${booking.userEmail || 'N/A'}</p>
                    <p><i class="fas fa-phone"></i> Phone: ${booking.userPhone || 'N/A'}</p>
                    <p><i class="fas fa-calendar"></i> Date: ${booking.date}</p>
                    <p><i class="fas fa-clock"></i> Time: ${booking.slotTime}</p>
                    <p><i class="fas fa-rupee-sign"></i> Amount: ${formatCurrency(booking.amount)}</p>
                    <p><i class="fas fa-credit-card"></i> Order ID: ${booking.cashfreeOrderId || 'N/A'}</p>
                    <p><i class="fas fa-exchange-alt"></i> Transaction ID: ${booking.cashfreeTransactionId || 'N/A'}</p>
                    <p><small>Booking ID: ${booking.bookingId}</small></p>
                    <button class="view-details-btn" onclick="viewBookingDetails('${booking.bookingId}')">View Details</button>
                </div>
            `;
        }
        
        html += '</div>';
        container.innerHTML = html;
        hideLoading();
        
    } catch (error) {
        hideLoading();
        console.error('Error loading owner bookings:', error);
        container.innerHTML = '<p class="text-center">Failed to load bookings</p>';
    }
}

