// ==================== UPDATE PAST BOOKINGS STATUS ====================

async function updatePastBookingsStatus() {
    console.log('Checking for past bookings to update...');
    
    if (!currentUser) return;
    
    try {
        const today = new Date().toISOString().split('T')[0];
        const now = new Date();
        
        // Get all confirmed bookings for the current user
        const snapshot = await db.collection(COLLECTIONS.BOOKINGS)
            .where('userId', '==', currentUser.uid)
            .where('bookingStatus', '==', 'confirmed')
            .get();
        
        console.log(`Found ${snapshot.size} confirmed bookings to check`);
        
        const batch = db.batch();
        let updatesCount = 0;
        
        for (const doc of snapshot.docs) {
            const booking = doc.data();
            const bookingDate = booking.date;
            
            // Check if booking date is in the past
            if (bookingDate < today) {
                console.log(`Booking ${booking.bookingId} on ${bookingDate} is past. Marking as COMPLETED.`);
                
                // Update to completed status
                batch.update(doc.ref, {
                    bookingStatus: 'completed',
                    completedAt: firebase.firestore.FieldValue.serverTimestamp(),
                    updatedAt: firebase.firestore.FieldValue.serverTimestamp()
                });
                updatesCount++;
            }
        }
        
        if (updatesCount > 0) {
            await batch.commit();
            console.log(`Updated ${updatesCount} past bookings to COMPLETED status`);
            
            // Refresh the bookings display if we're on bookings page
            if (document.getElementById('bookings-page') && 
                document.getElementById('bookings-page').classList.contains('active')) {
                const activeTab = document.querySelector('.bookings-tabs .tab-btn.active');
                const currentStatus = activeTab ? 
                    (activeTab.id === 'bookings-upcoming' ? 'upcoming' : 
                     activeTab.id === 'bookings-past' ? 'past' : 'upcoming') : 'upcoming';
                loadUserBookings(currentStatus);
            }
        }
        
    } catch (error) {
        console.error('Error updating past bookings:', error);
    }
}

