/**
 * handleTournamentPayment — called from tournament registration UI
 * @param {object} tournament — Firestore tournament doc data (must include .id, .entryFee)
 * @param {string} teamName   — optional
 */
async function handleTournamentPayment(tournament, teamName = '') {
    if (!currentUser) {
        showToast('Please log in to register', 'warning');
        showPage('login-page');
        return;
    }
    if (!tournament?.entryFee || tournament.entryFee <= 0) {
        showToast('Invalid entry fee for this tournament.', 'error');
        return;
    }

    // Prevent duplicate registrations
    const existing = await db.collection('tournament_entries')
        .where('tournamentId', '==', tournament.id)
        .where('userId',       '==', currentUser.uid)
        .limit(1).get();

    if (!existing.empty) {
        showToast('You are already registered for this tournament.', 'warning');
        return;
    }

    // FIX: `tournament` may be a raw Firestore doc payload containing Timestamp
    // fields (e.g. startDate stored as Timestamp, createdAt, etc.).
    // JSON round-trip converts all Timestamps to serialisable values (or drops
    // non-serialisable ones), giving us a plain-JS object safe for startPayment().
    const safeTournament = JSON.parse(JSON.stringify(tournament));

    // Build the explicit plain-JS payload — every field is a primitive.
    // Never spread safeTournament directly; only whitelist what startPayment needs.
    const paymentData = {
        tournamentId  : String(safeTournament.id            || ''),
        tournamentName: String(safeTournament.tournamentName || safeTournament.name || ''),
        amount        : Number(safeTournament.entryFee),
        userId        : String(currentUser.uid),
        userName      : String(currentUser.name   || ''),
        userEmail     : String(currentUser.email  || ''),
        userPhone     : String(currentUser.phone  || ''),
        teamName      : String(teamName || ''),
        sport         : String(safeTournament.sportType || safeTournament.sport || ''),
        date          : String(safeTournament.startDate  || ''),
        venue         : String(safeTournament.venue      || ''),
    };

    console.log('FINAL PAYMENT DATA:', paymentData); // debug log

    await startPayment(paymentData, 'tournament');
}



