// BUTTON CLICK FAILSAFE — belt-and-suspenders delegation
// All nav/back buttons are re-wired here so they work even if the
// DOMContentLoaded block above failed to bind them (e.g. element
// wasn't in DOM yet, or a JS error aborted the binding loop).
// ══════════════════════════════════════════════════════════════════
(function installButtonFailsafes() {
    function wire() {
        // ── Bottom nav ────────────────────────────────────────────
        const navMap = {
            'nav-home'        : () => showHome(),
            'nav-bookings'    : () => showBookings(),
            'nav-tournaments' : () => showTournaments(),
            'nav-profile'     : () => showProfile(),
        };
        Object.entries(navMap).forEach(([id, fn]) => {
            const el = document.getElementById(id);
            if (!el) return;
            // Only add if not already wired (avoid duplicates)
            if (el.dataset.bmgWired) return;
            el.dataset.bmgWired = '1';
            el.addEventListener('click', (e) => { e.preventDefault(); fn(); });
        });

        // ── Header profile / QR buttons ───────────────────────────
        const btnMap = {
            'profile-btn'          : () => showProfile(),
            'header-qr-scanner'    : () => typeof toggleProfessionalQRScanner === 'function' && toggleProfessionalQRScanner(),
            'payment-verify-icon'  : () => { const el = document.getElementById('payment-verify-icon'); if (el && !el.dataset.bmgWired) { el.dataset.bmgWired = '1'; el.addEventListener('click', () => typeof showPaymentVerification === 'function' && showPaymentVerification()); } },
            'refresh-location'     : () => typeof getUserLocation === 'function' && getUserLocation(),
            'view-all-venues'      : () => typeof loadAllVenuesPage === 'function' && loadAllVenuesPage(),
            'view-all-tournaments' : () => showTournaments(),
        };
        Object.entries(btnMap).forEach(([id, fn]) => {
            const el = document.getElementById(id);
            if (!el || el.dataset.bmgWired) return;
            el.dataset.bmgWired = '1';
            el.addEventListener('click', (e) => { e.preventDefault(); fn(); });
        });

        // ── Back buttons ──────────────────────────────────────────
        [
            'venue-back-btn', 'ground-back-btn', 'booking-back-btn',
            'confirmation-home-btn', 'entry-pass-back-btn',
            'tournaments-back-btn', 'tournament-details-back-btn',
            'tournament-reg-back-btn', 'bookings-back-btn',
            'profile-back-btn', 'owner-dashboard-back-btn',
            'admin-dashboard-back-btn', 'ceo-dashboard-back-btn',
            'venue-owner-register-back-btn', 'plot-owner-register-back-btn',
            'owner-type-back-btn', 'all-venues-back-btn',
        ].forEach(id => {
            const el = document.getElementById(id);
            if (!el || el.dataset.bmgWired) return;
            el.dataset.bmgWired = '1';
            el.addEventListener('click', (e) => { e.preventDefault(); goBack(); });
        });

        // ── Specific action buttons ───────────────────────────────
        const actMap = {
            'back-to-home-btn'       : () => goHome(),
            'write-review-btn'       : () => typeof showWriteReview === 'function' && showWriteReview(),
            'share-venue-btn'        : () => typeof shareVenue === 'function' && shareVenue(),
            'view-entry-pass-btn'    : () => typeof showEntryPassFromConfirmation === 'function' && showEntryPassFromConfirmation(),
            'logout-btn'             : () => logout(),
            'edit-profile-btn'       : () => typeof editProfile === 'function' && editProfile(),
            'profile-bookings-link'  : () => showBookings(),
            'owner-dashboard-link'   : () => typeof showOwnerDashboard === 'function' && showOwnerDashboard(),
            'admin-dashboard-link'   : () => typeof showAdminDashboard === 'function' && showAdminDashboard(),
            'ceo-dashboard-link'     : () => typeof showCEODashboard === 'function' && showCEODashboard(),
        };
        Object.entries(actMap).forEach(([id, fn]) => {
            const el = document.getElementById(id);
            if (!el || el.dataset.bmgWired) return;
            el.dataset.bmgWired = '1';
            el.addEventListener('click', (e) => { e.preventDefault(); fn(); });
        });

        // ── Modal close buttons ───────────────────────────────────
        [
            ['close-add-ground-modal',         'add-ground-modal'],
            ['close-create-tournament-modal',   'create-tournament-modal'],
            ['close-slot-management-modal',     'slot-management-modal'],
            ['close-create-admin-modal',        'create-admin-modal'],
            ['close-edit-profile-modal',        'edit-profile-modal'],
            ['close-write-review-modal',        'write-review-modal'],
            ['close-tournament-reg-modal',      'tournament-registration-modal'],
            ['close-verification-modal',        'owner-verification-modal'],
            ['close-host-payment-verify-modal', 'host-payment-verify-modal'],
        ].forEach(([btnId, modalId]) => {
            const el = document.getElementById(btnId);
            if (!el || el.dataset.bmgWired) return;
            el.dataset.bmgWired = '1';
            el.addEventListener('click', () => closeModal(modalId));
        });

        // ── Owner type selection ──────────────────────────────────
        const plotCard = document.getElementById('select-plot-owner');
        if (plotCard && !plotCard.dataset.bmgWired) {
            plotCard.dataset.bmgWired = '1';
            plotCard.addEventListener('click', () => {
                if (typeof showPage === 'function') showPage('plot-owner-register-page');
            });
        }

        // ── Auth tabs ─────────────────────────────────────────────
        document.querySelectorAll('.auth-tab:not([data-bmg-wired])').forEach(tab => {
            tab.dataset.bmgWired = '1';
            tab.addEventListener('click', () => {
                const target = tab.dataset.tab;
                document.querySelectorAll('.auth-tab').forEach(t => t.classList.remove('active'));
                document.querySelectorAll('.auth-panel').forEach(p => p.classList.remove('active'));
                tab.classList.add('active');
                const panel = document.getElementById(target + '-panel');
                if (panel) panel.classList.add('active');
            });
        });

        // ── Password toggle (modern style) ────────────────────────
        document.querySelectorAll('.toggle-password-modern:not([data-bmg-wired])').forEach(btn => {
            btn.dataset.bmgWired = '1';
            btn.addEventListener('click', () => {
                const input = btn.closest('.input-group-modern')?.querySelector('input[type="password"], input[type="text"]');
                if (!input) return;
                const icon = btn.querySelector('i');
                if (input.type === 'password') {
                    input.type = 'text';
                    icon?.classList.replace('fa-eye', 'fa-eye-slash');
                } else {
                    input.type = 'password';
                    icon?.classList.replace('fa-eye-slash', 'fa-eye');
                }
            });
        });

        // ── Ensure loading overlay is never permanently stuck ─────
        // If the overlay is visible and no auth/loading operation set a
        // timeout (the failsafe in showLoading handles this), clear it now.
        const overlay = document.getElementById('loading-overlay');
        if (overlay && overlay.style.display !== 'none' && !_loadingTimeout) {
            // Overlay is showing but no timeout is running — it's stuck. Kill it.
            console.warn('[BMG] Stuck loading overlay detected on wire() — hiding.');
            hideLoading();
        }
    }

    // Run immediately if DOM is ready, else wait
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', wire);
    } else {
        wire();
    }

    // Also re-run after auth completes (pages rendered dynamically won't have wired buttons)
    window.addEventListener('bmg:pageShown', wire);
    // Re-run on every page navigation so dynamically injected buttons also get wired
    // Guard: only wrap showPage ONCE
    if (!window._bmgShowPageWrapped && typeof window.showPage === 'function') {
        window._bmgShowPageWrapped = true;
        const _origShowPage = window.showPage;
        window.showPage = function(pageId) {
            const result = _origShowPage.apply(this, arguments);
            setTimeout(wire, 0);
            return result;
        };
    }
})();

// ══════════════════════════════════════════════════════════════════
// WINDOW EXPORTS — expose all key functions globally so the master
// event delegator in index.html can call them by name.
// ══════════════════════════════════════════════════════════════════
(function exportToWindow() {
    const fns = [
        'showPage', 'goBack', 'goHome',
        'showHome', 'showBookings', 'showTournaments', 'showProfile',
        'showOwnerTypeSelection', 'showVenueOwnerRegister', 'showPlotOwnerRegister',
        'showTerms', 'showPrivacyPolicy', 'showCancellationPolicy',
        'showRefundPolicy', 'showOwnerAgreement',
        'showOwnerDashboard', 'showAdminDashboard', 'showCEODashboard',
        'loadOwnerDashboard', 'loadAdminDashboard', 'loadCEODashboard',
        'loadAllVenuesPage', 'loadUserBookings', 'loadAllTournaments',
        'loadAllMatchesPage', 'showMyMatches',
        'showTournamentRegistration', 'showTournamentRegistrations',
        'showEntryPassFromConfirmation', 'showEntryPass',
        'showWriteReview', 'shareVenue', 'editProfile', 'changeProfilePhoto',
        'logout', 'handleGoogleSignIn', 'handleForgotPassword',
        'toggleProfessionalQRScanner', 'closeProfessionalQRScanner',
        'toggleTorch', 'selectFromGallery',
        'getUserLocation', 'filterBySport', 'filterTournaments', 'filterAllVenues',
        'closeModal', 'closeImageViewer', 'openImageViewer',
        'zoomImageViewerIn', 'zoomImageViewerOut', 'resetImageViewerTransform',
        'prevImageViewerImage', 'nextImageViewerImage',
        'closeVerificationResultModal',
        'showRegistrationPaymentModal',
        'clearBookingSession',
        'prevStep', 'nextStep',
        'tournamentPrevStep', 'tournamentNextStep',
        'addMorePlayers',
        'showPaymentVerification', 'showPaymentVerificationModal',
        'addAdminTabEventListeners',
        'showBookingPage',
        'prevGallerySlide', 'nextGallerySlide',
    ];
    fns.forEach(name => {
        // Only export if function is defined locally and not yet on window
        if (typeof window[name] === 'undefined') {
            try {
                // eslint-disable-next-line no-eval
                const fn = eval(name);
                if (typeof fn === 'function') window[name] = fn;
            } catch(e) { /* not defined in this scope */ }
        }
    });
    console.log('[BMG] Window exports done');
})();
